INSERT INTO public.alembic_version VALUES ('eacb4e35ee2e');
INSERT INTO public.countries VALUES ('e9e5cf1f-f4fc-4563-8ebb-2110f14cf5b8', 'Япония', 'Страна восходящего солнца, где древние синтоистские храмы соседствуют с неоновыми небоскребами, а вековые традиции — с передовыми технологиями.', '2026-03-26 15:25:48.888548', '2026-03-26 15:25:48.888548', NULL);
INSERT INTO public.countries VALUES ('cceb7c00-55e5-42c3-9f8e-f3388e8e1127', 'Южная Корея', 'Динамичное государство, объединяющее богатое историческое наследие эпохи Чосон с современными трендами, K-pop культурой и потрясающей кухней.', '2026-03-26 15:26:06.628359', '2026-03-26 15:26:06.628359', NULL);
INSERT INTO public.countries VALUES ('9b9a78e3-e6bb-441f-bcf5-7fa1bd55f478', 'Россия', 'мумумик', '2026-05-10 09:07:44.332532', '2026-05-10 09:07:44.332532', NULL);
INSERT INTO public.countries VALUES ('80bb3c77-8f9e-47f4-a4fd-26eeaf403f7b', 'Турция', 'Турция — страна на стыке Европы и Азии с богатой историей и разнообразной природой. Официальный язык — турецкий. Валюта — турецкая лира (TRY). Для граждан многих стран СНГ виза не требуется на срок до 90 дней. Популярные курорты: Анталья, Бодрум, Мармарис. Стамбул — культурная столица с мечетями, дворцами и оживлёнными базарами.', '2026-05-18 06:39:00.77185', '2026-05-18 06:39:00.77185', 'Страна на стыке Европы и Азии. Пляжи, мечети, базары и турецкая кухня.');
INSERT INTO public.countries VALUES ('30891716-033e-41ad-9893-631af79ad11a', 'Китай', 'Китай — самая населённая страна мира с богатейшей историей более 5000 лет. Официальный язык — мандаринский китайский. Валюта — юань (CNY). Виза обязательна для большинства стран, оформляется заранее. Интернет ограничен — Google, Instagram, WhatsApp заблокированы. Рекомендуется установить VPN до въезда в страну. Основной способ оплаты — WeChat Pay и Alipay, наличные принимаются везде. Иностранные карты работают ограниченно — лучше иметь наличные юани.', '2026-03-20 22:40:19.952777', '2026-03-20 22:40:19.952777', 'Древняя цивилизация с мегаполисами, храмами и уличной едой.');
INSERT INTO public.countries VALUES ('b8d1a40b-13eb-46c7-82a3-d52fe0bac37d', 'ОАЭ', 'Объединённые Арабские Эмираты — федерация семи эмиратов на берегу Персидского залива. Официальный язык — арабский, широко используется английский. Валюта — дирхам (AED). Дубай — мировой центр шопинга, туризма и архитектурных рекордов. Абу-Даби — столица с богатой культурной жизнью и мечетью шейха Зайда. Алкоголь разрешён только в лицензированных заведениях.', '2026-05-18 06:39:00.77185', '2026-05-18 06:39:00.77185', 'Дубай и Абу-Даби — небоскрёбы, пустыня и роскошь.');
INSERT INTO public.countries VALUES ('18108516-7c0c-4618-a251-f612867662e5', 'Абхазия', 'Абхазия — частично признанное государство на восточном побережье Чёрного моря. Официальный язык — абхазский и русский. Валюта — российский рубль (RUB). Для граждан России въезд без визы по внутреннему паспорту. Известна мягким климатом, цитрусовыми садами и живописными горными реками. Туристическая инфраструктура развита умеренно.', '2026-05-18 06:39:00.77185', '2026-05-18 06:39:00.77185', 'Черноморское побережье, горы и мандариновые рощи.');
INSERT INTO public.countries VALUES ('0afc0ac8-f6dc-4ff6-a69b-c1c79923ca50', 'Таиланд', 'Тропический рай Юго-Восточной Азии, известный своими белоснежными пляжами, древними буддийскими святынями и неповторимым колоритом уличной жизни.', '2026-03-26 15:26:21.706554', '2026-03-26 15:26:21.706554', 'Тропики, буддийские храмы, стритфуд и острова.');
INSERT INTO public.countries VALUES ('7cf30f85-e9cb-45a0-832c-cf101be15de4', 'Египет', 'Египет — страна с древнейшей цивилизацией на берегах Нила и двух морей. Официальный язык — арабский. Валюта — египетский фунт (EGP). Туристическая виза оформляется по прилёту или онлайн. Шарм-эль-Шейх и Хургада — главные курорты на Красном море. Египет запрещает вывоз антиквариата и исторических артефактов.', '2026-05-18 06:39:00.77185', '2026-05-18 06:39:00.77185', 'Пирамиды, Красное море и тысячелетняя история.');
INSERT INTO public.countries VALUES ('ccd13ef1-3b3c-4117-8032-b46bdb65b41b', 'Беларусь', 'Беларусь — страна в центре Европы с нетронутой природой и советским архитектурным наследием. Официальные языки — белорусский и русский. Валюта — белорусский рубль (BYN). Для граждан России въезд свободный. Для других стран — условия могут отличаться. Страна известна замками, национальными парками и чистыми городами. Несьвижский и Мирский замки включены в список ЮНЕСКО.', '2026-05-18 06:39:00.77185', '2026-05-18 06:39:00.77185', 'Европейская природа, замки и спокойный ритм жизни.');
INSERT INTO public.countries VALUES ('45c55a27-8068-4769-ae7a-779af27c5bee', 'Казахстан', 'Казахстан — крупнейшая страна Центральной Азии с разнообразной природой и быстро развивающимися городами. Официальный язык — казахский, широко используется русский. Валюта — тенге (KZT). Для граждан России и СНГ въезд безвизовый. Алматы — деловая столица у подножия гор Тянь-Шань. Астана (Нур-Султан) — ультрасовременная столица с футуристической архитектурой.', '2026-05-18 06:39:00.77185', '2026-05-18 06:39:00.77185', 'Степи, горы Алматы и современная Астана.');
INSERT INTO public.countries VALUES ('7c83e930-e2e6-4a34-885e-73f64dc659f4', 'Армения', 'Армения — горная страна Кавказа с богатейшим христианским наследием и гостеприимными традициями. Официальный язык — армянский. Валюта — армянский драм (AMD). Для граждан России и большинства стран СНГ виза не нужна. Страна известна монастырями IV–X веков, озером Севан и коньяком «Арарат». Ереван — розовый город с Каскадом, рынком Вернисаж и уличными кафе.', '2026-05-18 06:39:00.77185', '2026-05-18 06:39:00.77185', 'Древние монастыри, горный воздух и армянское вино.');
INSERT INTO public.cities VALUES ('79318373-6e9a-4b91-8201-e2736508b269', '30891716-033e-41ad-9893-631af79ad11a', 'Чжанцзяцзе', 'Чжанцзяцзе — национальный парк с уникальными скалами-столбами, ставшими прообразом планеты Пандора в фильме Аватар. Рекомендуется выделить минимум 3–4 дня на посещение парка. Лучший сезон — весна (апрель–май) и осень (сентябрь–ноябрь). Зимой меньше туристов, красивый туман, но часть аттракционов закрыта.', '2026-03-20 22:40:20.013814', '2026-03-20 22:40:20.013814', NULL);
INSERT INTO public.cities VALUES ('29d7e71c-3f97-4ee0-a349-6d991c977e31', '30891716-033e-41ad-9893-631af79ad11a', 'Фэнхуан', 'Фэнхуан — древний город с хорошо сохранившейся архитектурой эпохи Мин и Цин. Расположен в ~40 минутах езды на поезде от Чжанцзяцзе — удобно совмещать. Деревянные дома на сваях над рекой Туцзян — главная визитная карточка города. Вход в старый город платный — около 148 юаней.', '2026-03-20 22:40:20.013814', '2026-03-20 22:40:20.013814', NULL);
INSERT INTO public.cities VALUES ('87d60596-c253-42b6-8983-2cfbf427996c', '30891716-033e-41ad-9893-631af79ad11a', 'Чунцин', 'Чунцин — мегаполис на слиянии рек Янцзы и Цзялин, известный острой кухней и сложным рельефом с эскалаторами прямо в жилых кварталах. Знаменит барбекю хого (горячий горшок) — местная гастрономическая традиция. Панорамные виды на ночной город — одни из лучших в Китае.', '2026-03-20 22:40:20.013814', '2026-03-20 22:40:20.013814', NULL);
INSERT INTO public.cities VALUES ('5a5725ee-c783-49ae-85aa-15e86e0e9f71', '30891716-033e-41ad-9893-631af79ad11a', 'Фошань', 'Фошань — промышленный город рядом с Гуанчжоу, известный производством мебели, керамики и текстиля. Район Наньхай известен аутлет-центрами с брендовыми товарами. До Гуанчжоу — 30 минут на метро или автобусе.', '2026-03-20 22:40:20.013814', '2026-03-20 22:40:20.013814', NULL);
INSERT INTO public.cities VALUES ('5b3d3373-40ad-49d9-b7b9-27c8214e5a7e', 'e9e5cf1f-f4fc-4563-8ebb-2110f14cf5b8', 'Киото', 'Культурное сердце Японии, знаменитое своими тысячами красных торий храма Фусими Инари, Золотым павильоном и умиротворяющими бамбуковыми рощами Арасияма[cite: 2].', '2026-03-26 15:32:15.93246', '2026-03-26 15:32:15.93246', NULL);
INSERT INTO public.cities VALUES ('f7ea1e32-ca79-41f2-9bcb-bb7dffebcbbf', 'e9e5cf1f-f4fc-4563-8ebb-2110f14cf5b8', 'Осака', 'Динамичный город, известный своим историческим замком XVI века, ярким гастрономическим районом Дотонбори и парком Universal Studios Japan[cite: 2].', '2026-03-26 15:32:46.916676', '2026-03-26 15:32:46.916676', NULL);
INSERT INTO public.cities VALUES ('82788d97-9e68-4975-9812-8d81bd71ce37', 'cceb7c00-55e5-42c3-9f8e-f3388e8e1127', 'Сеул', 'Энергичная столица, объединяющая величие дворца Кёнбоккун эпохи Чосон с современными торговыми улицами Мёндон и панорамными видами с башни N Seoul Tower[cite: 2].', '2026-03-26 15:33:40.785179', '2026-03-26 15:33:40.785179', NULL);
INSERT INTO public.cities VALUES ('0ba5ba3e-fbbe-4af8-9f28-6c2c8bccdc10', '9b9a78e3-e6bb-441f-bcf5-7fa1bd55f478', 'карелия', 'string', '2026-05-10 12:36:27.881051', '2026-05-10 15:11:51.196391', '2026-05-10 15:11:51.195423');
INSERT INTO public.cities VALUES ('812714b9-873b-41b9-b849-acb601551000', '30891716-033e-41ad-9893-631af79ad11a', 'Шэньчжэнь', 'Шэньчжэнь — современный технологический город рядом с Гонконгом. Граница с Гонконгом через переход Lok Ma Chau — один из самых загруженных в мире. Метро соединяет город с пограничными переходами. Валюта — юань, в приграничных районах принимают гонконгский доллар.', '2026-03-20 22:40:20.013814', '2026-05-11 12:11:11.401283', '2026-05-11 12:11:11.400927');
INSERT INTO public.cities VALUES ('7b2a2673-2a59-40aa-b097-c2b46a72c95f', 'e9e5cf1f-f4fc-4563-8ebb-2110f14cf5b8', 'Токио', 'Ультрасовременный мегаполис, где неоновые небоскребы Сибуя соседствуют с древним храмом Сэнсо-дзи[cite: 2]. Это город контрастов, предлагающий всё: от иммерсивного цифрового искусства в TeamLab до традиционных рыбных рынков[cite: 2].', '2026-03-26 15:51:49.583865', '2026-05-18 06:30:29.111307', '2026-05-18 06:30:29.110997');
INSERT INTO public.cities VALUES ('f3e4f111-f0ec-4f7c-a3a7-2eaeb68a674e', '0afc0ac8-f6dc-4ff6-a69b-c1c79923ca50', 'Пхукет', 'Главный островной курорт страны, предлагающий доступ к островам Пхи-Пхи, историческую застройку Старого города и величественную статую Большого Будды[cite: 2].', '2026-03-26 15:34:52.68538', '2026-05-17 11:49:48.218052', '2026-05-17 11:49:48.217585');
INSERT INTO public.cities VALUES ('6ea12fdc-c2a4-4ed4-ba46-edc049da7db4', '30891716-033e-41ad-9893-631af79ad11a', 'Сиань', 'Сиань — древняя столица Китая, начальная точка Великого шёлкового пути. Главная достопримечательность — Терракотовая армия, 30 км от центра. Мусульманский квартал — обязательное место для посещения с уличной едой. Городская стена полностью сохранилась, можно арендовать велосипед. Добраться до Терракотовой армии: автобус №5 или туристический автобус от ж/д вокзала.', '2026-03-20 22:40:20.013814', '2026-05-11 17:02:35.169938', '2026-05-11 17:02:35.16898');
INSERT INTO public.cities VALUES ('9a6c21db-8538-4721-bce9-96a06e37b368', 'cceb7c00-55e5-42c3-9f8e-f3388e8e1127', 'Пусан', 'Крупный портовый город с живописными пляжами Хэундэ, красочной культурной деревней Камчхон и крупнейшим в Корее рыбным рынком Чагальчхи[cite: 2].', '2026-03-26 15:52:28.759901', '2026-05-18 05:24:01.153617', '2026-05-18 05:24:01.153196');
INSERT INTO public.cities VALUES ('8717ad74-80b9-4ac4-9640-bc1308ad3081', '0afc0ac8-f6dc-4ff6-a69b-c1c79923ca50', 'Бангкок', 'Шумная столица на реке Чаупхрая, дом для священного Изумрудного Будды, величественного Храма Рассвета и гигантских рынков выходного дня[cite: 2].', '2026-03-26 15:34:35.219107', '2026-05-17 11:06:47.905409', '2026-05-17 11:06:47.905177');
INSERT INTO public.cities VALUES ('72df7555-6cda-41ca-8269-11b0d4885703', '30891716-033e-41ad-9893-631af79ad11a', 'Гуанчжоу', 'Гуанчжоу — один из крупнейших торговых городов Китая на юге страны. Известен оптовыми рынками одежды, электроники и товаров. Метро хорошо развито, билет стоит 2–12 юаней. Ночные рынки работают до 23:00–00:00. Лучшее время для посещения — октябрь–апрель, летом очень жарко и влажно.', '2026-03-20 22:40:20.013814', '2026-05-18 05:28:02.118664', '2026-05-18 05:28:02.118277');
INSERT INTO public.cities VALUES ('4c712a0c-cb9b-4ca3-8a66-dc4c97436f81', '7c83e930-e2e6-4a34-885e-73f64dc659f4', 'Ереван', 'Столица с розовым туфом, каскадной лестницей, Матенадараном и видом на Арарат.', '2026-05-18 06:39:00.77185', '2026-05-18 06:39:00.77185', NULL);
INSERT INTO public.cities VALUES ('8342bf4e-9993-4b94-a328-dc569bb6fc71', '7c83e930-e2e6-4a34-885e-73f64dc659f4', 'Гюмри', 'Второй город Армении с купеческими домами XIX века и особой культурной идентичностью.', '2026-05-18 06:39:00.77185', '2026-05-18 06:39:00.77185', NULL);
INSERT INTO public.cities VALUES ('1e51b627-eec4-4706-af9a-11dbabbe30f5', '7c83e930-e2e6-4a34-885e-73f64dc659f4', 'Дилижан', 'Армянская Швейцария — курортный городок в лесах с монастырями Агарцин и Гошаванк.', '2026-05-18 06:39:00.77185', '2026-05-18 06:39:00.77185', NULL);
INSERT INTO public.cities VALUES ('97a9a4ba-9773-49b9-a159-4184fba61299', '9b9a78e3-e6bb-441f-bcf5-7fa1bd55f478', 'Калининград', 'Калининград — самый западный город России, бывший Кёнигсберг (Восточная Пруссия). Единственный российский эксклав, окружённый Польшей, Литвой и Балтийским морем. Валюта — рубль (RUB). Въезд для граждан России свободный; для иностранцев — виза РФ. Часовой пояс: UTC+2 (как Вильнюс и Варшава, на 1 час западнее Москвы). Янтарный регион — здесь добывается около 90% мирового янтаря. Богатое немецко-прусское наследие: готические соборы, форты, Кёнигсбергский замок. Климат мягкий морской: лето тёплое (+18–22°C), зима мягкая (редко ниже −5°C). Удобный транспорт: трамваи, автобусы, такси; до Балтийского побережья — 30–50 мин.', '2026-05-17 11:57:56.808007', '2026-05-17 12:03:50.621717', '2026-05-17 12:03:50.621281');
INSERT INTO public.cities VALUES ('fdc7338c-412f-4b29-b192-c3fedf53f247', '80bb3c77-8f9e-47f4-a4fd-26eeaf403f7b', 'Анталья', 'Главный курортный город Турции на берегу Средиземного моря с развитой туристической инфраструктурой.', '2026-05-18 06:39:00.77185', '2026-05-18 06:39:00.77185', NULL);
INSERT INTO public.cities VALUES ('cc6a73b8-03c6-4142-bc61-915d90463e01', '80bb3c77-8f9e-47f4-a4fd-26eeaf403f7b', 'Каппадокия', 'Уникальный регион с туфовыми скалами, пещерными городами и полётами на воздушных шарах.', '2026-05-18 06:39:00.77185', '2026-05-18 06:39:00.77185', NULL);
INSERT INTO public.cities VALUES ('6b3f97bb-2e8b-4f93-85ce-483bcdb3b9e1', '80bb3c77-8f9e-47f4-a4fd-26eeaf403f7b', 'Бодрум', 'Элегантный курорт на Эгейском побережье, известный яхтами, клубами и замком Святого Петра.', '2026-05-18 06:39:00.77185', '2026-05-18 06:39:00.77185', NULL);
INSERT INTO public.cities VALUES ('141237a2-4ea7-4633-a6c5-18d40ebb0073', '80bb3c77-8f9e-47f4-a4fd-26eeaf403f7b', 'Измир', 'Третий по величине город Турции, современный портовый мегаполис с развитой культурой и набережной Корнальтъ.', '2026-05-18 06:39:00.77185', '2026-05-18 06:39:00.77185', NULL);
INSERT INTO public.cities VALUES ('153d3f68-a6f1-4fd6-aea1-7c376504db9b', 'b8d1a40b-13eb-46c7-82a3-d52fe0bac37d', 'Абу-Даби', 'Столица ОАЭ с величественной мечетью шейха Зайда, музеями и гоночной трассой Formula 1.', '2026-05-18 06:39:00.77185', '2026-05-18 06:39:00.77185', NULL);
