INSERT INTO public.pois VALUES ('123fdaf0-5251-4493-9147-55872468518a', 'Остров Кижи', 'Остров-музей с деревянными церквями XVIII века под открытым небом', 'Объект Всемирного наследия ЮНЕСКО. Главный памятник — 22-главая Преображенская церковь 1714 года постройки без единого гвоздя. Добраться: «Метеор» из Петрозаводска, 75 минут, стоимость около 3000 руб. в одну сторону. Режим работы: май–октябрь, 9:00–20:00. Зимой — по льду или вертолётом. Вход: 800–1200 руб. Рекомендуется бронировать билеты заранее в сезон.', '0101000020E610000014AE47E17A9C4140B84082E2C7084F40', false, '0ba5ba3e-fbbe-4af8-9f28-6c2c8bccdc10', NULL);
INSERT INTO public.pois VALUES ('2a9b1e5b-bd16-44a7-9352-c45fc0ae3d09', 'Горный парк Рускеала', 'Бывший мраморный карьер XVIII века — главная природная достопримечательность Карелии', 'Затопленный карьер итальянского мрамора, добывавшегося для Исаакиевского собора и Зимнего дворца. Изумрудная вода, отвесные скалы до 20 метров. Летом: лодки и SUP-бординг по карьеру; зимой: подсветка и горки. Стоимость входа: 400–700 руб. Лодка: 500 руб./час. От Сортавалы: 25 км (30 мин. на машине). Туристический поезд из Сортавалы летом.', '0101000020E610000086C954C1A8943E407FFB3A70CEF84E40', false, '0ba5ba3e-fbbe-4af8-9f28-6c2c8bccdc10', NULL);
INSERT INTO public.pois VALUES ('6e247a7f-c9cf-485f-b23c-354a75da46d7', 'Водопад Кивач', 'Один из крупнейших равнинных водопадов России в одноимённом заповеднике', 'Высота падения воды — 10.7 метров, ширина — 170 метров. Находится в заповеднике Кивач в 80 км от Петрозаводска. На территории: дендрарий, музей природы и минералов Карелии. Режим работы: 9:00–21:00 ежедневно. Вход: 250 руб. Удобно совмещать с посещением горы Сампо и питомника хаски.', '0101000020E610000007F0164850FC40400AD7A3703D224F40', false, '0ba5ba3e-fbbe-4af8-9f28-6c2c8bccdc10', NULL);
INSERT INTO public.pois VALUES ('79ff6f78-6135-403f-93a8-665419dba46b', 'Петрозаводская набережная', 'Главная прогулочная набережная столицы Карелии на берегу Онежского озера', 'Набережная Онего — центр городской жизни Петрозаводска. Скульптуры-подарки городов-побратимов: «Рыбаки» (Дулут, США), «Спящая красавица» (Берлин) и др. Рядом — Площадь Кирова, Краеведческий музей, рестораны карельской кухни. Выходы «Метеоров» на Кижи и Валаам отсюда.', '0101000020E61000003108AC1C5A2C41405BB1BFEC9EE44E40', false, '0ba5ba3e-fbbe-4af8-9f28-6c2c8bccdc10', NULL);
INSERT INTO public.pois VALUES ('1b320424-72a3-4c69-a4da-f48fa6092286', 'Гора Воттоваара', 'Мистическая гора с сейдами — культовыми камнями саамов', 'Высшая точка Западно-Карельской возвышенности (417 м). Знаменита «Смерть-горой» — лесом из искривлённых деревьев после снеговала. Более 1500 сейдов — камней, поставленных на маленькие подпорки. Путь из Петрозаводска: 180 км на авто + 7 км пешком. Лучшее время: июль–август. Ночёвка в палатке у подножия.', '0101000020E6100000F38E5374244F4040D3BCE3141D894F40', false, '0ba5ba3e-fbbe-4af8-9f28-6c2c8bccdc10', NULL);
INSERT INTO public.pois VALUES ('8fd82310-e0d6-491a-ada1-b8fb0c008ac1', 'Валаамский монастырь', 'Православный монастырь XIV века на архипелаге в Ладожском озере', 'Один из крупнейших монастырей России на архипелаге из 50 островов. Спасо-Преображенский собор, скиты, монастырские сады и ферма. Добраться: теплоход из Приозерска (~3 часа) или Сортавалы (~1.5 часа). На острове работают гостиницы; монастырская трапеза доступна для паломников. Режим работы: круглогодично, навигация — май–октябрь.', '0101000020E610000052B81E85EBF13E40711B0DE02DB04E40', false, '0ba5ba3e-fbbe-4af8-9f28-6c2c8bccdc10', NULL);
INSERT INTO public.pois VALUES ('542f2673-85ab-4cf0-9375-b6ff5020c6bb', 'Мраморный каньон Рускеала (зимний тур)', 'Ночная подсветка карьера и зимние развлечения — отдельный зимний опыт', 'Зимой горный парк преображается: иллюминация подсвечивает ледяные стены карьера, работают горки, тюбинг и экскурсии в штольни. Лыжная трасса по берегу карьера. Режим работы: декабрь–март, 10:00–21:00. Температура зимой: −10..−25°C — одевайтесь очень тепло.', '0101000020E6100000DBF97E6ABC943E407FFB3A70CEF84E40', false, '0ba5ba3e-fbbe-4af8-9f28-6c2c8bccdc10', NULL);
INSERT INTO public.pois VALUES ('d0b14107-d059-4090-812d-9e0fd55f1367', 'Онежское озеро (Петроглифы)', 'Наскальные рисунки IV–II тысячелетия до н.э. на берегу Онежского озера', 'Более 1200 петроглифов на мысах Бесов Нос, Карецкий Нос и Пери Нос. Возраст рисунков — 5000–7000 лет: изображения людей, животных, лодок и мифических существ. Добраться: 200 км от Петрозаводска, часть пути на лодке. Лучший сезон: июнь–август. Рекомендуется с гидом. Координаты Бесова Носа: 61.6417°N, 35.8303°E.', '0101000020E610000035EF384547EA4140EEEBC03923D24E40', false, '0ba5ba3e-fbbe-4af8-9f28-6c2c8bccdc10', NULL);
INSERT INTO public.pois VALUES ('1a882467-a802-4b8a-8bf5-69afb770391e', 'Карельская деревня Кинерма', 'Самая красивая деревня России — живой музей карельского быта', 'Деревня Кинерма — победитель конкурса «Самая красивая деревня России». Сохранились 17 традиционных карельских домов XVIII–XIX веков. Часовня Смоленской Богоматери — объект культурного наследия. Хозяйка деревни Надежда Калмыкова проводит экскурсии и угощает карельской кухней. В 60 км от Петрозаводска. Обязательное бронирование визита.', '0101000020E6100000BBB88D06F0AE4040787AA52C43D44E40', false, '0ba5ba3e-fbbe-4af8-9f28-6c2c8bccdc10', NULL);
INSERT INTO public.pois VALUES ('07d3bcaa-1f2a-47b0-9ba0-540cdb51c350', 'Краеведческий музей Карелии', 'Главный музей республики с коллекцией карельской культуры и природы', 'Основан в 1871 году, одна из богатейших коллекций Северо-Запада России. Залы: природа Карелии, история саамов и вепсов, деревянное зодчество, советский период. Адрес: пл. Ленина, 1, Петрозаводск. Режим работы: вт–вс 10:00–18:00. Вход: 300 руб. Рядом — Площадь Кирова и набережная Онего.', '0101000020E610000066666666662E41404E62105839E44E40', true, '0ba5ba3e-fbbe-4af8-9f28-6c2c8bccdc10', NULL);
