INSERT INTO public.trips VALUES ('dfcd7531-a714-4c6e-aba4-8617c926f5df', 'b108d26c-e301-448e-9b7e-da68dac89958', '0afc0ac8-f6dc-4ff6-a69b-c1c79923ca50', '8717ad74-80b9-4ac4-9640-bc1308ad3081', 'leisure', 'low', 2, '{active}', '2026-05-18', '2026-05-31', '2026-05-11 19:36:27.656387', 'Эта 14-дневная поездка в Бангкок идеально подходит для двух молодых и активных путешественников с экономным бюджетом, которые хотят окунуться в ночную жизнь, попробовать уличную еду и познакомиться с молодежью со всего мира. Маршрут включает посещение самых тусовочных мест, рынков с едой и возможностью для активного отдыха, а также места для расслабления после бурных ночей.', '30000-40000 бат (около 800-1100 евро) на группу на 14 дней, не включая перелет и проживание (очень экономный вариант, с упором на уличную еду и бесплатные развлечения)');
INSERT INTO public.trips VALUES ('2020f3dd-686e-46d1-8b32-3e4d1b7dcd5c', 'b108d26c-e301-448e-9b7e-da68dac89958', '0afc0ac8-f6dc-4ff6-a69b-c1c79923ca50', '8717ad74-80b9-4ac4-9640-bc1308ad3081', 'leisure', 'low', 3, '{active}', '2026-05-18', '2026-05-27', '2026-05-12 09:49:49.292231', 'Эта поездка в Бангкок для троих друзей-студентов, желающих отдохнуть от учебы, включает в себя насыщенную программу ночных развлечений, знакомство с местной кухней и активный туризм. Маршрут сфокусирован на бюджетных вариантах, предлагая множество возможностей для общения с молодежью со всего мира и получения ярких впечатлений.', 'Около 1500-2000 USD на группу (без учета перелета и проживания, но с учетом еды, транспорта, развлечений и ночной жизни на 10 дней).');
INSERT INTO public.trips VALUES ('ff5cfb7c-abcb-4cc4-811f-3c3d9f3d5f5e', 'b108d26c-e301-448e-9b7e-da68dac89958', '0afc0ac8-f6dc-4ff6-a69b-c1c79923ca50', '8717ad74-80b9-4ac4-9640-bc1308ad3081', 'leisure', 'medium', 2, '{balanced}', '2026-05-18', '2026-05-24', '2026-05-17 11:06:45.861277', 'Насладитесь романтическим путешествием в Бангкок, погрузившись в богатую культуру, изысканную кухню и оживленную атмосферу города. Этот маршрут разработан для пары, желающей исследовать как исторические достопримечательности, так и современные развлечения, с акцентом на комфорт и возможность понаблюдать за местной жизнью.', 'Средний (примерно 2000-3000 USD на двоих, без учета авиабилетов и проживания)');
INSERT INTO public.trips VALUES ('32374cb5-8cf3-44d7-9d1b-3fff0943a59f', 'b108d26c-e301-448e-9b7e-da68dac89958', '0afc0ac8-f6dc-4ff6-a69b-c1c79923ca50', 'f3e4f111-f0ec-4f7c-a3a7-2eaeb68a674e', 'leisure', 'medium', 3, '{balanced}', '2026-05-29', '2026-06-07', '2026-05-17 11:49:45.689385', 'Эта 10-дневная поездка на Пхукет идеально подходит для группы из трех человек со средним бюджетом, которые хотят совместить расслабленный пляжный отдых с активным туризмом и погружением в природу и культуру Таиланда. Маршрут охватывает живописные острова, исторические улицы, природные заповедники и местные рынки, предлагая разнообразные впечатления.', 'Примерно 2000-2500 долларов США на человека (без учета перелета и проживания), включая экскурсии, питание, транспорт и развлечения.');
INSERT INTO public.trips VALUES ('619c33ff-1cbe-433f-8955-8cdb9ddee9f4', 'b108d26c-e301-448e-9b7e-da68dac89958', '9b9a78e3-e6bb-441f-bcf5-7fa1bd55f478', '97a9a4ba-9773-49b9-a159-4184fba61299', 'leisure', 'low', 2, '{active}', '2026-06-24', '2026-06-26', '2026-05-17 12:03:47.475484', 'Эта поездка в Калининград идеально подходит для пары, желающей отдохнуть от суеты и погрузиться в атмосферу города. Маршрут сочетает культурные достопримечательности, активный отдых, гастрономические впечатления и вечерние развлечения, позволяя насладиться каждым моментом в своем ритме при экономном бюджете.', '10000-15000 руб. на группу');
INSERT INTO public.trips VALUES ('54d9610b-1f88-4ec2-95a9-baa0d016e6b4', 'b108d26c-e301-448e-9b7e-da68dac89958', '0afc0ac8-f6dc-4ff6-a69b-c1c79923ca50', '8717ad74-80b9-4ac4-9640-bc1308ad3081', 'leisure', 'medium', 2, '{balanced}', '2026-05-20', '2026-05-26', '2026-05-17 12:35:50.076894', 'Эта 7-дневная поездка в Бангкок специально разработана для двух человек со средним бюджетом, ориентированным на ночную жизнь, гастрономические приключения и активный туризм. Маршрут сбалансирован между культурными достопримечательностями, рынками, расслабляющими спа-процедурами и яркими вечерними развлечениями, чтобы каждый день был наполнен новыми впечатлениями.', 'Приблизительно 80,000 - 120,000 THB (2200 - 3300 USD) на двоих, исключая перелет и проживание, но включая еду, развлечения, транспорт и спа.');
INSERT INTO public.trips VALUES ('072e09c6-b681-4e53-9960-797ca6e7f1b3', 'b108d26c-e301-448e-9b7e-da68dac89958', '0afc0ac8-f6dc-4ff6-a69b-c1c79923ca50', 'f3e4f111-f0ec-4f7c-a3a7-2eaeb68a674e', 'leisure', 'medium', 4, '{relaxed}', '2026-05-19', '2026-05-25', '2026-05-18 00:38:57.155563', 'Эта 7-дневная поездка на Пхукет идеально подходит для группы из 4 человек, ищущих активный отдых, яркую ночную жизнь и гастрономические приключения. Маршрут сбалансирован между культурными достопримечательностями, природными красотами и возможностями для развлечений, обеспечивая комфортное путешествие со средним бюджетом.', 'Примерно 60 000 - 80 000 THB на группу (без учета проживания и перелетов)');
INSERT INTO public.trips VALUES ('f50f8aa9-3d59-438f-ab92-78b348b1d8f5', 'b108d26c-e301-448e-9b7e-da68dac89958', 'cceb7c00-55e5-42c3-9f8e-f3388e8e1127', '9a6c21db-8538-4721-bce9-96a06e37b368', 'leisure', 'medium', 2, '{balanced}', '2026-05-26', '2026-06-01', '2026-05-18 05:23:58.335763', 'Маршрут по Пусану для двух человек на 7 дней, ориентированный на кулинарные изыски, активный отдых и яркую ночную жизнь. Путешествие включает посещение рынков, парков, смотровых площадок и уютных баров, обеспечивая комфортный отдых со средним бюджетом.', '2000-2500 USD на группу');
INSERT INTO public.trips VALUES ('1a9b315c-f5b8-411b-befa-d1c6ca8abf5d', 'b108d26c-e301-448e-9b7e-da68dac89958', '30891716-033e-41ad-9893-631af79ad11a', '72df7555-6cda-41ca-8269-11b0d4885703', 'leisure', 'medium', 2, '{balanced}', '2026-05-26', '2026-06-01', '2026-05-18 05:27:59.542468', 'Насыщенное 7-дневное путешествие по Гуанчжоу для двух человек со средним бюджетом, ориентированное на культурное погружение, активный отдых и яркую ночную жизнь. Маршрут включает посещение исторических достопримечательностей, парков, а также знакомство с местной кухней и развлечениями.', '8000-12000 юаней на группу');
INSERT INTO public.trips VALUES ('ceb1a46f-f44c-4b15-be86-899d83febc59', 'b108d26c-e301-448e-9b7e-da68dac89958', 'e9e5cf1f-f4fc-4563-8ebb-2110f14cf5b8', '7b2a2673-2a59-40aa-b097-c2b46a72c95f', 'leisure', 'medium', 2, '{balanced}', '2026-05-26', '2026-06-01', '2026-05-18 06:30:26.716484', 'Эта поездка в Токио предлагает глубокое погружение в японскую культуру, сочетая посещение исторических храмов и музеев с современными арт-пространствами и кулинарными изысками. Маршрут разработан для двух человек со средним бюджетом, обеспечивая комфортное и насыщенное путешествие с акцентом на культурное обогащение.', '3500-4500 USD (без учета перелета и проживания)');
INSERT INTO public.trips VALUES ('2343e2c5-4e06-4276-8f34-b14c07ddb76c', 'b108d26c-e301-448e-9b7e-da68dac89958', '80bb3c77-8f9e-47f4-a4fd-26eeaf403f7b', 'd51638b8-7386-45fb-942d-15b52c2cd886', 'leisure', 'medium', 2, '{balanced}', '2026-05-26', '2026-06-01', '2026-05-18 06:55:26.157605', 'Эта 7-дневная поездка в Стамбул для двух человек ориентирована на глубокое погружение в культурное наследие города, его историю, искусство и уникальную атмосферу. Маршрут включает посещение знаковых достопримечательностей, музеев, исторических рынков и уютных кафе, а также возможность расслабиться в традиционном турецком хаммаме. Бюджет рассчитан на комфортное путешествие с учетом входных билетов, питания и транспорта.', '1200-1500 USD на группу');
INSERT INTO public.trips VALUES ('7b1e28a1-41c4-4f84-9902-71ee3587e166', 'b108d26c-e301-448e-9b7e-da68dac89958', 'b8d1a40b-13eb-46c7-82a3-d52fe0bac37d', 'ef7d5dbe-a660-450f-9c30-d9cce8b2c829', 'leisure', 'medium', 2, '{balanced}', '2026-05-27', '2026-05-30', '2026-05-18 07:26:01.468058', 'Эта 4-дневная поездка в Дубай предлагает идеальное сочетание современного туризма, культурного погружения и расслабляющего отдыха. Маршрут включает посещение знаковых достопримечательностей, знакомство с местной культурой и возможность насладиться комфортным отдыхом.', '4500-6000 AED на группу');
