INSERT INTO public.trip_pois VALUES ('dfcd7531-a714-4c6e-aba4-8617c926f5df', '0cef74e8-74b3-4d43-81dc-5dc4571002dc', NULL, NULL, 'main', true, 1, '18:00', '22:00', 4, '500 бат/чел', 'Начните вечер с прогулки по легендарной улице, попробуйте уличную еду и коктейли. Это центр притяжения молодежи со всего мира.', 'Прибытие и первое погружение в ночную жизнь');
INSERT INTO public.trip_pois VALUES ('dfcd7531-a714-4c6e-aba4-8617c926f5df', '83b39e59-3d43-46fe-9462-51d0727c5b82', NULL, NULL, 'main', true, 1, '22:00', '02:00', 4, '300 бат/чел (вход + напиток)', 'Один из самых известных клубов Бангкока, отличное место для танцев и знакомств. Приходите пораньше, чтобы избежать очередей.', 'Прибытие и первое погружение в ночную жизнь');
INSERT INTO public.trip_pois VALUES ('dfcd7531-a714-4c6e-aba4-8617c926f5df', '0d579681-a4fc-4780-a978-155a6be8396f', NULL, NULL, 'additional', false, 1, '16:00', '18:00', 2, '200 бат/чел', 'Отличный вариант для бюджетного шопинга и перекуса перед вечерними развлечениями. Можно найти недорогую одежду и сувениры.', 'Прибытие и первое погружение в ночную жизнь');
INSERT INTO public.trip_pois VALUES ('dfcd7531-a714-4c6e-aba4-8617c926f5df', 'd91b9083-9795-42be-b2c9-9c00a09e265c', NULL, NULL, 'main', true, 11, '12:00', '13:30', 1.5, '0', 'Красивое и спокойное место, где можно полюбоваться бабочками и узнать о насекомых. Бесплатный вход.', 'Музеи и пивные бары');
INSERT INTO public.trip_pois VALUES ('dfcd7531-a714-4c6e-aba4-8617c926f5df', '1ec5d24c-4262-49bb-8f97-7cfb2dca3c6b', NULL, NULL, 'additional', false, 1, '23:00', '02:00', 3, '300 бат/чел (вход + напиток)', 'Еще один популярный клуб в районе Каосан, если хотите сменить обстановку или ищете более разнообразную музыку.', 'Прибытие и первое погружение в ночную жизнь');
INSERT INTO public.trip_pois VALUES ('dfcd7531-a714-4c6e-aba4-8617c926f5df', '3b62206c-42cd-4f81-92e5-c9a2c2414e20', NULL, NULL, 'main', true, 2, '09:00', '11:00', 2, '500 бат/чел', 'Посетите Храм Изумрудного Будды. Одевайтесь скромно (плечи и колени должны быть прикрыты). Приходите рано утром, чтобы избежать толп.', 'Храмы, рынки и ночной базар у реки');
INSERT INTO public.trip_pois VALUES ('dfcd7531-a714-4c6e-aba4-8617c926f5df', 'f0ff55ac-1f6f-4db5-b1e3-eadbb5415d79', NULL, NULL, 'main', true, 2, '11:30', '13:00', 1.5, '100 бат/чел', 'Переправьтесь через реку на пароме, чтобы увидеть Храм Рассвета. Виды на реку и город потрясающие.', 'Храмы, рынки и ночной базар у реки');
INSERT INTO public.trip_pois VALUES ('dfcd7531-a714-4c6e-aba4-8617c926f5df', '92a1368c-3e41-4a94-a17b-8311021c1d5f', NULL, NULL, 'main', true, 2, '18:00', '22:00', 4, '500 бат/чел (еда/шопинг)', 'Вечерний рынок у реки с множеством магазинов, ресторанов и развлечений. Отличное место для ужина и прогулки.', 'Храмы, рынки и ночной базар у реки');
INSERT INTO public.trip_pois VALUES ('dfcd7531-a714-4c6e-aba4-8617c926f5df', 'b016e68f-4cd6-454d-bc5c-17de70870a52', NULL, NULL, 'additional', false, 2, '14:00', '14:30', 0.5, '0', 'Исторический памятник, расположенный недалеко от Каосан Роуд. Интересно для общего развития, если будете проходить мимо.', 'Храмы, рынки и ночной базар у реки');
INSERT INTO public.trip_pois VALUES ('dfcd7531-a714-4c6e-aba4-8617c926f5df', 'c3f66d8b-6236-4174-8f8f-8999c7b0c9ea', NULL, NULL, 'additional', false, 2, '15:00', '17:00', 2, '200 бат/чел', 'Один из старейших оптовых рынков Бангкока, где можно найти все, от тканей до сувениров по очень низким ценам. Отличный опыт местного колорита.', 'Храмы, рынки и ночной базар у реки');
INSERT INTO public.trip_pois VALUES ('dfcd7531-a714-4c6e-aba4-8617c926f5df', '6795a1a1-757e-4f85-8d69-f8fe81dadb4c', NULL, NULL, 'main', true, 3, '10:00', '14:00', 4, '500 бат/чел', 'Один из крупнейших рынков в мире, работает по выходным. Здесь можно найти все, что угодно. Торгуйтесь!', 'Шопинг, небоскребы и вечеринка на крыше');
INSERT INTO public.trip_pois VALUES ('dfcd7531-a714-4c6e-aba4-8617c926f5df', 'e99bc00f-d5fe-4370-a4b4-5fab773a0d14', NULL, NULL, 'main', true, 3, '17:00', '19:00', 2, '800 бат/чел', 'Полюбуйтесь панорамными видами Бангкока с высоты птичьего полета. Особенно красиво на закате.', 'Шопинг, небоскребы и вечеринка на крыше');
INSERT INTO public.trip_pois VALUES ('dfcd7531-a714-4c6e-aba4-8617c926f5df', '8f4420e1-b405-467a-9960-e3d6b9ccff51', NULL, NULL, 'main', true, 3, '19:00', '22:00', 3, '700 бат/чел (напитки)', 'Бар на крыше King Power Mahanakhon. Продолжите вечер с коктейлями и потрясающими ночными видами города.', 'Шопинг, небоскребы и вечеринка на крыше');
INSERT INTO public.trip_pois VALUES ('dfcd7531-a714-4c6e-aba4-8617c926f5df', 'b0b1abc5-3739-4837-9b4c-890539ec6025', NULL, NULL, 'additional', false, 3, '14:30', '16:00', 1.5, '0', 'Отличное место для отдыха после шопинга на рынке Чатучак. Можно погулять или просто расслабиться.', 'Шопинг, небоскребы и вечеринка на крыше');
INSERT INTO public.trip_pois VALUES ('dfcd7531-a714-4c6e-aba4-8617c926f5df', '95888122-36ef-4291-ac26-49ff28fe899a', NULL, NULL, 'additional', false, 3, '16:00', '17:30', 1.5, '400 бат/чел', 'Альтернативный вариант смотровой площадки, если хотите сэкономить или просто посмотреть на город с другой высоты.', 'Шопинг, небоскребы и вечеринка на крыше');
INSERT INTO public.trip_pois VALUES ('dfcd7531-a714-4c6e-aba4-8617c926f5df', '4e58d9be-35a9-44de-a986-2b924edd38ff', NULL, NULL, 'main', true, 4, '09:00', '14:00', 5, '1500 бат/чел', 'Погрузитесь в местную культуру, прокатившись по каналам и научившись готовить тайские блюда. Это интерактивный и вкусный опыт.', 'Кулинарные приключения и релакс');
INSERT INTO public.trip_pois VALUES ('dfcd7531-a714-4c6e-aba4-8617c926f5df', 'f22db413-6760-4177-a841-db42c2994513', NULL, NULL, 'main', true, 4, '16:00', '18:00', 2, '500 бат/чел', 'Расслабляющий массаж после активного дня. Отличное соотношение цены и качества для бюджетного отдыха.', 'Кулинарные приключения и релакс');
INSERT INTO public.trip_pois VALUES ('dfcd7531-a714-4c6e-aba4-8617c926f5df', '352d337d-b59e-4520-b327-b751c749eb1c', NULL, NULL, 'main', true, 4, '19:00', '21:30', 2.5, '700 бат/чел', 'Попробуйте свежие морепродукты в формате шведского стола с видом на реку. Отличный способ наесться до отвала.', 'Кулинарные приключения и релакс');
INSERT INTO public.trip_pois VALUES ('dfcd7531-a714-4c6e-aba4-8617c926f5df', 'dd5ac82b-04d9-4cb3-bfdd-14a9f8a72c26', NULL, NULL, 'additional', false, 4, '08:00', '09:00', 1, '150 бат/чел', 'Завтрак в уютном кафе перед началом кулинарного приключения. Попробуйте местный кофе.', 'Кулинарные приключения и релакс');
INSERT INTO public.trip_pois VALUES ('dfcd7531-a714-4c6e-aba4-8617c926f5df', '42a6627c-4ab9-4d7b-ae7a-3c58c3e69af1', NULL, NULL, 'additional', false, 4, '15:30', '17:00', 1.5, '400 бат/чел', 'Еще один вариант для бюджетного массажа, если Loft Thai Spa занят или хотите попробовать что-то другое поблизости.', 'Кулинарные приключения и релакс');
INSERT INTO public.trip_pois VALUES ('dfcd7531-a714-4c6e-aba4-8617c926f5df', '2084b58d-4980-4b2b-be9c-a17b5b5d3901', NULL, NULL, 'main', true, 5, '10:00', '12:30', 2.5, '0', 'Прогуляйтесь по одному из самых больших парков Бангкока, возьмите велосипед напрокат и насладитесь природой. Отличное место для утренней активности.', 'Парки, искусство и живая музыка');
INSERT INTO public.trip_pois VALUES ('dfcd7531-a714-4c6e-aba4-8617c926f5df', '4ba942fd-69ab-40d2-959c-53ef2e352807', NULL, NULL, 'main', true, 5, '14:00', '16:00', 2, '0', 'Бесплатный вход, интересные выставки современного искусства. Отличная возможность прикоснуться к культуре.', 'Парки, искусство и живая музыка');
INSERT INTO public.trip_pois VALUES ('dfcd7531-a714-4c6e-aba4-8617c926f5df', 'e6700b07-1d62-4186-ad2a-e6a3f1c71464', NULL, NULL, 'main', true, 5, '20:00', '23:00', 3, '500 бат/чел (напитки)', 'Легендарный джаз-клуб с живой музыкой. Отличная атмосфера для вечернего отдыха и знакомств с местной интеллигенцией.', 'Парки, искусство и живая музыка');
INSERT INTO public.trip_pois VALUES ('dfcd7531-a714-4c6e-aba4-8617c926f5df', 'c6205efd-e961-485e-8af9-d3f61c5a10be', NULL, NULL, 'additional', false, 5, '12:30', '13:30', 1, '0', 'Соседний парк с Вачирабенчатат, можно объединить прогулку по двум паркам.', 'Парки, искусство и живая музыка');
INSERT INTO public.trip_pois VALUES ('dfcd7531-a714-4c6e-aba4-8617c926f5df', '3a1cc556-a1ce-44cf-a245-1f0a5c722aaf', NULL, NULL, 'additional', false, 5, '16:30', '18:00', 1.5, '100 бат/чел (кофе)', 'Небольшая галерея с уютным кафе. Хорошее место для перерыва и знакомства с работами местных художников.', 'Парки, искусство и живая музыка');
INSERT INTO public.trip_pois VALUES ('dfcd7531-a714-4c6e-aba4-8617c926f5df', 'c824357b-585e-4f21-9438-a3274ae5196a', NULL, NULL, 'main', true, 6, '10:00', '16:00', 6, '900 бат/чел', 'Проведите день в аквапарке и парке аттракционов. Отличный способ охладиться и получить заряд адреналина.', 'Активный отдых и техно-вечеринка');
INSERT INTO public.trip_pois VALUES ('dfcd7531-a714-4c6e-aba4-8617c926f5df', 'e2c2bf0f-cc86-494d-8709-db19d4916ce0', NULL, NULL, 'main', true, 6, '22:00', '03:00', 5, '500 бат/чел (вход + напитки)', 'Если вы любите техно и пси-транс, следите за анонсами Rave Times. Это не клуб, а организатор мероприятий, поэтому место проведения может меняться. Идеально для ''жесткой тусовки'' с местной и международной молодежью.', 'Активный отдых и техно-вечеринка');
INSERT INTO public.trip_pois VALUES ('dfcd7531-a714-4c6e-aba4-8617c926f5df', 'b78ad908-7275-4018-b598-512e93491b42', NULL, NULL, 'additional', false, 6, '17:00', '18:00', 1, '600 бат/чел', 'Если вы хотите попробовать что-то экстремальное, но не хотите ехать далеко, флайборд может быть интересным вариантом.', 'Активный отдых и техно-вечеринка');
INSERT INTO public.trip_pois VALUES ('dfcd7531-a714-4c6e-aba4-8617c926f5df', '88305b6f-3349-45e1-9630-f452a9da9f28', NULL, NULL, 'additional', false, 6, '23:00', '02:00', 3, '400 бат/чел (вход + напитки)', 'Популярный клуб с разнообразной музыкой, если Rave Times не совпадает с вашими музыкальными предпочтениями или нет мероприятия в этот день.', 'Активный отдых и техно-вечеринка');
INSERT INTO public.trip_pois VALUES ('dfcd7531-a714-4c6e-aba4-8617c926f5df', '60057fef-ec7e-4f74-9b24-a05fb5c3fa1c', NULL, NULL, 'main', true, 7, '12:00', '14:00', 2, '300 бат/чел', 'Отведайте традиционную тайскую кухню в этом аутентичном ресторане. Отличный выбор для обеда.', 'Гастрономический день и спорт-бары');
INSERT INTO public.trip_pois VALUES ('dfcd7531-a714-4c6e-aba4-8617c926f5df', 'f4662788-1972-4fa9-be3b-773296da2692', NULL, NULL, 'main', true, 7, '20:00', '23:00', 3, '500 бат/чел (напитки + закуски)', 'Спорт-бар с отличной атмосферой, где можно посмотреть матчи, выпить пива и пообщаться с другими путешественниками.', 'Гастрономический день и спорт-бары');
INSERT INTO public.trip_pois VALUES ('dfcd7531-a714-4c6e-aba4-8617c926f5df', '576b25a9-8ead-4e00-833c-1e8960059248', NULL, NULL, 'additional', false, 7, '13:00', '14:30', 1.5, '400 бат/чел', 'Если захочется разнообразия, попробуйте турецкую кухню. Отличный вариант для вкусного обеда.', 'Гастрономический день и спорт-бары');
INSERT INTO public.trip_pois VALUES ('dfcd7531-a714-4c6e-aba4-8617c926f5df', '6686a893-d271-49a8-ad03-afa2bb9ccb80', NULL, NULL, 'additional', false, 7, '21:00', '23:30', 2.5, '400 бат/чел (напитки)', 'Еще один английский паб, если O''Leary''s переполнен или вы хотите сменить место.', 'Гастрономический день и спорт-бары');
INSERT INTO public.trip_pois VALUES ('dfcd7531-a714-4c6e-aba4-8617c926f5df', '42ee1196-e490-44b6-930c-3d0f0ce70e58', NULL, NULL, 'main', true, 8, '09:00', '17:00', 8, '800 бат/чел (трансфер + еда)', 'Отправьтесь на однодневную поездку на пляж Сай Кео. Можно доехать на автобусе до Паттайи, а оттуда на лодке. Насладитесь солнцем, морем и водными видами спорта.', 'Отдых на пляже и водные виды спорта');
INSERT INTO public.trip_pois VALUES ('dfcd7531-a714-4c6e-aba4-8617c926f5df', 'f41a3257-2105-4b76-a893-0b3e32b37113', NULL, NULL, 'additional', false, 8, '09:30', '16:30', 7, '700 бат/чел (трансфер + еда)', 'Еще один красивый пляж на острове Ко Лан, куда можно добраться с Паттайи. Отличная альтернатива Сай Кео.', 'Отдых на пляже и водные виды спорта');
INSERT INTO public.trip_pois VALUES ('dfcd7531-a714-4c6e-aba4-8617c926f5df', 'e96de9a3-dd9b-41b5-acf4-7936e723a08a', NULL, NULL, 'main', true, 9, '10:00', '11:30', 1.5, '50 бат/чел', 'Поднимитесь на Золотую Гору, чтобы насладиться панорамными видами города и посетить древний храм. Приходите утром, пока не так жарко.', 'Культура, история и ночные развлечения');
INSERT INTO public.trip_pois VALUES ('dfcd7531-a714-4c6e-aba4-8617c926f5df', 'd42495f0-5212-47f1-af7a-1fac9dc958ce', NULL, NULL, 'main', true, 9, '13:00', '14:30', 1.5, '300 бат/чел', 'Современный тайский ресторан с отличной кухней. Хороший вариант для обеда после посещения храма.', 'Культура, история и ночные развлечения');
INSERT INTO public.trip_pois VALUES ('dfcd7531-a714-4c6e-aba4-8617c926f5df', '7d75d57e-d7e1-4954-b6a7-4f5bf83a0ba6', NULL, NULL, 'additional', false, 9, '15:00', '17:00', 2, '100 бат/чел', 'Музей, посвященный истории и культуре района Раттанакосин. Интересно для тех, кто хочет узнать больше о Бангкоке.', 'Культура, история и ночные развлечения');
INSERT INTO public.trip_pois VALUES ('dfcd7531-a714-4c6e-aba4-8617c926f5df', '37169b77-0611-4104-b6b4-ac6c56848eea', NULL, NULL, 'additional', false, 9, '20:00', '22:00', 2, '800 бат/чел (напитки)', 'Легендарный джаз-бар в отеле Mandarin Oriental. Более изысканная атмосфера, чем в других местах, но отличное место для коктейлей.', 'Культура, история и ночные развлечения');
INSERT INTO public.trip_pois VALUES ('dfcd7531-a714-4c6e-aba4-8617c926f5df', '4b5f0ee6-f210-42a4-9f86-f61aa7c6106c', NULL, NULL, 'main', true, 10, '10:00', '11:30', 1.5, '200 бат/чел', 'Посмотрите на змей и узнайте о них больше. Есть шоу с демонстрацией змей, что может быть очень интересно.', 'Животный мир и расслабление');
INSERT INTO public.trip_pois VALUES ('dfcd7531-a714-4c6e-aba4-8617c926f5df', 'ef187127-1531-46d2-8a76-f5e45fafd73c', NULL, NULL, 'main', true, 10, '12:00', '15:00', 3, '900 бат/чел', 'Крупнейший аквариум в Юго-Восточной Азии. Отличное место, чтобы провести несколько часов, наблюдая за морскими обитателями.', 'Животный мир и расслабление');
INSERT INTO public.trip_pois VALUES ('dfcd7531-a714-4c6e-aba4-8617c926f5df', 'b2b66a25-914f-4995-8701-f4fba7daa75e', NULL, NULL, 'main', true, 10, '17:00', '19:00', 2, '500 бат/чел', 'Еще один отличный спа-салон от Loft Thai Spa. Идеально для расслабления после насыщенного дня.', 'Животный мир и расслабление');
INSERT INTO public.trip_pois VALUES ('dfcd7531-a714-4c6e-aba4-8617c926f5df', '710a36b1-2f98-44aa-910b-5820b9f78879', NULL, NULL, 'additional', false, 10, '10:30', '12:30', 2, '250 бат/чел', 'Если вы любите животных, этот зоопарк на крыше торгового центра может быть интересным вариантом.', 'Животный мир и расслабление');
INSERT INTO public.trip_pois VALUES ('dfcd7531-a714-4c6e-aba4-8617c926f5df', '4861acf2-e89b-4689-b3cb-a28e54857a5e', NULL, NULL, 'additional', false, 10, '17:30', '19:00', 1.5, '600 бат/чел', 'Более роскошный вариант спа, если хотите побаловать себя.', 'Животный мир и расслабление');
INSERT INTO public.trip_pois VALUES ('dfcd7531-a714-4c6e-aba4-8617c926f5df', '5c53524a-408e-4931-aa94-90d1d6344ac4', NULL, NULL, 'main', true, 11, '19:00', '22:00', 3, '600 бат/чел (пиво + закуски)', 'Отличный выбор крафтового пива и закусок. Хорошее место для любителей пива и общения.', 'Музеи и пивные бары');
INSERT INTO public.trip_pois VALUES ('dfcd7531-a714-4c6e-aba4-8617c926f5df', 'ce6716f2-57b3-4e57-8b54-ae26c5d8bdb4', NULL, NULL, 'additional', false, 11, '14:00', '15:00', 1, '0', 'Еще один небольшой музей, если интересуетесь местной историей и архитектурой.', 'Музеи и пивные бары');
INSERT INTO public.trip_pois VALUES ('dfcd7531-a714-4c6e-aba4-8617c926f5df', 'af39d632-66db-4cf7-b8de-9d8eb34a50f2', NULL, NULL, 'additional', false, 11, '20:00', '22:30', 2.5, '400 бат/чел (напитки)', 'Популярный паб с хорошим выбором напитков и закусок. Отличная атмосфера.', 'Музеи и пивные бары');
INSERT INTO public.trip_pois VALUES ('dfcd7531-a714-4c6e-aba4-8617c926f5df', '075d861b-bfe1-46e2-8012-9b2c3373a479', NULL, NULL, 'main', true, 12, '09:00', '11:00', 2, '0', 'Насладитесь утренней прогулкой или пробежкой в одном из самых больших парков Бангкока.', 'Парки, смотровые площадки и уличная еда');
INSERT INTO public.trip_pois VALUES ('dfcd7531-a714-4c6e-aba4-8617c926f5df', 'f623f038-4cef-4e97-9669-908afbb2e062', NULL, NULL, 'main', true, 12, '12:00', '12:30', 0.5, '0', 'Исторический памятник и крупный транспортный узел. Интересно посмотреть на архитектуру и местную жизнь.', 'Парки, смотровые площадки и уличная еда');
INSERT INTO public.trip_pois VALUES ('dfcd7531-a714-4c6e-aba4-8617c926f5df', 'e49d31ac-90c7-4a3b-812d-ef55c1296187', NULL, NULL, 'main', true, 12, '18:00', '20:30', 2.5, '300 бат/чел (еда/шопинг)', 'Индийский квартал Бангкока. Попробуйте индийскую уличную еду и окунитесь в атмосферу другого мира.', 'Парки, смотровые площадки и уличная еда');
INSERT INTO public.trip_pois VALUES ('dfcd7531-a714-4c6e-aba4-8617c926f5df', '36d222df-65a2-4361-b69e-4dcdf3dbeb4b', NULL, NULL, 'additional', false, 12, '10:30', '11:30', 1, '0', 'Небольшой, но уютный парк, если хотите отдохнуть от суеты.', 'Парки, смотровые площадки и уличная еда');
INSERT INTO public.trip_pois VALUES ('dfcd7531-a714-4c6e-aba4-8617c926f5df', '91c2b239-6510-476a-ae20-a4c3472c9ca0', NULL, NULL, 'main', true, 13, '10:00', '12:00', 2, '0', 'Посетите современную художественную галерею, где представлены работы тайских и международных художников.', 'Искусство, кафе и прощальная вечеринка');
INSERT INTO public.trip_pois VALUES ('dfcd7531-a714-4c6e-aba4-8617c926f5df', 'fe9a7d84-a3ff-40ae-90d8-83a52acfc4c9', NULL, NULL, 'main', true, 13, '12:30', '14:00', 1.5, '250 бат/чел', 'Уютное кафе с красивым интерьером и вкусным кофе. Отличное место для обеда или легкого перекуса.', 'Искусство, кафе и прощальная вечеринка');
INSERT INTO public.trip_pois VALUES ('dfcd7531-a714-4c6e-aba4-8617c926f5df', '0b3374b8-3f44-4ac4-bcdf-2bf9086b1c14', NULL, NULL, 'main', true, 13, '21:00', '01:00', 4, '600 бат/чел (напитки)', 'Один из популярных баров на Каосан Роуд, если вы хотите провести последнюю ночь в Бангкоке весело и беззаботно. Здесь всегда много молодежи.', 'Искусство, кафе и прощальная вечеринка');
INSERT INTO public.trip_pois VALUES ('dfcd7531-a714-4c6e-aba4-8617c926f5df', '6903ced7-d63d-444b-b437-af463658fb20', NULL, NULL, 'additional', false, 13, '14:00', '15:00', 1, '0', 'Небольшая галерея, если хотите увидеть больше местного искусства.', 'Искусство, кафе и прощальная вечеринка');
INSERT INTO public.trip_pois VALUES ('dfcd7531-a714-4c6e-aba4-8617c926f5df', '1628edb5-de15-47a8-ac1a-474225c0386d', NULL, NULL, 'additional', false, 13, '22:00', '01:00', 3, '500 бат/чел (напитки)', 'Еще один бар в районе Каосан, если Happy Bar не по вкусу или вы хотите попробовать что-то новое.', 'Искусство, кафе и прощальная вечеринка');
INSERT INTO public.trip_pois VALUES ('dfcd7531-a714-4c6e-aba4-8617c926f5df', '8d67e487-5872-4e66-8946-4ce1bda0396f', NULL, NULL, 'main', true, 14, '10:00', '11:30', 1.5, '300 бат/чел', 'Купите последние сувениры и подарки перед отъездом. Здесь можно найти что-то уникальное.', 'Прощание с Бангкоком и отъезд');
INSERT INTO public.trip_pois VALUES ('dfcd7531-a714-4c6e-aba4-8617c926f5df', '9eed7d67-ca3f-4d5b-9a51-6f58f3a927b7', NULL, NULL, 'main', true, 14, '12:00', '13:30', 1.5, '250 бат/чел', 'Последний тайский обед в уютном кафе перед отъездом. Насладитесь вкусами Таиланда напоследок.', 'Прощание с Бангкоком и отъезд');
INSERT INTO public.trip_pois VALUES ('dfcd7531-a714-4c6e-aba4-8617c926f5df', '02196f3f-df57-40dd-8ad9-5498ee1ee7fb', NULL, NULL, 'additional', false, 14, '09:00', '10:00', 1, '0', 'Если у вас осталось время и вы хотите что-то быстро посмотреть, можно поискать короткие экскурсии или просто погулять по району.', 'Прощание с Бангкоком и отъезд');
INSERT INTO public.trip_pois VALUES ('dfcd7531-a714-4c6e-aba4-8617c926f5df', 'ec8a5198-c3fb-4d79-ab03-80c7f1963146', NULL, NULL, 'additional', false, 14, '11:00', '12:00', 1, '200 бат/чел', 'Отличный вариант для завтрака или бранча, если вы любите европейскую кухню и хороший кофе.', 'Прощание с Бангкоком и отъезд');
INSERT INTO public.trip_pois VALUES ('2020f3dd-686e-46d1-8b32-3e4d1b7dcd5c', 'da0a6ec3-f51d-4812-b89d-d59cdaf8f303', NULL, NULL, 'main', true, 1, '14:00', '16:00', 2, '300-500 бат/группа за такси до центра', 'По прибытии возьмите такси или воспользуйтесь общественным транспортом до вашего жилья. Убедитесь, что таксист включил счетчик.', 'Прибытие и первое погружение в ночной Бангкок');
INSERT INTO public.trip_pois VALUES ('2020f3dd-686e-46d1-8b32-3e4d1b7dcd5c', '0cef74e8-74b3-4d43-81dc-5dc4571002dc', NULL, NULL, 'main', true, 1, '19:00', '23:00', 4, '300-500 бат/чел за еду и напитки', 'Идеальное место для первого знакомства с ночной жизнью Бангкока, уличной едой и общением с другими туристами. Попробуйте местный стрит-фуд.', 'Прибытие и первое погружение в ночной Бангкок');
INSERT INTO public.trip_pois VALUES ('2020f3dd-686e-46d1-8b32-3e4d1b7dcd5c', '9a0b2de2-411a-4c64-8fad-f406a042530b', NULL, NULL, 'main', true, 1, '23:00', '02:00', 3, '200-400 бат/чел за вход/напитки', 'Один из самых популярных клубов на Кхао Сан Роуд, где можно танцевать до утра и познакомиться с молодежью.', 'Прибытие и первое погружение в ночной Бангкок');
INSERT INTO public.trip_pois VALUES ('2020f3dd-686e-46d1-8b32-3e4d1b7dcd5c', '4e3f65b7-1b2d-4cbd-b8da-f1bc2576af13', NULL, NULL, 'additional', false, 1, '17:00', '18:00', 1, '0', 'Отличное место для прогулки и отдыха после заселения, недалеко от Кхао Сан Роуд. Можно посмотреть закат над рекой.', 'Прибытие и первое погружение в ночной Бангкок');
INSERT INTO public.trip_pois VALUES ('2020f3dd-686e-46d1-8b32-3e4d1b7dcd5c', 'af39d632-66db-4cf7-b8de-9d8eb34a50f2', NULL, NULL, 'additional', false, 1, '22:00', '00:00', 2, '300-500 бат/чел', 'Если ищете более расслабленную атмосферу бара перед клубом, это хороший вариант недалеко от Khao San Road.', 'Прибытие и первое погружение в ночной Бангкок');
INSERT INTO public.trip_pois VALUES ('2020f3dd-686e-46d1-8b32-3e4d1b7dcd5c', '98630f5e-5f18-4da2-ba67-dbd90bfd0bde', NULL, NULL, 'main', true, 2, '09:00', '11:00', 2, '200 бат/чел', 'Посетите храм Лежащего Будды. Приходите пораньше, чтобы избежать толп. Одевайтесь скромно.', 'Храмы, рынки и ночная жизнь');
INSERT INTO public.trip_pois VALUES ('2020f3dd-686e-46d1-8b32-3e4d1b7dcd5c', '709a596b-1ee2-4a9e-be7e-a6b8cbe12c9f', NULL, NULL, 'main', true, 2, '11:30', '13:00', 1.5, '100 бат/чел за вход, 5 бат/чел за паром', 'Переправьтесь на пароме через реку Чао Прайя. Храм очень фотогеничен, особенно на фоне неба.', 'Храмы, рынки и ночная жизнь');
INSERT INTO public.trip_pois VALUES ('2020f3dd-686e-46d1-8b32-3e4d1b7dcd5c', '47b706ea-66aa-4c94-9995-644cd6c5027c', NULL, NULL, 'main', true, 2, '14:00', '17:00', 3, '200-400 бат/чел за еду и сувениры', 'Погрузитесь в атмосферу местного плавучего рынка. Попробуйте свежие морепродукты и фрукты.', 'Храмы, рынки и ночная жизнь');
INSERT INTO public.trip_pois VALUES ('2020f3dd-686e-46d1-8b32-3e4d1b7dcd5c', '9aee3e76-ad98-4a6d-bdb4-63e06c3fd833', NULL, NULL, 'main', true, 2, '23:00', '02:00', 3, '300-600 бат/чел за вход/напитки', 'Один из самых популярных хип-хоп клубов Бангкока, отличное место для танцев и знакомств.', 'Храмы, рынки и ночная жизнь');
INSERT INTO public.trip_pois VALUES ('2020f3dd-686e-46d1-8b32-3e4d1b7dcd5c', '198243e1-142a-4a27-b6dc-0d666db220a6', NULL, NULL, 'additional', false, 2, '10:00', '11:30', 1.5, '50 бат/чел', 'Предлагает панорамные виды на город после подъема по сотням ступеней. Хорошая альтернатива, если хотите больше видов.', 'Храмы, рынки и ночная жизнь');
INSERT INTO public.trip_pois VALUES ('2020f3dd-686e-46d1-8b32-3e4d1b7dcd5c', '0d579681-a4fc-4780-a978-155a6be8396f', NULL, NULL, 'additional', false, 2, '20:00', '22:00', 2, '200-500 бат/чел', 'Отличный ночной рынок для шопинга и еды. Более бюджетный, чем некоторые другие рынки.', 'Храмы, рынки и ночная жизнь');
INSERT INTO public.trip_pois VALUES ('2020f3dd-686e-46d1-8b32-3e4d1b7dcd5c', 'c824357b-585e-4f21-9438-a3274ae5196a', NULL, NULL, 'main', true, 3, '10:00', '16:00', 6, '900-1200 бат/чел', 'Крупнейший парк аттракционов и аквапарк в Бангкоке. Отличный способ активно провести день и отдохнуть от городской суеты.', 'Активный день и тусовки на Сукхумвите');
INSERT INTO public.trip_pois VALUES ('2020f3dd-686e-46d1-8b32-3e4d1b7dcd5c', 'bdfe84fa-d6f8-40b9-bba3-b90f1c68a835', NULL, NULL, 'main', true, 3, '19:00', '21:00', 2, '500-800 бат/чел', 'Хотя это ресторан, он известен своей стильной атмосферой и баром. Может быть немного дороже, но стоит того для особого вечера.', 'Активный день и тусовки на Сукхумвите');
INSERT INTO public.trip_pois VALUES ('2020f3dd-686e-46d1-8b32-3e4d1b7dcd5c', '408ff70e-0ef0-45aa-9c6c-33739aed644a', NULL, NULL, 'main', true, 3, '23:00', '02:00', 3, '300-500 бат/чел', 'Популярный ночной клуб с хорошей музыкой и атмосферой для тусовок.', 'Активный день и тусовки на Сукхумвите');
INSERT INTO public.trip_pois VALUES ('2020f3dd-686e-46d1-8b32-3e4d1b7dcd5c', 'd70c09c5-627c-49ba-91c7-ff94672e5e51', NULL, NULL, 'additional', false, 3, '08:00', '10:00', 2, '0', 'Если Siam Park City кажется слишком дорогим, проведите утро в этом красивом парке, можно заняться йогой или просто прогуляться.', 'Активный день и тусовки на Сукхумвите');
INSERT INTO public.trip_pois VALUES ('2020f3dd-686e-46d1-8b32-3e4d1b7dcd5c', '156f7b1e-9763-4ea6-a0d5-a940b65ca4bf', NULL, NULL, 'additional', false, 3, '00:00', '03:00', 3, '300-500 бат/чел', 'Известен своей электронной музыкой и андеграундной атмосферой. Отличная альтернатива для любителей техно.', 'Активный день и тусовки на Сукхумвите');
INSERT INTO public.trip_pois VALUES ('2020f3dd-686e-46d1-8b32-3e4d1b7dcd5c', 'e99bc00f-d5fe-4370-a4b4-5fab773a0d14', NULL, NULL, 'main', true, 4, '10:00', '12:00', 2, '850-1050 бат/чел', 'Посетите одну из самых высоких смотровых площадок Бангкока. Стеклянный пол даст вам незабываемые ощущения.', 'Высоты и рынки выходного дня');
INSERT INTO public.trip_pois VALUES ('2020f3dd-686e-46d1-8b32-3e4d1b7dcd5c', 'ca6cc99a-f0aa-464b-806f-9ff13073c1ac', NULL, NULL, 'main', true, 4, '13:00', '17:00', 4, '500-1000 бат/чел за еду и шопинг', 'Один из крупнейших рынков в мире, открыт в выходные. Здесь можно найти все, от одежды до сувениров. Обязательно торгуйтесь!', 'Высоты и рынки выходного дня');
INSERT INTO public.trip_pois VALUES ('2020f3dd-686e-46d1-8b32-3e4d1b7dcd5c', 'efcec5e5-7a3b-4f21-8bb8-e6340be44859', NULL, NULL, 'main', true, 4, '19:00', '21:00', 2, '500-800 бат/чел за напитки', 'Насладитесь коктейлями и потрясающим видом на город с одного из самых известных баров на крыше. Придерживайтесь дресс-кода (smart casual).', 'Высоты и рынки выходного дня');
INSERT INTO public.trip_pois VALUES ('2020f3dd-686e-46d1-8b32-3e4d1b7dcd5c', '95888122-36ef-4291-ac26-49ff28fe899a', NULL, NULL, 'additional', false, 4, '10:00', '11:30', 1.5, '400 бат/чел', 'Более бюджетная альтернатива Mahanakhon Skywalk с хорошими видами.', 'Высоты и рынки выходного дня');
INSERT INTO public.trip_pois VALUES ('2020f3dd-686e-46d1-8b32-3e4d1b7dcd5c', '3d5d0d47-7038-4b3d-a421-c3ec7f67064f', NULL, NULL, 'additional', false, 4, '16:00', '17:00', 1, '100 бат/чел', 'Посетите этот впечатляющий храм с золотым Буддой, если у вас есть время после рынка.', 'Высоты и рынки выходного дня');
INSERT INTO public.trip_pois VALUES ('2020f3dd-686e-46d1-8b32-3e4d1b7dcd5c', '6d17e5fb-3ad5-4226-80f4-8e2fec211895', NULL, NULL, 'main', true, 5, '10:00', '12:00', 2, '200 бат/чел', 'Узнайте историю американского предпринимателя, возродившего тайский шелк. Интересный архитектурный комплекс.', 'Культура и современные развлечения');
INSERT INTO public.trip_pois VALUES ('2020f3dd-686e-46d1-8b32-3e4d1b7dcd5c', 'ef187127-1531-46d2-8a76-f5e45fafd73c', NULL, NULL, 'main', true, 5, '13:00', '16:00', 3, '990 бат/чел', 'Один из крупнейших аквариумов в Юго-Восточной Азии. Отличное место для отдыха и знакомства с морской жизнью.', 'Культура и современные развлечения');
INSERT INTO public.trip_pois VALUES ('2020f3dd-686e-46d1-8b32-3e4d1b7dcd5c', 'af119f05-462d-49d9-b282-8ce6940ee3e9', NULL, NULL, 'main', true, 5, '17:00', '20:00', 3, '300-800 бат/чел за еду и шопинг', 'Посетите этот роскошный торговый центр на берегу реки. Насладитесь ужином в фудкорте и посмотрите вечернее шоу фонтанов.', 'Культура и современные развлечения');
INSERT INTO public.trip_pois VALUES ('2020f3dd-686e-46d1-8b32-3e4d1b7dcd5c', '7bb12168-f499-4402-86c8-3d511b51ee3e', NULL, NULL, 'additional', false, 5, '09:00', '11:00', 2, '400 бат/чел', 'Музей с впечатляющей трехголовой статуей слона. Красивое место для фото и культурного погружения.', 'Культура и современные развлечения');
INSERT INTO public.trip_pois VALUES ('2020f3dd-686e-46d1-8b32-3e4d1b7dcd5c', '739c6f9b-1e82-42d1-a760-08316b61f635', NULL, NULL, 'additional', false, 5, '19:00', '21:00', 2, 'зависит от мероприятия', 'Проверьте расписание на предмет традиционных тайских танцев или других культурных представлений. Может быть хорошей альтернативой ночному клубу.', 'Культура и современные развлечения');
INSERT INTO public.trip_pois VALUES ('2020f3dd-686e-46d1-8b32-3e4d1b7dcd5c', '81977b95-b59d-4d5f-ba58-84b676e870ad', NULL, NULL, 'main', true, 6, '10:00', '12:00', 2, '500-1000 бат/чел', 'Насладитесь традиционным тайским массажем после нескольких активных дней. Отличное место для расслабления.', 'Расслабление и бары на крыше');
INSERT INTO public.trip_pois VALUES ('2020f3dd-686e-46d1-8b32-3e4d1b7dcd5c', '18360f22-50bc-4d06-bebe-819f9ddfda6e', NULL, NULL, 'main', true, 6, '16:00', '18:00', 2, '300-600 бат/чел', 'Посетите этот исторический особняк, превращенный в ресторан и бар. Отличная атмосфера для коктейлей перед ужином.', 'Расслабление и бары на крыше');
INSERT INTO public.trip_pois VALUES ('2020f3dd-686e-46d1-8b32-3e4d1b7dcd5c', 'e5126470-9a57-4fb0-9fe7-d6c600abe3ce', NULL, NULL, 'main', true, 6, '19:00', '21:00', 2, '500-1000 бат/чел за напитки', 'Один из самых известных баров на крыше в Бангкоке, известный по фильму ''Мальчишник 2''. Шикарные виды, но цены выше среднего. Дресс-код (smart casual).', 'Расслабление и бары на крыше');
INSERT INTO public.trip_pois VALUES ('2020f3dd-686e-46d1-8b32-3e4d1b7dcd5c', '0142612b-3732-41f3-b33a-7ac2ad81a447', NULL, NULL, 'additional', false, 6, '10:00', '12:00', 2, '700-1500 бат/чел', 'Ещё один вариант для спа-процедур, если ищете альтернативу.', 'Расслабление и бары на крыше');
INSERT INTO public.trip_pois VALUES ('2020f3dd-686e-46d1-8b32-3e4d1b7dcd5c', '8df303ec-a2dc-40eb-8177-6d9f9d58c22a', NULL, NULL, 'additional', false, 6, '19:00', '21:00', 2, '400-800 бат/чел', 'Отличная альтернатива Sky Bar, если хотите более интимную и стильную атмосферу с хорошими коктейлями.', 'Расслабление и бары на крыше');
INSERT INTO public.trip_pois VALUES ('2020f3dd-686e-46d1-8b32-3e4d1b7dcd5c', '075d861b-bfe1-46e2-8012-9b2c3373a479', NULL, NULL, 'main', true, 7, '10:00', '13:00', 3, '0', 'Один из крупнейших и красивейших парков Бангкока. Отличное место для прогулок, пикника или аренды велосипедов.', 'Парки, искусство и живая музыка');
INSERT INTO public.trip_pois VALUES ('2020f3dd-686e-46d1-8b32-3e4d1b7dcd5c', 'c740d36a-67d3-4322-8f7b-c0b836ed1a64', NULL, NULL, 'main', true, 7, '15:00', '17:00', 2, '100-300 бат/чел (за напитки)', 'Посетите эту галерею и бар, чтобы познакомиться с местным современным искусством. Часто проводятся выставки и мероприятия.', 'Парки, искусство и живая музыка');
INSERT INTO public.trip_pois VALUES ('2020f3dd-686e-46d1-8b32-3e4d1b7dcd5c', '2a270e80-48cd-4be8-968d-38ddd6665952', NULL, NULL, 'main', true, 7, '20:00', '23:00', 3, '300-600 бат/чел', 'Бар с хорошей музыкой и расслабляющей атмосферой, часто с живыми выступлениями.', 'Парки, искусство и живая музыка');
INSERT INTO public.trip_pois VALUES ('2020f3dd-686e-46d1-8b32-3e4d1b7dcd5c', '36d222df-65a2-4361-b69e-4dcdf3dbeb4b', NULL, NULL, 'additional', false, 7, '10:00', '12:00', 2, '0', 'Ещё один красивый парк, если хотите сменить обстановку или он ближе к вашему маршруту.', 'Парки, искусство и живая музыка');
INSERT INTO public.trip_pois VALUES ('2020f3dd-686e-46d1-8b32-3e4d1b7dcd5c', '6d896921-f397-4780-aa1e-5a4b3d723ac8', NULL, NULL, 'additional', false, 7, '14:00', '15:30', 1.5, '0', 'Популярная галерея современного искусства, если вы хотите больше погрузиться в арт-сцену Бангкока.', 'Парки, искусство и живая музыка');
INSERT INTO public.trip_pois VALUES ('2020f3dd-686e-46d1-8b32-3e4d1b7dcd5c', '78f3e694-69e2-4da6-b085-57590c1b6342', NULL, NULL, 'main', true, 8, '12:00', '14:00', 2, '1200-1500 бат/чел', 'Уникальный опыт обеда в автобусе, который проезжает мимо достопримечательностей. Бюджет не совсем эконом, но это интересный опыт.', 'Тайская кухня и прогулки по историческому центру');
INSERT INTO public.trip_pois VALUES ('2020f3dd-686e-46d1-8b32-3e4d1b7dcd5c', 'b016e68f-4cd6-454d-bc5c-17de70870a52', NULL, NULL, 'main', true, 8, '14:30', '15:30', 1, '0', 'Историческое место, символизирующее переход Таиланда к конституционной монархии. Рядом можно погулять и почувствовать атмосферу старого Бангкока.', 'Тайская кухня и прогулки по историческому центру');
INSERT INTO public.trip_pois VALUES ('2020f3dd-686e-46d1-8b32-3e4d1b7dcd5c', '31264b80-f1fa-438a-a264-452a0dcb38da', NULL, NULL, 'main', true, 8, '16:00', '18:00', 2, '0', 'Прогуляйтесь по обновленной набережной канала, наслаждаясь стрит-артом и местной жизнью. По вечерам здесь бывает небольшой рынок.', 'Тайская кухня и прогулки по историческому центру');
INSERT INTO public.trip_pois VALUES ('2020f3dd-686e-46d1-8b32-3e4d1b7dcd5c', '7bf4e689-4092-4398-a156-1e697479e77f', NULL, NULL, 'main', true, 8, '19:00', '22:00', 3, '300-600 бат/чел', 'Один из менее туристических ночных рынков, где можно найти уникальные товары и вкусную уличную еду.', 'Тайская кухня и прогулки по историческому центру');
INSERT INTO public.trip_pois VALUES ('2020f3dd-686e-46d1-8b32-3e4d1b7dcd5c', '23f6f656-aee7-4da3-9232-0ac4a6ee91c8', NULL, NULL, 'additional', false, 8, '14:00', '15:30', 1.5, 'зависит от представления', 'Если хотите посмотреть традиционное тайское представление, проверьте расписание театра. Это может быть интересным культурным опытом.', 'Тайская кухня и прогулки по историческому центру');
INSERT INTO public.trip_pois VALUES ('2020f3dd-686e-46d1-8b32-3e4d1b7dcd5c', 'bfddb0f6-f28a-48de-8a34-89809d61c3ea', NULL, NULL, 'additional', false, 8, '15:00', '15:30', 0.5, '0', 'Памятник основателю династии Чакри. Хорошее место для короткой остановки и фото.', 'Тайская кухня и прогулки по историческому центру');
INSERT INTO public.trip_pois VALUES ('2020f3dd-686e-46d1-8b32-3e4d1b7dcd5c', '3901ecb6-9995-4ac6-9407-ac336e84e5c6', NULL, NULL, 'main', true, 9, '10:00', '13:00', 3, '300-800 бат/чел', 'Один из старейших оптовых рынков Бангкока. Отличное место для покупки сувениров и подарков по низким ценам.', 'Последний день шопинга и вечеринок');
INSERT INTO public.trip_pois VALUES ('2020f3dd-686e-46d1-8b32-3e4d1b7dcd5c', 'a1d90adb-cacb-4fc5-8827-4ef860427246', NULL, NULL, 'main', true, 9, '14:00', '16:00', 2, '300-800 бат/чел', 'Еще один крупный рынок, известный своей одеждой. Подойдет для последних покупок перед отъездом.', 'Последний день шопинга и вечеринок');
INSERT INTO public.trip_pois VALUES ('2020f3dd-686e-46d1-8b32-3e4d1b7dcd5c', '83b39e59-3d43-46fe-9462-51d0727c5b82', NULL, NULL, 'main', true, 9, '22:00', '02:00', 4, '300-600 бат/чел', 'Легендарный гей-клуб, известный своей невероятной атмосферой и танцами до утра. Открыт для всех, кто хочет оторваться.', 'Последний день шопинга и вечеринок');
INSERT INTO public.trip_pois VALUES ('2020f3dd-686e-46d1-8b32-3e4d1b7dcd5c', '8d67e487-5872-4e66-8946-4ce1bda0396f', NULL, NULL, 'additional', false, 9, '11:00', '12:00', 1, '200-500 бат/чел', 'Если у вас мало времени, это хороший вариант для покупки последних сувениров в одном месте.', 'Последний день шопинга и вечеринок');
INSERT INTO public.trip_pois VALUES ('2020f3dd-686e-46d1-8b32-3e4d1b7dcd5c', 'fc82aa7e-c3e6-4ddf-a8c0-4c12177cc60d', NULL, NULL, 'additional', false, 9, '19:00', '21:00', 2, '400-700 бат/чел', 'Отличный вариант для ужина перед последней вечеринкой, с хорошим выбором гриль-блюд.', 'Последний день шопинга и вечеринок');
INSERT INTO public.trip_pois VALUES ('2020f3dd-686e-46d1-8b32-3e4d1b7dcd5c', 'cd33a4de-8fbd-4db5-a47b-051175b25e9c', NULL, NULL, 'additional', false, 10, 'Зависит от времени вылета', NULL, 1, '100-200 бат/чел', 'Если у вас есть время перед вылетом, можно зайти в ближайшее кафе, чтобы выпить кофе и перекусить.', 'Вылет');
INSERT INTO public.trip_pois VALUES ('ff5cfb7c-abcb-4cc4-811f-3c3d9f3d5f5e', '3b62206c-42cd-4f81-92e5-c9a2c2414e20', NULL, NULL, 'main', true, 1, '09:00', '12:00', 3, '500 бат/чел', 'Посетите Храм Изумрудного Будды рано утром, чтобы избежать толп и насладиться спокойствием. Оденьтесь скромно (плечи и колени должны быть прикрыты).', 'Величие храмов и речные прогулки');
INSERT INTO public.trip_pois VALUES ('ff5cfb7c-abcb-4cc4-811f-3c3d9f3d5f5e', 'f0ff55ac-1f6f-4db5-b1e3-eadbb5415d79', NULL, NULL, 'main', true, 1, '13:00', '15:00', 2, '100 бат/чел', 'Переправьтесь на пароме через реку Чао Прайя, чтобы полюбоваться Ват Арун. Поднимитесь на центральную пагоду для панорамного вида.', 'Величие храмов и речные прогулки');
INSERT INTO public.trip_pois VALUES ('ff5cfb7c-abcb-4cc4-811f-3c3d9f3d5f5e', 'c29d2f84-36fa-4f00-83d8-fdeb4fd94a44', NULL, NULL, 'main', true, 1, '19:00', '21:30', 2.5, '1500 бат/чел', 'Насладитесь романтическим ужином с видом на реку и вечерние огни Бангкока.', 'Величие храмов и речные прогулки');
INSERT INTO public.trip_pois VALUES ('ff5cfb7c-abcb-4cc4-811f-3c3d9f3d5f5e', '25ba5e8d-5bfd-43fe-92df-6aea51ec9ba1', NULL, NULL, 'additional', false, 1, '16:00', '17:30', 1.5, '0', 'Исторический китайский особняк, превращенный в арт-пространство с магазинами и кафе. Отличное место для прогулки и фотографий.', 'Величие храмов и речные прогулки');
INSERT INTO public.trip_pois VALUES ('ff5cfb7c-abcb-4cc4-811f-3c3d9f3d5f5e', '58796ed2-ef11-43e0-ad36-fc2c0f5ef9f0', NULL, NULL, 'additional', false, 1, '10:30', '11:30', 1, '150 бат/чел', 'Уютное кафе для утреннего кофе или освежающего напитка перед посещением храмов.', 'Величие храмов и речные прогулки');
INSERT INTO public.trip_pois VALUES ('ff5cfb7c-abcb-4cc4-811f-3c3d9f3d5f5e', '03c2855e-4dce-4a9f-bd37-f7c9dd887fd1', NULL, NULL, 'main', true, 2, '09:30', '12:30', 3, '500 бат/чел (еда и сувениры)', 'Погрузитесь в атмосферу плавучего рынка, попробуйте местную еду прямо с лодок и прокатитесь на лодке по каналам.', 'Рынки, еда и традиционный массаж');
INSERT INTO public.trip_pois VALUES ('ff5cfb7c-abcb-4cc4-811f-3c3d9f3d5f5e', '4e58d9be-35a9-44de-a986-2b924edd38ff', NULL, NULL, 'main', true, 2, '14:00', '18:00', 4, '1500 бат/чел', 'Отличный способ познакомиться с местной жизнью на каналах и научиться готовить традиционные тайские блюда.', 'Рынки, еда и традиционный массаж');
INSERT INTO public.trip_pois VALUES ('ff5cfb7c-abcb-4cc4-811f-3c3d9f3d5f5e', '6bb14ccb-c4a2-49f5-b26c-1d6dbafa52aa', NULL, NULL, 'main', true, 2, '19:00', '21:00', 2, '800 бат/чел', 'Расслабьтесь после насыщенного дня с традиционным тайским массажем в уютной атмосфере.', 'Рынки, еда и традиционный массаж');
INSERT INTO public.trip_pois VALUES ('ff5cfb7c-abcb-4cc4-811f-3c3d9f3d5f5e', 'd1a1f328-c93f-46f7-bd73-aa8ea0dcde4f', NULL, NULL, 'additional', false, 2, '17:00', '18:30', 1.5, '800 бат/чел', 'Элегантный ресторан с итальянской кухней и коктейлями, если захочется сменить обстановку после тайской еды.', 'Рынки, еда и традиционный массаж');
INSERT INTO public.trip_pois VALUES ('ff5cfb7c-abcb-4cc4-811f-3c3d9f3d5f5e', '47b706ea-66aa-4c94-9995-644cd6c5027c', NULL, NULL, 'additional', false, 2, '09:00', '11:00', 2, '400 бат/чел', 'Еще один аутентичный плавучий рынок, менее туристический, чем Талинг Чан. Отличное место для наблюдения за местными жителями.', 'Рынки, еда и традиционный массаж');
INSERT INTO public.trip_pois VALUES ('ff5cfb7c-abcb-4cc4-811f-3c3d9f3d5f5e', '6d17e5fb-3ad5-4226-80f4-8e2fec211895', NULL, NULL, 'main', true, 3, '10:00', '12:00', 2, '200 бат/чел', 'Познакомьтесь с историей тайского шелка и архитектурой в этом удивительном доме-музее.', 'Искусство, шопинг и ночная жизнь');
INSERT INTO public.trip_pois VALUES ('ff5cfb7c-abcb-4cc4-811f-3c3d9f3d5f5e', '5cf55bc9-766f-4d10-a514-d3601361b58b', NULL, NULL, 'main', true, 3, '13:00', '16:00', 3, '1000 бат/чел (шопинг)', 'Один из самых известных торговых центров Бангкока, где можно найти все - от электроники до сувениров по разумным ценам. Отличное место для покупки подарков.', 'Искусство, шопинг и ночная жизнь');
INSERT INTO public.trip_pois VALUES ('ff5cfb7c-abcb-4cc4-811f-3c3d9f3d5f5e', '8df303ec-a2dc-40eb-8177-6d9f9d58c22a', NULL, NULL, 'main', true, 3, '20:00', '22:30', 2.5, '800 бат/чел', 'Насладитесь изысканными коктейлями и потрясающим видом на город с крыши.', 'Искусство, шопинг и ночная жизнь');
INSERT INTO public.trip_pois VALUES ('ff5cfb7c-abcb-4cc4-811f-3c3d9f3d5f5e', '6d896921-f397-4780-aa1e-5a4b3d723ac8', NULL, NULL, 'additional', false, 3, '16:30', '17:30', 1, '0', 'Современная художественная галерея, представляющая тайских художников. Идеально для любителей искусства.', 'Искусство, шопинг и ночная жизнь');
INSERT INTO public.trip_pois VALUES ('ff5cfb7c-abcb-4cc4-811f-3c3d9f3d5f5e', 'e75c780a-21f6-48a2-b4ac-5fba9ee0f76a', NULL, NULL, 'additional', false, 3, '22:00', '00:00', 2, '500 бат/чел', 'Исследуйте оживленную ночную жизнь Бангкока, прогулявшись по известным улицам с барами и клубами.', 'Искусство, шопинг и ночная жизнь');
INSERT INTO public.trip_pois VALUES ('ff5cfb7c-abcb-4cc4-811f-3c3d9f3d5f5e', '03bfca58-a9ef-41bb-867a-346c90c093f1', NULL, NULL, 'main', true, 4, '10:00', '12:00', 2, '1000 бат/чел', 'Развлекательное посещение музея восковых фигур, где можно сделать забавные фотографии со знаменитостями.', 'Развлечения и кулинарные открытия');
INSERT INTO public.trip_pois VALUES ('ff5cfb7c-abcb-4cc4-811f-3c3d9f3d5f5e', '5c6fc71a-82a2-45e9-bc6f-4005e78f66d1', NULL, NULL, 'main', true, 4, '18:00', '21:00', 3, '700 бат/чел (еда)', 'Погрузитесь в атмосферу местного ночного рынка с невероятным разнообразием уличной еды. Идеально для ужина.', 'Развлечения и кулинарные открытия');
INSERT INTO public.trip_pois VALUES ('ff5cfb7c-abcb-4cc4-811f-3c3d9f3d5f5e', 'a5218c1d-b614-437f-8131-34674f9c9af9', NULL, NULL, 'main', true, 4, '21:00', '23:00', 2, '1200 бат/чел', 'Элегантный ресторан с полинезийской кухней и живой музыкой, идеальное место для романтического вечера.', 'Развлечения и кулинарные открытия');
INSERT INTO public.trip_pois VALUES ('ff5cfb7c-abcb-4cc4-811f-3c3d9f3d5f5e', '78f3e694-69e2-4da6-b085-57590c1b6342', NULL, NULL, 'additional', false, 4, '14:00', '16:00', 2, '1000 бат/чел', 'Необычный способ познакомиться с городом, наслаждаясь изысканной едой в движущемся автобусе.', 'Развлечения и кулинарные открытия');
INSERT INTO public.trip_pois VALUES ('ff5cfb7c-abcb-4cc4-811f-3c3d9f3d5f5e', '6acc08ac-df4e-42ec-ab6a-c2240a62b0a0', NULL, NULL, 'additional', false, 4, '12:00', '13:30', 1.5, '400 бат/чел', 'Стильное кафе с разнообразным меню, отличное место для обеда или легкого перекуса.', 'Развлечения и кулинарные открытия');
INSERT INTO public.trip_pois VALUES ('ff5cfb7c-abcb-4cc4-811f-3c3d9f3d5f5e', '4b5f0ee6-f210-42a4-9f86-f61aa7c6106c', NULL, NULL, 'main', true, 5, '10:00', '12:00', 2, '200 бат/чел', 'Уникальная возможность познакомиться с различными видами змей и узнать о производстве противоядия. Будьте готовы к необычным впечатлениям.', 'Природа и спа-отдых');
INSERT INTO public.trip_pois VALUES ('ff5cfb7c-abcb-4cc4-811f-3c3d9f3d5f5e', '7e9e3f1d-0ce4-4762-820e-b643769c4357', NULL, NULL, 'main', true, 5, '14:00', '17:00', 3, '2000 бат/чел', 'Побалуйте себя роскошными спа-процедурами в современном спа-центре, расположенном в отеле с прекрасным видом.', 'Природа и спа-отдых');
INSERT INTO public.trip_pois VALUES ('ff5cfb7c-abcb-4cc4-811f-3c3d9f3d5f5e', 'ae66aa4f-910d-4f7a-bf20-7c07243dedba', NULL, NULL, 'main', true, 5, '19:00', '21:30', 2.5, '1200 бат/чел', 'Насладитесь средиземноморской кухней и коктейлями на крыше с панорамным видом на город.', 'Природа и спа-отдых');
INSERT INTO public.trip_pois VALUES ('ff5cfb7c-abcb-4cc4-811f-3c3d9f3d5f5e', '783da607-ae1e-411c-8fb2-3990c8c6c964', NULL, NULL, 'additional', false, 5, '11:00', '12:30', 1.5, '500 бат/чел', 'Более бюджетный, но качественный вариант для традиционного тайского массажа и релакса.', 'Природа и спа-отдых');
INSERT INTO public.trip_pois VALUES ('ff5cfb7c-abcb-4cc4-811f-3c3d9f3d5f5e', '8ffdeffb-7214-4eef-8a98-554e2569d58c', NULL, NULL, 'additional', false, 5, '16:00', '18:00', 2, '1000 бат/чел', 'Еще один отличный спа-салон для расслабления и восстановления сил после активного дня.', 'Природа и спа-отдых');
INSERT INTO public.trip_pois VALUES ('ff5cfb7c-abcb-4cc4-811f-3c3d9f3d5f5e', '83d2a752-c131-4135-bb7d-b15ac343b4eb', NULL, NULL, 'main', true, 6, '09:30', '12:30', 3, '200 бат/чел', 'Один из крупнейших музеев Юго-Восточной Азии, где можно познакомиться с историей и культурой Таиланда.', 'История, искусство и местные рынки');
INSERT INTO public.trip_pois VALUES ('ff5cfb7c-abcb-4cc4-811f-3c3d9f3d5f5e', '56d7ead3-5229-442b-bc8b-15d427671180', NULL, NULL, 'main', true, 6, '14:00', '17:00', 3, '1000 бат/чел (шопинг)', 'Огромный оптовый рынок, где можно найти одежду, аксессуары и сувениры по очень низким ценам. Отличное место для поиска уникальных подарков.', 'История, искусство и местные рынки');
INSERT INTO public.trip_pois VALUES ('ff5cfb7c-abcb-4cc4-811f-3c3d9f3d5f5e', 'f730b824-6c44-4565-b80a-c5dcbfd4245c', NULL, NULL, 'main', true, 6, '19:00', '21:30', 2.5, '1000 бат/чел', 'Шикарный бар на крыше с панорамным видом на город. Отличное место для прощального ужина или коктейлей.', 'История, искусство и местные рынки');
INSERT INTO public.trip_pois VALUES ('ff5cfb7c-abcb-4cc4-811f-3c3d9f3d5f5e', '0d579681-a4fc-4780-a978-155a6be8396f', NULL, NULL, 'additional', false, 6, '17:00', '19:00', 2, '500 бат/чел (еда и шопинг)', 'Продолжение дневного рынка с уличной едой и товарами. Отличная возможность попробовать местные деликатесы.', 'История, искусство и местные рынки');
INSERT INTO public.trip_pois VALUES ('ff5cfb7c-abcb-4cc4-811f-3c3d9f3d5f5e', 'abdab995-bc19-4a55-8022-6df3cd202b67', NULL, NULL, 'additional', false, 6, '12:00', '13:30', 1.5, '0', 'Галерея современного искусства для тех, кто ищет что-то необычное и вдохновляющее.', 'История, искусство и местные рынки');
INSERT INTO public.trip_pois VALUES ('ff5cfb7c-abcb-4cc4-811f-3c3d9f3d5f5e', 'db33d53b-d877-41e2-8487-5d21832d93f5', NULL, NULL, 'main', true, 7, '09:00', '11:00', 2, '0', 'Насладитесь спокойной прогулкой по парку, наблюдая за местными жителями и наслаждаясь зеленью перед отъездом.', 'Отдых и последние впечатления');
INSERT INTO public.trip_pois VALUES ('ff5cfb7c-abcb-4cc4-811f-3c3d9f3d5f5e', 'cca337ba-ee14-4ea5-9acc-851ecd6ec829', NULL, NULL, 'main', true, 7, '11:30', '13:00', 1.5, '300 бат/чел', 'Уютное кафе с отличным кофе и завтраками, идеальное место для последнего бранча в Бангкоке.', 'Отдых и последние впечатления');
INSERT INTO public.trip_pois VALUES ('ff5cfb7c-abcb-4cc4-811f-3c3d9f3d5f5e', 'af119f05-462d-49d9-b282-8ce6940ee3e9', NULL, NULL, 'main', true, 7, '14:00', '17:00', 3, '500 бат/чел (шопинг/еда)', 'Посетите этот роскошный торговый центр на берегу реки, чтобы сделать последние покупки, насладиться видом на город или посмотреть фонтанное шоу.', 'Отдых и последние впечатления');
INSERT INTO public.trip_pois VALUES ('ff5cfb7c-abcb-4cc4-811f-3c3d9f3d5f5e', '8d67e487-5872-4e66-8946-4ce1bda0396f', NULL, NULL, 'additional', false, 7, '12:00', '13:00', 1, '300 бат/чел', 'Место для покупки последних сувениров перед отъездом.', 'Отдых и последние впечатления');
INSERT INTO public.trip_pois VALUES ('ff5cfb7c-abcb-4cc4-811f-3c3d9f3d5f5e', 'cd33a4de-8fbd-4db5-a47b-051175b25e9c', NULL, NULL, 'additional', false, 7, '10:00', '11:00', 1, '150 бат/чел', 'Спокойное место для утреннего кофе и планирования дня.', 'Отдых и последние впечатления');
INSERT INTO public.trip_pois VALUES ('32374cb5-8cf3-44d7-9d1b-3fff0943a59f', 'ac23464e-e425-45fe-aa63-c65c606acc07', NULL, NULL, 'main', true, 1, '14:00', '17:00', 3, '0', 'Начните прогулку по колоритным улицам, насладитесь архитектурой и атмосферой. Отличное место для первых фотографий.', 'Прибытие и знакомство со Старым городом Пхукета');
INSERT INTO public.trip_pois VALUES ('32374cb5-8cf3-44d7-9d1b-3fff0943a59f', 'bfa0f059-47c3-4c93-b0e3-f61b69666343', NULL, NULL, 'main', true, 1, '17:00', '19:00', 2, '0', 'Продолжите исследование исторического центра, обратите внимание на китайско-португальские особняки.', 'Прибытие и знакомство со Старым городом Пхукета');
INSERT INTO public.trip_pois VALUES ('32374cb5-8cf3-44d7-9d1b-3fff0943a59f', '5513a061-0151-4066-9581-462ca52b0eea', NULL, NULL, 'main', true, 1, '19:30', '22:00', 2.5, '30-50 долларов США/чел', 'Ужин в ресторане с прекрасным видом, совмещающим природу и современный дизайн. Забронируйте столик заранее, чтобы получить лучший вид.', 'Прибытие и знакомство со Старым городом Пхукета');
INSERT INTO public.trip_pois VALUES ('32374cb5-8cf3-44d7-9d1b-3fff0943a59f', '3217a3c5-7353-4c91-a9f3-515341eefdb8', NULL, NULL, 'additional', false, 1, '16:00', '17:00', 1, '5-10 долларов США/чел', 'Отличный вариант для перерыва и дегустации местного кофе.', 'Прибытие и знакомство со Старым городом Пхукета');
INSERT INTO public.trip_pois VALUES ('32374cb5-8cf3-44d7-9d1b-3fff0943a59f', 'e6786842-164b-40ff-80cc-f01a608b72f4', NULL, NULL, 'additional', false, 1, '16:30', '17:30', 1, '0', 'Если интересует искусство, загляните в местную галерею.', 'Прибытие и знакомство со Старым городом Пхукета');
INSERT INTO public.trip_pois VALUES ('32374cb5-8cf3-44d7-9d1b-3fff0943a59f', '4763de3b-b4f0-4c05-8b20-236b9d2f15d5', NULL, NULL, 'additional', false, 1, '18:00', '19:30', 1.5, '15-25 долларов США/чел', 'Альтернативный вариант для ужина в неформальной обстановке с бургерами и музыкой.', 'Прибытие и знакомство со Старым городом Пхукета');
INSERT INTO public.trip_pois VALUES ('32374cb5-8cf3-44d7-9d1b-3fff0943a59f', '229da484-15af-4d9b-88bd-5b4ae6e0ac3e', NULL, NULL, 'main', true, 2, '09:00', '11:00', 2, '0 (пожертвования приветствуются)', 'Посетите одну из самых известных достопримечательностей Пхукета с панорамным видом. Одевайтесь скромно.', 'Природные красоты и обзорные точки');
INSERT INTO public.trip_pois VALUES ('32374cb5-8cf3-44d7-9d1b-3fff0943a59f', '68c60df6-d930-46c9-ad77-e2d55b0554bf', NULL, NULL, 'main', true, 2, '11:30', '12:30', 1, '0', 'Остановитесь, чтобы насладиться захватывающим видом на три пляжа: Карон, Ката и Ката Ной.', 'Природные красоты и обзорные точки');
INSERT INTO public.trip_pois VALUES ('32374cb5-8cf3-44d7-9d1b-3fff0943a59f', 'abf37f83-407e-4adf-805d-b8352a219dd0', NULL, NULL, 'main', true, 2, '12:30', '13:00', 0.5, '0', 'Еще одна живописная точка для фото и наслаждения морскими пейзажами.', 'Природные красоты и обзорные точки');
INSERT INTO public.trip_pois VALUES ('32374cb5-8cf3-44d7-9d1b-3fff0943a59f', 'f34400df-b636-475b-a37f-e3719f9f3c77', NULL, NULL, 'main', true, 2, '13:30', '14:00', 0.5, '0', 'Идеальное место для красивых фотографий на закате, но и днем виды впечатляющие.', 'Природные красоты и обзорные точки');
INSERT INTO public.trip_pois VALUES ('32374cb5-8cf3-44d7-9d1b-3fff0943a59f', '21b737be-091e-49d0-9b36-d43b337e13cf', NULL, NULL, 'additional', false, 2, '15:00', '16:30', 1.5, '0', 'Хорошее место для отдыха после обзорных точек, можно просто погулять или отдохнуть на пляже Ката.', 'Природные красоты и обзорные точки');
INSERT INTO public.trip_pois VALUES ('32374cb5-8cf3-44d7-9d1b-3fff0943a59f', 'db303b99-e3d8-4081-aaf0-4766360826fe', NULL, NULL, 'additional', false, 2, '18:00', '20:00', 2, '20-40 долларов США/чел', 'Завершите день коктейлями с видом на закат.', 'Природные красоты и обзорные точки');
INSERT INTO public.trip_pois VALUES ('32374cb5-8cf3-44d7-9d1b-3fff0943a59f', '9035ff06-8fe7-4b49-9b41-45e7e10448bf', NULL, NULL, 'additional', false, 2, '20:00', '22:00', 2, '100-150 долларов США/чел', 'Если ищете уникальный и запоминающийся ужин, это экстремальный, но очень интересный вариант.', 'Природные красоты и обзорные точки');
INSERT INTO public.trip_pois VALUES ('32374cb5-8cf3-44d7-9d1b-3fff0943a59f', 'a2f0c839-3432-4668-90a4-86f2c1452b9d', NULL, NULL, 'main', true, 3, '08:00', '16:00', 8, '70-120 долларов США/чел (за экскурсию)', 'Отправляйтесь на однодневную экскурсию на острова Пхи-Пхи. Это одно из самых красивых мест в Таиланде, обязательно включите плавание с маской и трубкой.', 'Островные приключения: Пхи-Пхи');
INSERT INTO public.trip_pois VALUES ('32374cb5-8cf3-44d7-9d1b-3fff0943a59f', 'affcbc5f-e0cd-4c0a-a88c-d9d9ea6867ff', NULL, NULL, 'additional', false, 3, '07:30', '08:00', 0.5, '0', 'Удобно забронировать тур на острова Пхи-Пхи заранее.', 'Островные приключения: Пхи-Пхи');
INSERT INTO public.trip_pois VALUES ('32374cb5-8cf3-44d7-9d1b-3fff0943a59f', 'c1806a05-203c-4d34-a90c-e07273775c94', NULL, NULL, 'additional', false, 3, '07:30', '08:00', 0.5, '0', 'Еще один вариант для бронирования морских экскурсий.', 'Островные приключения: Пхи-Пхи');
INSERT INTO public.trip_pois VALUES ('32374cb5-8cf3-44d7-9d1b-3fff0943a59f', '7eff965b-493d-47ca-912b-3734738fabf3', NULL, NULL, 'additional', false, 3, '19:00', '21:00', 2, '25-40 долларов США/чел', 'После насыщенного дня на островах, насладитесь вкусным ужином в расслабленной атмосфере.', 'Островные приключения: Пхи-Пхи');
INSERT INTO public.trip_pois VALUES ('32374cb5-8cf3-44d7-9d1b-3fff0943a59f', '0545f52e-467a-4235-a3ac-7b29f69e2d11', NULL, NULL, 'main', true, 4, '14:00', '17:00', 3, '50-100 долларов США/чел (шопинг/еда)', 'Отправьтесь на шопинг в один из крупнейших торговых центров Пхукета. Здесь есть все, от международных брендов до местных сувениров.', 'День релакса и шопинга');
INSERT INTO public.trip_pois VALUES ('32374cb5-8cf3-44d7-9d1b-3fff0943a59f', '9e6dcd55-6317-41dd-b012-02ed430ac18f', NULL, NULL, 'main', true, 4, '17:30', '19:00', 1.5, '20-40 долларов США/чел', 'Расслабьтесь после шопинга с традиционным тайским массажем.', 'День релакса и шопинга');
INSERT INTO public.trip_pois VALUES ('32374cb5-8cf3-44d7-9d1b-3fff0943a59f', '545abe23-e9c2-40c6-b3f5-a1258441e773', NULL, NULL, 'additional', false, 4, '17:30', '19:00', 1.5, '25-50 долларов США/чел', 'Еще один отличный спа-салон для релаксации.', 'День релакса и шопинга');
INSERT INTO public.trip_pois VALUES ('32374cb5-8cf3-44d7-9d1b-3fff0943a59f', '7d136e89-dee5-49eb-a38c-eabfb7d33762', NULL, NULL, 'additional', false, 4, '17:30', '19:00', 1.5, '20-40 долларов США/чел', 'Еще один вариант массажного салона, если вы находитесь ближе к Чалонгу.', 'День релакса и шопинга');
INSERT INTO public.trip_pois VALUES ('32374cb5-8cf3-44d7-9d1b-3fff0943a59f', '4182486e-1df3-4e15-8fd3-46601b738e4f', NULL, NULL, 'additional', false, 4, '19:30', '21:30', 2, '40-70 долларов США/чел', 'Если хотите провести вечер в более романтической обстановке, этот ресторан станет отличным выбором.', 'День релакса и шопинга');
INSERT INTO public.trip_pois VALUES ('32374cb5-8cf3-44d7-9d1b-3fff0943a59f', '20231288-9e95-4ef0-8529-6cdc51978038', NULL, NULL, 'main', true, 5, '09:00', '13:00', 4, '80-120 долларов США/чел', 'Посетите этический заповедник слонов, где вы сможете покормить и искупать слонов, узнав об их жизни. Выбирайте места, где не катают на слонах.', 'Слоны и природа');
INSERT INTO public.trip_pois VALUES ('32374cb5-8cf3-44d7-9d1b-3fff0943a59f', '527fc6e6-9a0d-4053-a099-c35255ff36a8', NULL, NULL, 'main', true, 5, '14:30', '16:00', 1.5, '0', 'Прогуляйтесь по мангровым зарослям, насладитесь природой и свежим воздухом.', 'Слоны и природа');
INSERT INTO public.trip_pois VALUES ('32374cb5-8cf3-44d7-9d1b-3fff0943a59f', '104ae689-dde1-4282-8667-1da3303750c8', NULL, NULL, 'main', true, 5, '16:30', '18:00', 1.5, '10-15 долларов США/чел', 'Интересное место для знакомства с морской фауной Андаманского моря.', 'Слоны и природа');
INSERT INTO public.trip_pois VALUES ('32374cb5-8cf3-44d7-9d1b-3fff0943a59f', 'f108fc6b-d899-4049-bb37-2f0264d092ac', NULL, NULL, 'additional', false, 5, '09:00', '13:00', 4, '80-120 долларов США/чел', 'Другой хороший вариант для этического взаимодействия со слонами.', 'Слоны и природа');
INSERT INTO public.trip_pois VALUES ('32374cb5-8cf3-44d7-9d1b-3fff0943a59f', 'b69a3d1a-574c-41cc-b34b-2675db0a6811', NULL, NULL, 'additional', false, 5, '09:00', '13:00', 4, '80-120 долларов США/чел', 'Еще один этичный заповедник слонов, если первые два варианта недоступны или не подходят по логистике.', 'Слоны и природа');
INSERT INTO public.trip_pois VALUES ('32374cb5-8cf3-44d7-9d1b-3fff0943a59f', '9a318f5c-3f86-4d9e-999a-4ad663cceaa6', NULL, NULL, 'additional', false, 5, '15:00', '17:00', 2, '15-25 долларов США/чел', 'Если интересует орнитология, это место предложит вам знакомство с разнообразными видами птиц.', 'Слоны и природа');
INSERT INTO public.trip_pois VALUES ('32374cb5-8cf3-44d7-9d1b-3fff0943a59f', '6538d257-dfd9-4849-858d-5e394be0a41c', NULL, NULL, 'main', true, 6, '08:00', '17:00', 9, '100-150 долларов США/чел (за экскурсию)', 'Отправьтесь на экскурсию к островам Ко Рок и Ко Ха. Это идеальное место для снорклинга и дайвинга с кристально чистой водой и богатым подводным миром. Забронируйте тур заранее.', 'Острова Ко Рок и Ко Ха: снорклинг и дайвинг');
INSERT INTO public.trip_pois VALUES ('32374cb5-8cf3-44d7-9d1b-3fff0943a59f', '5e358d09-d7dd-43f8-ae64-2c680ccf1034', NULL, NULL, 'additional', false, 6, '07:30', '08:00', 0.5, '0', 'Хороший вариант для поиска и бронирования морских экскурсий.', 'Острова Ко Рок и Ко Ха: снорклинг и дайвинг');
INSERT INTO public.trip_pois VALUES ('32374cb5-8cf3-44d7-9d1b-3fff0943a59f', 'b8ae4f2f-5076-40f3-9ca9-c32a483fc82e', NULL, NULL, 'additional', false, 6, '07:30', '08:00', 0.5, '0', 'Еще одно агентство для организации экскурсий.', 'Острова Ко Рок и Ко Ха: снорклинг и дайвинг');
INSERT INTO public.trip_pois VALUES ('32374cb5-8cf3-44d7-9d1b-3fff0943a59f', 'fa425946-0601-45b1-8d27-c751cf64abea', NULL, NULL, 'additional', false, 6, '07:30', '08:00', 0.5, '0', 'Если вы находитесь в районе Ката, это удобное место для бронирования туров.', 'Острова Ко Рок и Ко Ха: снорклинг и дайвинг');
INSERT INTO public.trip_pois VALUES ('32374cb5-8cf3-44d7-9d1b-3fff0943a59f', '5e17f7c3-35d3-490d-b324-6a9aa76bed79', NULL, NULL, 'main', true, 7, '10:00', '14:00', 4, '80-120 долларов США/чел', 'Погрузитесь в мир тайской кухни, посетив кулинарный класс. Вы научитесь готовить традиционные блюда, которые потом сможете приготовить дома.', 'Кулинария и вечерние развлечения');
INSERT INTO public.trip_pois VALUES ('32374cb5-8cf3-44d7-9d1b-3fff0943a59f', 'e19fe977-6ddd-4173-98fe-8ea9b5ba4e6a', NULL, NULL, 'main', true, 7, '16:00', '18:00', 2, '10-30 долларов США/чел', 'Исследуйте местный рынок, попробуйте уличную еду и купите свежие фрукты. Отличное место для знакомства с местной жизнью.', 'Кулинария и вечерние развлечения');
INSERT INTO public.trip_pois VALUES ('32374cb5-8cf3-44d7-9d1b-3fff0943a59f', 'f73f7d8a-db3b-4488-b958-c5e0f4e989be', NULL, NULL, 'main', true, 7, '22:00', '01:00', 3, '30-60 долларов США/чел', 'Если хотите потанцевать и насладиться ночной жизнью, это один из популярных клубов на Пхукете.', 'Кулинария и вечерние развлечения');
INSERT INTO public.trip_pois VALUES ('32374cb5-8cf3-44d7-9d1b-3fff0943a59f', '0f8197a5-1b67-442a-b044-78e7dc545e9f', NULL, NULL, 'additional', false, 7, '21:00', '23:00', 2, '20-40 долларов США/чел', 'Если ищете бар для начала вечера, это хороший вариант.', 'Кулинария и вечерние развлечения');
INSERT INTO public.trip_pois VALUES ('32374cb5-8cf3-44d7-9d1b-3fff0943a59f', 'c3299b61-f262-4cab-ace5-8325afbbd083', NULL, NULL, 'additional', false, 7, '18:00', '20:00', 2, '10-30 долларов США/чел', 'Отличный вариант для ужина с местной едой и поиска сувениров, если вы находитесь ближе к Карону.', 'Кулинария и вечерние развлечения');
INSERT INTO public.trip_pois VALUES ('32374cb5-8cf3-44d7-9d1b-3fff0943a59f', '049936a2-84fb-4f4f-9517-4535dc1a07bd', NULL, NULL, 'additional', false, 7, '22:00', '01:00', 3, '30-60 долларов США/чел', 'Еще один популярный ночной клуб для любителей вечеринок.', 'Кулинария и вечерние развлечения');
INSERT INTO public.trip_pois VALUES ('32374cb5-8cf3-44d7-9d1b-3fff0943a59f', '22b3a542-0176-4b47-bdf2-a152fa66ad9e', NULL, NULL, 'main', true, 8, '09:30', '11:00', 1.5, '0 (пожертвования приветствуются)', 'Посетите один из самых старых и важных китайских храмов на Пхукете. Погрузитесь в атмосферу местной культуры.', 'Культура и искусство');
INSERT INTO public.trip_pois VALUES ('32374cb5-8cf3-44d7-9d1b-3fff0943a59f', 'fa1f5ca8-3efd-4ff7-a2ba-cebcde5b807e', NULL, NULL, 'main', true, 8, '11:30', '12:30', 1, '0 (пожертвования приветствуются)', 'Еще один интересный храм, известный своей наполовину закопанной статуей Будды.', 'Культура и искусство');
INSERT INTO public.trip_pois VALUES ('32374cb5-8cf3-44d7-9d1b-3fff0943a59f', '490a00cd-63f8-4c13-afb3-632b199bb285', NULL, NULL, 'main', true, 8, '14:00', '16:00', 2, '15-20 долларов США/чел', 'Забавное интерактивное место, где можно сделать много креативных фотографий.', 'Культура и искусство');
INSERT INTO public.trip_pois VALUES ('32374cb5-8cf3-44d7-9d1b-3fff0943a59f', '0a1ef2c3-db18-4397-a32c-61a040325d0f', NULL, NULL, 'main', true, 8, '16:30', '17:30', 1, '0', 'Если интересует современное искусство, загляните в эту галерею.', 'Культура и искусство');
INSERT INTO public.trip_pois VALUES ('32374cb5-8cf3-44d7-9d1b-3fff0943a59f', '74d532be-4e80-4246-a86e-f18ec8ea3ec0', NULL, NULL, 'additional', false, 8, '10:00', '11:00', 1, '0', 'Интересное место для знакомства с местными традициями и, возможно, приобретения уникальных сувениров.', 'Культура и искусство');
INSERT INTO public.trip_pois VALUES ('32374cb5-8cf3-44d7-9d1b-3fff0943a59f', 'fe138f36-7064-471c-ba51-f0d0bd85f700', NULL, NULL, 'additional', false, 8, '15:00', '16:30', 1.5, '0', 'Еще одна галерея, где можно посмотреть работы местных художников.', 'Культура и искусство');
INSERT INTO public.trip_pois VALUES ('32374cb5-8cf3-44d7-9d1b-3fff0943a59f', '4eea191b-9531-4fea-9121-36e5d68261b9', NULL, NULL, 'additional', false, 8, '15:00', '16:30', 1.5, '5-10 долларов США/чел', 'Если хотите узнать больше об истории Пхукета, посетите этот музей.', 'Культура и искусство');
INSERT INTO public.trip_pois VALUES ('32374cb5-8cf3-44d7-9d1b-3fff0943a59f', 'baad8011-b534-430b-a44d-940b62d338e1', NULL, NULL, 'main', true, 9, '10:00', '14:00', 4, '10-20 долларов США/чел (вход/трансфер)', 'Отправляйтесь на уединенный пляж Нуи. Это отличное место для плавания, загара и наслаждения природой вдали от толп. Дорога может быть сложной, рассмотрите вариант с арендой джипа или мотобайка.', 'Пляжный отдых и закат');
INSERT INTO public.trip_pois VALUES ('32374cb5-8cf3-44d7-9d1b-3fff0943a59f', '1e169000-8e21-41dd-85ec-361e5ccdd763', NULL, NULL, 'main', true, 9, '17:00', '20:00', 3, '40-70 долларов США/чел', 'Насладитесь коктейлями и ужином в стильном пляжном клубе, наблюдая за закатом. Отличная атмосфера и музыка.', 'Пляжный отдых и закат');
INSERT INTO public.trip_pois VALUES ('32374cb5-8cf3-44d7-9d1b-3fff0943a59f', 'f40aadac-a55b-4917-8487-b766cb3da0d2', NULL, NULL, 'additional', false, 9, '16:00', '16:30', 0.5, '0', 'Если вы оказались в районе Патонга, это хорошая точка для быстрого обзора.', 'Пляжный отдых и закат');
INSERT INTO public.trip_pois VALUES ('32374cb5-8cf3-44d7-9d1b-3fff0943a59f', 'a4ae73bd-2318-43c3-a290-439712dbde41', NULL, NULL, 'additional', false, 9, '18:00', '20:30', 2.5, '30-60 долларов США/чел', 'Альтернативный вариант для коктейлей и ужина с видом на море.', 'Пляжный отдых и закат');
INSERT INTO public.trip_pois VALUES ('32374cb5-8cf3-44d7-9d1b-3fff0943a59f', '00b7c8ea-ca16-4996-b6dd-dcedb4fe0ca0', NULL, NULL, 'additional', false, 9, '20:30', '22:30', 2, '20-40 долларов США/чел', 'Если захочется продолжить вечер в Старом городе, это хороший бар с живой музыкой.', 'Пляжный отдых и закат');
INSERT INTO public.trip_pois VALUES ('32374cb5-8cf3-44d7-9d1b-3fff0943a59f', 'ffdedf26-e037-4eb9-a7d9-569d74244800', NULL, NULL, 'main', true, 10, '10:00', '12:00', 2, '10-30 долларов США/чел', 'Если ваш последний день выпадает на воскресенье, обязательно посетите этот рынок. Он предлагает огромное разнообразие еды, сувениров и развлечений.', 'Прощание с Пхукетом: сувениры и последние впечатления');
INSERT INTO public.trip_pois VALUES ('32374cb5-8cf3-44d7-9d1b-3fff0943a59f', 'f7906995-a561-4238-9b89-c27af23b5475', NULL, NULL, 'main', true, 10, '12:30', '14:00', 1.5, '20-50 долларов США/чел', 'Последний шанс купить сувениры для друзей и семьи.', 'Прощание с Пхукетом: сувениры и последние впечатления');
INSERT INTO public.trip_pois VALUES ('32374cb5-8cf3-44d7-9d1b-3fff0943a59f', 'af234583-a867-4b7c-9ed1-41fc0232096b', NULL, NULL, 'main', true, 10, '14:30', '16:00', 1.5, '0 (покупка по желанию)', 'Посетите галерею драгоценных камней, чтобы посмотреть на местные ювелирные изделия. Покупки не обязательны.', 'Прощание с Пхукетом: сувениры и последние впечатления');
INSERT INTO public.trip_pois VALUES ('32374cb5-8cf3-44d7-9d1b-3fff0943a59f', 'a82a5e0f-116c-49e0-9d7e-1ddb39d5211b', NULL, NULL, 'additional', false, 10, '11:00', '12:30', 1.5, '10-30 долларов США/чел', 'Еще один рынок, где можно найти сувениры и подарки.', 'Прощание с Пхукетом: сувениры и последние впечатления');
INSERT INTO public.trip_pois VALUES ('32374cb5-8cf3-44d7-9d1b-3fff0943a59f', '6db51fcd-0c7e-42e7-ad74-bb2cfb50ac05', NULL, NULL, 'additional', false, 10, '13:00', '14:30', 1.5, '20-40 долларов США/чел', 'Вкусный обед перед отъездом.', 'Прощание с Пхукетом: сувениры и последние впечатления');
INSERT INTO public.trip_pois VALUES ('32374cb5-8cf3-44d7-9d1b-3fff0943a59f', '604a0863-b36f-4f47-87da-8cd867e56148', NULL, NULL, 'additional', false, 10, '13:00', '14:30', 1.5, '15-30 долларов США/чел', 'Если захочется чего-то знакомого, это хороший вариант для обеда.', 'Прощание с Пхукетом: сувениры и последние впечатления');
INSERT INTO public.trip_pois VALUES ('619c33ff-1cbe-433f-8955-8cdb9ddee9f4', '4305f4a3-ae1a-4ab2-a080-7e7be833fd53', NULL, NULL, 'additional', false, 1, '11:00', '12:00', 1, '0', 'Прекрасное место для неспешной прогулки и отдыха на свежем воздухе, если вы захотите отвлечься от музеев.', 'Историческое погружение и вечерняя атмосфера');
INSERT INTO public.trip_pois VALUES ('619c33ff-1cbe-433f-8955-8cdb9ddee9f4', 'f2df7da1-6948-48dd-b81b-f9760300d435', NULL, NULL, 'additional', false, 1, '16:30', '17:30', 1, '300-1000 руб./чел. (сувениры)', 'Если вы ищете уникальные сувениры, это место предлагает изделия из янтаря и другие ремесленные товары. Хороший вариант для подарков.', 'Историческое погружение и вечерняя атмосфера');
INSERT INTO public.trip_pois VALUES ('619c33ff-1cbe-433f-8955-8cdb9ddee9f4', '1d2d883d-e98d-40e0-9e70-205ebab25251', NULL, NULL, 'additional', false, 1, '21:30', '23:30', 2, '500-1000 руб./чел. (напитки)', 'Популярный бар для тех, кто хочет продолжить вечер в более оживленной атмосфере. Отлично подойдет для завершения дня.', 'Историческое погружение и вечерняя атмосфера');
INSERT INTO public.trip_pois VALUES ('619c33ff-1cbe-433f-8955-8cdb9ddee9f4', '5190711e-20f1-4e2e-822a-c12348900cbe', NULL, NULL, 'main', true, 2, '10:00', '13:00', 3, '300-500 руб./чел.', 'Один из старейших зоопарков России, с красивой территорией. Отличное место для неспешной прогулки и отдыха.', 'Природа, искусство и вечерние развлечения');
INSERT INTO public.trip_pois VALUES ('619c33ff-1cbe-433f-8955-8cdb9ddee9f4', '1162bf4e-7e8e-48c0-8ec9-19b9e8b38506', NULL, NULL, 'main', true, 2, '13:30', '15:30', 2, '150-250 руб./чел.', 'Прекрасное место для любителей природы, чтобы расслабиться и насладиться красотой растений. Отлично подходит для уединения.', 'Природа, искусство и вечерние развлечения');
INSERT INTO public.trip_pois VALUES ('619c33ff-1cbe-433f-8955-8cdb9ddee9f4', '2cd9ca02-23f1-466a-8816-87e7c36aa90f', NULL, NULL, 'main', true, 2, '16:00', '18:00', 2, '200-300 руб./чел.', 'Позволит глубже понять историю и культуру региона. Интересные экспозиции для любителей истории.', 'Природа, искусство и вечерние развлечения');
INSERT INTO public.trip_pois VALUES ('619c33ff-1cbe-433f-8955-8cdb9ddee9f4', '2f9eae80-a01f-43cc-92be-b04c86dcc7b3', NULL, NULL, 'main', true, 2, '20:00', '23:00', 3, '700-1500 руб./чел. (ужин и напитки)', 'Популярный паб с хорошим выбором напитков и еды. Отличное место для вечернего отдыха и общения в неформальной обстановке.', 'Природа, искусство и вечерние развлечения');
INSERT INTO public.trip_pois VALUES ('619c33ff-1cbe-433f-8955-8cdb9ddee9f4', 'b0c7696c-5da1-431b-ab6c-e457044835b0', NULL, NULL, 'additional', false, 2, '12:00', '13:30', 1.5, '0-200 руб./чел. (аттракционы)', 'Если захочется более активного отдыха, в парке есть аттракционы и кафе. Хорошая альтернатива зоопарку или после него.', 'Природа, искусство и вечерние развлечения');
INSERT INTO public.trip_pois VALUES ('619c33ff-1cbe-433f-8955-8cdb9ddee9f4', '68e90d17-3d91-460d-97ce-25f92570bbce', NULL, NULL, 'additional', false, 2, '15:00', '16:00', 1, '300-500 руб./чел. (кофе/десерт)', 'Уютное кафе, где можно перекусить или выпить кофе после прогулки по парку или перед музеем.', 'Природа, искусство и вечерние развлечения');
INSERT INTO public.trip_pois VALUES ('619c33ff-1cbe-433f-8955-8cdb9ddee9f4', '93e49795-7340-4cc8-84fa-35d208cebafa', NULL, NULL, 'additional', false, 2, '22:00', '01:00', 3, '500-1500 руб./чел. (вход/напитки)', 'Для тех, кто ищет более энергичное завершение вечера, ночной клуб предложит музыку и танцы.', 'Природа, искусство и вечерние развлечения');
INSERT INTO public.trip_pois VALUES ('619c33ff-1cbe-433f-8955-8cdb9ddee9f4', '50ba1e15-b883-4b32-a3ac-358c0db98547', NULL, NULL, 'main', true, 3, '10:00', '13:00', 3, '400-600 руб./чел. (комплексный билет)', 'Обязательный к посещению музей с уникальными экспонатами, включая подводную лодку. Позволит окунуться в морскую историю.', 'Морские приключения и архитектурные сокровища');
INSERT INTO public.trip_pois VALUES ('619c33ff-1cbe-433f-8955-8cdb9ddee9f4', 'fe28176d-e754-4fd8-8554-133d82ab075d', NULL, NULL, 'main', true, 3, '13:30', '15:00', 1.5, 'Включено в билет Музея Мирового океана', 'Часть Музея Мирового океана. Уникальная возможность побывать внутри настоящей подводной лодки и почувствовать себя моряком.', 'Морские приключения и архитектурные сокровища');
INSERT INTO public.trip_pois VALUES ('619c33ff-1cbe-433f-8955-8cdb9ddee9f4', 'e43d9a56-9706-4c2c-825a-07e790ce8602', NULL, NULL, 'main', true, 3, '19:00', '21:00', 2, '700-1500 руб./чел. (ужин)', 'Ресторан с приятной атмосферой и хорошей кухней для завершающего ужина в Калининграде. Позволит насладиться последним вечером.', 'Морские приключения и архитектурные сокровища');
INSERT INTO public.trip_pois VALUES ('619c33ff-1cbe-433f-8955-8cdb9ddee9f4', 'c72fffaa-071b-4cec-93ed-a6bf86aec9f0', NULL, NULL, 'additional', false, 3, '12:00', '13:00', 1, '0', 'Рядом с Музеем Мирового океана. Если вы увлечены морской тематикой, это место может предложить дополнительные интересные объекты.', 'Морские приключения и архитектурные сокровища');
INSERT INTO public.trip_pois VALUES ('619c33ff-1cbe-433f-8955-8cdb9ddee9f4', 'b472d372-bc67-4de3-8421-77031cb8244a', NULL, NULL, 'additional', false, 3, '17:00', '18:00', 1, '0', 'Красивая архитектура, которая может быть интересна для любителей истории и фотографии. Находится недалеко от Фридландских ворот.', 'Морские приключения и архитектурные сокровища');
INSERT INTO public.trip_pois VALUES ('619c33ff-1cbe-433f-8955-8cdb9ddee9f4', '6a99e430-064b-44d1-bda8-a3aeba90ed67', NULL, NULL, 'additional', false, 3, '21:30', '23:30', 2, '500-1000 руб./чел. (напитки)', 'Для тех, кто хочет завершить поездку в неформальной обстановке с хорошей музыкой и напитками.', 'Морские приключения и архитектурные сокровища');
INSERT INTO public.trip_pois VALUES ('619c33ff-1cbe-433f-8955-8cdb9ddee9f4', '0b77b4f5-c15d-40a2-bbb0-ea00494d5c5a', 1, NULL, 'main', true, 1, '10:00', '12:00', 2, '200 руб./чел. (вход в музей Канта)', 'Обязательно посетите Музей Канта внутри собора и прогуляйтесь по острову, чтобы насладиться архитектурой и атмосферой.', 'Историческое погружение и вечерняя атмосфера');
INSERT INTO public.trip_pois VALUES ('619c33ff-1cbe-433f-8955-8cdb9ddee9f4', '9ce15b9b-fdb6-4866-bf3e-77a73b6046fb', 2, NULL, 'main', true, 1, '12:30', '14:00', 1.5, '0', 'Музей расположен внутри Собора, поэтому его удобно совместить с посещением Собора. Позволит глубже погрузиться в историю философа.', 'Историческое погружение и вечерняя атмосфера');
INSERT INTO public.trip_pois VALUES ('619c33ff-1cbe-433f-8955-8cdb9ddee9f4', 'bacab44f-a5c6-4435-9796-7dc4d593f4e2', 4, NULL, 'main', true, 1, '19:00', '21:30', 2.5, '700-1500 руб./чел. (ужин)', 'Отличное место для ужина с приятной атмосферой. Позволит расслабиться после насыщенного дня.', 'Историческое погружение и вечерняя атмосфера');
INSERT INTO public.trip_pois VALUES ('619c33ff-1cbe-433f-8955-8cdb9ddee9f4', 'c669db64-48a5-4e25-8057-37bdb06515c5', 3, NULL, 'main', true, 1, '14:30', '16:30', 2, '500-1000 руб./чел. (обед)', 'Идеальное место для обеда с видом на Преголю. Попробуйте местную рыбу и прогуляйтесь по набережной.', 'Историческое погружение и вечерняя атмосфера');
INSERT INTO public.trip_pois VALUES ('54d9610b-1f88-4ec2-95a9-baa0d016e6b4', '97bdb441-f6a2-4f17-acb6-a145969f7968', NULL, NULL, 'main', true, 1, '09:00', '12:00', 3, '500 THB/чел', 'Наденьте скромную одежду, закрывающую плечи и колени. Приходите пораньше, чтобы избежать толп и жары.', 'Культурное погружение и уличная еда');
INSERT INTO public.trip_pois VALUES ('54d9610b-1f88-4ec2-95a9-baa0d016e6b4', '3b62206c-42cd-4f81-92e5-c9a2c2414e20', NULL, NULL, 'main', true, 1, '12:00', '13:30', 1.5, 'Включено в билет The Grand Palace', 'Храм Изумрудного Будды находится на территории Королевского дворца. Соблюдайте тишину и уважение.', 'Культурное погружение и уличная еда');
INSERT INTO public.trip_pois VALUES ('54d9610b-1f88-4ec2-95a9-baa0d016e6b4', '0cef74e8-74b3-4d43-81dc-5dc4571002dc', NULL, NULL, 'main', true, 1, '18:00', '22:00', 4, '500-1000 THB/чел', 'Идеальное место для ужина с уличной едой, покупки сувениров и погружения в атмосферу ночной жизни Бангкока.', 'Культурное погружение и уличная еда');
INSERT INTO public.trip_pois VALUES ('54d9610b-1f88-4ec2-95a9-baa0d016e6b4', '0c5a03fe-68a6-4780-ad10-46805ffe69d8', NULL, NULL, 'main', true, 1, '19:30', '21:00', 1.5, '300-500 THB/чел', 'Отличное место, чтобы попробовать настоящий тайский карри после прогулки по Каосан Роуд.', 'Культурное погружение и уличная еда');
INSERT INTO public.trip_pois VALUES ('54d9610b-1f88-4ec2-95a9-baa0d016e6b4', 'e96de9a3-dd9b-41b5-acf4-7936e723a08a', NULL, NULL, 'additional', false, 1, '15:00', '16:30', 1.5, '50 THB/чел', 'Поднимитесь на Золотую Гору за панорамными видами Бангкока, это недалеко от Королевского дворца.', 'Культурное погружение и уличная еда');
INSERT INTO public.trip_pois VALUES ('54d9610b-1f88-4ec2-95a9-baa0d016e6b4', '4771b037-44ec-4322-b5bc-4f674f5729b6', NULL, NULL, 'additional', false, 1, '16:30', '17:30', 1, '0', 'Спокойный парк для отдыха после осмотра достопримечательностей, расположенный рядом с дворцом.', 'Культурное погружение и уличная еда');
INSERT INTO public.trip_pois VALUES ('54d9610b-1f88-4ec2-95a9-baa0d016e6b4', 'dd5ac82b-04d9-4cb3-bfdd-14a9f8a72c26', NULL, NULL, 'additional', false, 1, '17:30', '18:30', 1, '150-250 THB/чел', 'Уютное кафе в старом городе, чтобы выпить кофе или перекусить перед вечерней прогулкой.', 'Культурное погружение и уличная еда');
INSERT INTO public.trip_pois VALUES ('54d9610b-1f88-4ec2-95a9-baa0d016e6b4', 'ca6cc99a-f0aa-464b-806f-9ff13073c1ac', NULL, NULL, 'main', true, 2, '10:00', '14:00', 4, '1000-3000 THB/чел (зависит от покупок)', 'Работает только в выходные. Готовьтесь к толпам, торгуйтесь и исследуйте множество уникальных товаров и еды.', 'Рынки и шопинг');
INSERT INTO public.trip_pois VALUES ('54d9610b-1f88-4ec2-95a9-baa0d016e6b4', '03c2855e-4dce-4a9f-bd37-f7c9dd887fd1', NULL, NULL, 'main', true, 2, '14:30', '17:00', 2.5, '500-800 THB/чел', 'Небольшой, но аутентичный плавучий рынок, где можно попробовать свежие морепродукты и местные деликатесы прямо с лодок.', 'Рынки и шопинг');
INSERT INTO public.trip_pois VALUES ('54d9610b-1f88-4ec2-95a9-baa0d016e6b4', 'c79cd7ee-3b43-4494-890b-9026fa33c1e1', NULL, NULL, 'main', true, 2, '18:00', '20:00', 2, '1000-5000 THB/чел (зависит от покупок)', 'Один из крупнейших торговых центров Бангкока. Здесь можно найти как люксовые бренды, так и отличные рестораны.', 'Рынки и шопинг');
INSERT INTO public.trip_pois VALUES ('54d9610b-1f88-4ec2-95a9-baa0d016e6b4', '9f1b423e-2e52-42e6-8774-0b99e791dbca', NULL, NULL, 'main', true, 2, '22:00', '01:00', 3, '800-1500 THB/чел', 'Уникальный ночной клуб с азиатской тематикой, отличной музыкой и атмосферой. Отличный выбор для активной ночи.', 'Рынки и шопинг');
INSERT INTO public.trip_pois VALUES ('54d9610b-1f88-4ec2-95a9-baa0d016e6b4', '5cf55bc9-766f-4d10-a514-d3601361b58b', NULL, NULL, 'additional', false, 2, '16:00', '17:30', 1.5, '500-2000 THB/чел', 'Хорошая альтернатива Siam Paragon для более бюджетных покупок, особенно электроники и сувениров.', 'Рынки и шопинг');
INSERT INTO public.trip_pois VALUES ('54d9610b-1f88-4ec2-95a9-baa0d016e6b4', '0d579681-a4fc-4780-a978-155a6be8396f', NULL, NULL, 'additional', false, 2, '19:00', '21:00', 2, '300-800 THB/чел', 'Оживленный ночной рынок, отличный для покупки одежды и аксессуаров по низким ценам.', 'Рынки и шопинг');
INSERT INTO public.trip_pois VALUES ('54d9610b-1f88-4ec2-95a9-baa0d016e6b4', '156f7b1e-9763-4ea6-a0d5-a940b65ca4bf', NULL, NULL, 'additional', false, 2, '23:00', '02:00', 3, '500-1000 THB/чел', 'Если вы любите электронную музыку, это андеграундный клуб, который стоит посетить после Синг Синг.', 'Рынки и шопинг');
INSERT INTO public.trip_pois VALUES ('54d9610b-1f88-4ec2-95a9-baa0d016e6b4', '326c336e-11a9-488c-a9db-7cc3903a757b', NULL, NULL, 'main', true, 3, '10:30', '12:00', 1.5, '0', 'Современная художественная галерея, предлагающая интересные экспозиции. Отличное место для любителей искусства.', 'Искусство, спа и панорамные виды');
INSERT INTO public.trip_pois VALUES ('54d9610b-1f88-4ec2-95a9-baa0d016e6b4', 'a2f8dcf6-e5fa-4c6f-87e7-19e829d5e094', NULL, NULL, 'main', true, 3, '13:00', '15:00', 2, '2000-4000 THB/чел', 'Роскошный спа-салон для полного расслабления и восстановления сил после активных дней.', 'Искусство, спа и панорамные виды');
INSERT INTO public.trip_pois VALUES ('54d9610b-1f88-4ec2-95a9-baa0d016e6b4', 'e5126470-9a57-4fb0-9fe7-d6c600abe3ce', NULL, NULL, 'main', true, 3, '18:00', '20:00', 2, '800-1500 THB/чел', 'Знаменитый бар на крыше с потрясающими видами на город. Приходите до заката, чтобы насладиться сменой дня и ночи.', 'Искусство, спа и панорамные виды');
INSERT INTO public.trip_pois VALUES ('54d9610b-1f88-4ec2-95a9-baa0d016e6b4', '3a2c0944-49d3-438d-9f04-c69348cfbfd8', NULL, NULL, 'main', true, 3, '20:00', '22:00', 2, '1500-2500 THB/чел', 'Изысканный ресторан с международной кухней, идеально подходящий для романтического ужина после Sky Bar.', 'Искусство, спа и панорамные виды');
INSERT INTO public.trip_pois VALUES ('54d9610b-1f88-4ec2-95a9-baa0d016e6b4', '617a803c-da99-4204-8803-15b55e7ffb70', NULL, NULL, 'additional', false, 3, '10:00', '11:30', 1.5, '0-200 THB/чел', 'Еще одна галерея современного искусства, если вы хотите продолжить культурное утро.', 'Искусство, спа и панорамные виды');
INSERT INTO public.trip_pois VALUES ('54d9610b-1f88-4ec2-95a9-baa0d016e6b4', '5b102e41-9ba6-4969-a981-2410d325c617', NULL, NULL, 'additional', false, 3, '14:00', '15:30', 1.5, '1000-2000 THB/чел', 'Отличная альтернатива Amaranth Spa, предлагающая традиционный тайский массаж.', 'Искусство, спа и панорамные виды');
INSERT INTO public.trip_pois VALUES ('54d9610b-1f88-4ec2-95a9-baa0d016e6b4', '4b0f2937-9905-4b40-89fb-981758656520', NULL, NULL, 'additional', false, 3, '19:00', '20:30', 1.5, '500-1000 THB/чел', 'Еще один прекрасный бар на крыше с отличной атмосферой и видами, если Sky Bar слишком переполнен.', 'Искусство, спа и панорамные виды');
INSERT INTO public.trip_pois VALUES ('54d9610b-1f88-4ec2-95a9-baa0d016e6b4', '6d17e5fb-3ad5-4226-80f4-8e2fec211895', NULL, NULL, 'main', true, 4, '10:00', '12:00', 2, '200 THB/чел', 'Узнайте историю американского предпринимателя, возродившего тайский шелк. Обязательно возьмите экскурсию.', 'Музеи и развлечения');
INSERT INTO public.trip_pois VALUES ('54d9610b-1f88-4ec2-95a9-baa0d016e6b4', '9aca702e-18cb-460e-b2d6-8cb18b3dc820', NULL, NULL, 'main', true, 4, '13:00', '15:30', 2.5, '1000-1200 THB/чел', 'Крупнейший аквариум в Юго-Восточной Азии, идеально подходит для жаркого дня. Купите билеты онлайн, чтобы сэкономить.', 'Музеи и развлечения');
INSERT INTO public.trip_pois VALUES ('54d9610b-1f88-4ec2-95a9-baa0d016e6b4', '3bcd6047-e548-48ba-a897-7054a4971ae1', NULL, NULL, 'main', true, 4, '19:00', '22:00', 3, '1500-2000 THB/чел (шоу + ужин)', 'Грандиозное культурное шоу, рассказывающее историю Таиланда. Рекомендуется забронировать билеты заранее, особенно с ужином.', 'Музеи и развлечения');
INSERT INTO public.trip_pois VALUES ('54d9610b-1f88-4ec2-95a9-baa0d016e6b4', '98f9ac48-3ae4-4b22-a7c6-bd46771e4e5e', NULL, NULL, 'main', true, 4, '18:00', '19:30', 1.5, '500-1000 THB/чел', 'Если вы хотите поужинать перед шоу, этот ресторан предлагает разнообразные блюда в оживленной атмосфере Asiatique.', 'Музеи и развлечения');
INSERT INTO public.trip_pois VALUES ('54d9610b-1f88-4ec2-95a9-baa0d016e6b4', '03bfca58-a9ef-41bb-867a-346c90c093f1', NULL, NULL, 'additional', false, 4, '11:00', '12:30', 1.5, '800-1000 THB/чел', 'Классический музей восковых фигур, расположенный недалеко от Siam Paragon.', 'Музеи и развлечения');
INSERT INTO public.trip_pois VALUES ('54d9610b-1f88-4ec2-95a9-baa0d016e6b4', '7bb12168-f499-4402-86c8-3d511b51ee3e', NULL, NULL, 'additional', false, 4, '15:00', '17:00', 2, '400 THB/чел', 'Уникальный музей с гигантской трехголовой статуей слона, предлагающий красивые фотозоны.', 'Музеи и развлечения');
INSERT INTO public.trip_pois VALUES ('54d9610b-1f88-4ec2-95a9-baa0d016e6b4', '612a8a9e-bdce-4e62-8b0e-1cf1dc7e0976', NULL, NULL, 'additional', false, 4, '21:30', '23:00', 1.5, '1200-1500 THB/чел', 'Еще одно знаменитое кабаре-шоу трансвеститов, если вы ищете вечернее развлечение после Сиам Нирамит или как альтернативу.', 'Музеи и развлечения');
INSERT INTO public.trip_pois VALUES ('54d9610b-1f88-4ec2-95a9-baa0d016e6b4', '1e99da6d-8b45-4055-8174-9ef69d029756', NULL, NULL, 'main', true, 5, '09:30', '10:30', 1, '150-250 THB/чел', 'Культовая кофейня в районе Талат Ной, известная своим уникальным кофе и атмосферой старого Бангкока.', 'Кулинарные открытия и отдых у реки');
INSERT INTO public.trip_pois VALUES ('54d9610b-1f88-4ec2-95a9-baa0d016e6b4', 'a43ba5bc-00f0-4acd-9a5f-9ec699ee1cbf', NULL, NULL, 'main', true, 5, '12:00', '13:30', 1.5, '500-800 THB/чел', 'Ресторан с видом на реку Чао Прайя, предлагающий изысканные тайские блюда. Отличное место для обеда.', 'Кулинарные открытия и отдых у реки');
INSERT INTO public.trip_pois VALUES ('54d9610b-1f88-4ec2-95a9-baa0d016e6b4', 'e93bb2d1-7e09-40ab-ad1d-8b9e260d18e6', NULL, NULL, 'main', true, 5, '18:00', '20:30', 2.5, '1500-3000 THB/чел', 'Уникальный опыт ужина на борту старинного корабля, пришвартованного на реке. Бронируйте заранее.', 'Кулинарные открытия и отдых у реки');
INSERT INTO public.trip_pois VALUES ('54d9610b-1f88-4ec2-95a9-baa0d016e6b4', 'ae66aa4f-910d-4f7a-bf20-7c07243dedba', NULL, NULL, 'main', true, 5, '21:00', '23:00', 2, '800-1500 THB/чел', 'Стильный бар на крыше с средиземноморской кухней и коктейлями, отличный для завершения вечера.', 'Кулинарные открытия и отдых у реки');
INSERT INTO public.trip_pois VALUES ('54d9610b-1f88-4ec2-95a9-baa0d016e6b4', '8dd431ed-6824-460d-9526-cd9d4893ecae', NULL, NULL, 'additional', false, 5, '10:00', '11:00', 1, '100-200 THB/чел', 'Еще одна уютная кофейня для утреннего кофе в этом районе.', 'Кулинарные открытия и отдых у реки');
INSERT INTO public.trip_pois VALUES ('f50f8aa9-3d59-438f-ab92-78b348b1d8f5', '67893c65-569f-4867-a48f-c4dc6cb808bd', NULL, NULL, 'additional', false, 3, '10:30', '12:00', 1.5, '15 USD/чел', 'Если захочется перекусить или купить свежие морепродукты, рынок Хэундэ — отличное место.', 'Хэундэ: Пляж, Море и Развлечения');
INSERT INTO public.trip_pois VALUES ('54d9610b-1f88-4ec2-95a9-baa0d016e6b4', 'a5218c1d-b614-437f-8131-34674f9c9af9', NULL, NULL, 'additional', false, 5, '19:00', '21:00', 2, '1000-2000 THB/чел', 'Ресторан полинезийской кухни с живой музыкой, отличный вариант для ужина у реки, если Sirimahannop занят.', 'Кулинарные открытия и отдых у реки');
INSERT INTO public.trip_pois VALUES ('54d9610b-1f88-4ec2-95a9-baa0d016e6b4', '352d337d-b59e-4520-b327-b751c749eb1c', NULL, NULL, 'additional', false, 5, '19:00', '21:00', 2, '1000-1500 THB/чел', 'Шведский стол с морепродуктами на берегу реки, если вы предпочитаете более непринужденную атмосферу.', 'Кулинарные открытия и отдых у реки');
INSERT INTO public.trip_pois VALUES ('54d9610b-1f88-4ec2-95a9-baa0d016e6b4', '8a541ed9-929f-4e2f-90f5-1940fcaa08ab', NULL, NULL, 'main', true, 6, '10:00', '15:00', 5, '1000-1200 THB/чел', 'Парк развлечений с аттракционами для всех возрастов. Расположен за пределами центра, поэтому запланируйте время на дорогу.', 'Активный отдых и ночная жизнь');
INSERT INTO public.trip_pois VALUES ('54d9610b-1f88-4ec2-95a9-baa0d016e6b4', '95888122-36ef-4291-ac26-49ff28fe899a', NULL, NULL, 'main', true, 6, '17:00', '18:30', 1.5, '400 THB/чел', 'Насладитесь панорамными видами Бангкока с самой высокой смотровой площадки. Отличное место для фотографий на закате.', 'Активный отдых и ночная жизнь');
INSERT INTO public.trip_pois VALUES ('54d9610b-1f88-4ec2-95a9-baa0d016e6b4', '389d54d6-8b62-45bc-96d6-e6b3b730e46b', NULL, NULL, 'main', true, 6, '21:00', '23:30', 2.5, '500-1000 THB/чел', 'Веселый и энергичный бар с драг-шоу. Отличное место для незабываемого вечера.', 'Активный отдых и ночная жизнь');
INSERT INTO public.trip_pois VALUES ('54d9610b-1f88-4ec2-95a9-baa0d016e6b4', 'cc5eacfc-1952-4473-b7d0-31c877d3c538', NULL, NULL, 'main', true, 6, '19:00', '21:00', 2, '300-800 THB/чел', 'Один из самых известных ночных рынков Бангкока, известный своим разнообразием товаров и оживленной атмосферой.', 'Активный отдых и ночная жизнь');
INSERT INTO public.trip_pois VALUES ('54d9610b-1f88-4ec2-95a9-baa0d016e6b4', 'b78ad908-7275-4018-b598-512e93491b42', NULL, NULL, 'additional', false, 6, '14:00', '15:00', 1, '1000-1500 THB/чел', 'Если вы ищете еще больше приключений, попробуйте симулятор свободного падения.', 'Активный отдых и ночная жизнь');
INSERT INTO public.trip_pois VALUES ('54d9610b-1f88-4ec2-95a9-baa0d016e6b4', '7bf4e689-4092-4398-a156-1e697479e77f', NULL, NULL, 'additional', false, 6, '18:00', '20:00', 2, '300-800 THB/чел', 'Менее туристический ночной рынок, где можно найти уникальные товары и местную еду.', 'Активный отдых и ночная жизнь');
INSERT INTO public.trip_pois VALUES ('54d9610b-1f88-4ec2-95a9-baa0d016e6b4', '9a0b2de2-411a-4c64-8fad-f406a042530b', NULL, NULL, 'additional', false, 6, '22:00', '01:00', 3, '500-1000 THB/чел', 'Популярный ночной клуб в районе Каосан Роуд, если вы хотите продолжить вечеринку.', 'Активный отдых и ночная жизнь');
INSERT INTO public.trip_pois VALUES ('54d9610b-1f88-4ec2-95a9-baa0d016e6b4', 'ac46e989-b935-4d5f-9ba4-28004edf6a29', NULL, NULL, 'main', true, 7, '10:00', '12:00', 2, '2500-5000 THB/чел', 'Премиальный спа-салон для полного расслабления перед отъездом. Бронируйте заранее.', 'Релакс и последние покупки');
INSERT INTO public.trip_pois VALUES ('54d9610b-1f88-4ec2-95a9-baa0d016e6b4', 'da910cce-60e0-4082-a899-a14a9231ce76', NULL, NULL, 'main', true, 7, '13:00', '14:30', 1.5, '500-1500 THB/чел', 'Место для покупки последних сувениров и подарков.', 'Релакс и последние покупки');
INSERT INTO public.trip_pois VALUES ('54d9610b-1f88-4ec2-95a9-baa0d016e6b4', '78f3e694-69e2-4da6-b085-57590c1b6342', NULL, NULL, 'main', true, 7, '18:00', '20:00', 2, '1500-2000 THB/чел', 'Уникальный опыт ужина в двухэтажном автобусе, проезжающем мимо достопримечательностей Бангкока. Отличный способ увидеть город в последний раз.', 'Релакс и последние покупки');
INSERT INTO public.trip_pois VALUES ('54d9610b-1f88-4ec2-95a9-baa0d016e6b4', '8df303ec-a2dc-40eb-8177-6d9f9d58c22a', NULL, NULL, 'main', true, 7, '20:30', '22:30', 2, '800-1500 THB/чел', 'Стильный бар на крыше в стиле спикизи, идеальный для прощальных коктейлей.', 'Релакс и последние покупки');
INSERT INTO public.trip_pois VALUES ('54d9610b-1f88-4ec2-95a9-baa0d016e6b4', '81977b95-b59d-4d5f-ba58-84b676e870ad', NULL, NULL, 'additional', false, 7, '11:00', '12:30', 1.5, '1500-3000 THB/чел', 'Еще один отличный спа-салон с видом на реку, если вы хотите совместить релакс с красивыми видами.', 'Релакс и последние покупки');
INSERT INTO public.trip_pois VALUES ('54d9610b-1f88-4ec2-95a9-baa0d016e6b4', 'a4f7cf1d-e93e-48dd-8f85-ab740b6adcb8', NULL, NULL, 'additional', false, 7, '14:00', '15:00', 1, '500-2000 THB/чел', 'Магазин, специализирующийся на тайских ремесленных изделиях и дизайнерских товарах. Отличное место для уникальных подарков.', 'Релакс и последние покупки');
INSERT INTO public.trip_pois VALUES ('54d9610b-1f88-4ec2-95a9-baa0d016e6b4', 'e5633c99-abab-4e91-a056-073f90cbedf0', NULL, NULL, 'additional', false, 7, '21:00', '22:30', 1.5, '400-800 THB/чел', 'Уютный пивной бар, где можно расслабиться и обсудить впечатления от поездки.', 'Релакс и последние покупки');
INSERT INTO public.trip_pois VALUES ('072e09c6-b681-4e53-9960-797ca6e7f1b3', 'bfa0f059-47c3-4c93-b0e3-f61b69666343', NULL, NULL, 'main', true, 1, '10:00', '13:00', 3, '0', 'Прогуляйтесь по ярким улицам, наслаждаясь архитектурой и атмосферой. Обязательно загляните в сувенирные лавки.', 'Исследование Старого города и гастрономические открытия');
INSERT INTO public.trip_pois VALUES ('072e09c6-b681-4e53-9960-797ca6e7f1b3', '0c51043e-1149-477c-906b-e514eb3af256', NULL, NULL, 'main', true, 1, '13:30', '14:30', 1, '0', 'Посетите этот красивый китайский храм, чтобы окунуться в местную культуру и сделать красивые фотографии.', 'Исследование Старого города и гастрономические открытия');
INSERT INTO public.trip_pois VALUES ('072e09c6-b681-4e53-9960-797ca6e7f1b3', 'e19fe977-6ddd-4173-98fe-8ea9b5ba4e6a', NULL, NULL, 'main', true, 1, '17:00', '19:00', 2, '500 THB/чел', 'Отличное место для знакомства с местной кухней. Попробуйте свежие морепродукты и экзотические фрукты. Ужин.', 'Исследование Старого города и гастрономические открытия');
INSERT INTO public.trip_pois VALUES ('072e09c6-b681-4e53-9960-797ca6e7f1b3', 'b76be6d1-1ddc-4a33-8cf3-930324b6c011', NULL, NULL, 'main', true, 1, '21:00', '00:00', 3, '800 THB/чел', 'Завершите день в уютном баре в Старом городе, наслаждаясь напитками и живой музыкой.', 'Исследование Старого города и гастрономические открытия');
INSERT INTO public.trip_pois VALUES ('072e09c6-b681-4e53-9960-797ca6e7f1b3', '890c5a97-b5c7-4625-beb6-15173c5034b7', NULL, NULL, 'additional', false, 1, '11:30', '12:30', 1, '0', 'Если интересует современное искусство, эта галерея предлагает интересные экспозиции.', 'Исследование Старого города и гастрономические открытия');
INSERT INTO public.trip_pois VALUES ('072e09c6-b681-4e53-9960-797ca6e7f1b3', '7df9264b-d6e8-4d0e-a81d-bfe62226b415', NULL, NULL, 'additional', false, 1, '18:00', '20:00', 2, '700 THB/чел', 'Отличный вариант для ужина с более изысканной кухней, если хочется разнообразия после рынка.', 'Исследование Старого города и гастрономические открытия');
INSERT INTO public.trip_pois VALUES ('072e09c6-b681-4e53-9960-797ca6e7f1b3', 'a970a48d-4e7a-49bc-b5a7-afdceaf725ef', NULL, NULL, 'additional', false, 1, '20:00', '22:00', 2, '500 THB/чел', 'Еще один вариант для вечернего времяпровождения с едой и напитками в центре города.', 'Исследование Старого города и гастрономические открытия');
INSERT INTO public.trip_pois VALUES ('072e09c6-b681-4e53-9960-797ca6e7f1b3', 'e1120c88-f6fa-4cf8-ad24-2ad682940458', NULL, NULL, 'additional', false, 1, '10:30', '11:30', 1, '200 THB/чел', 'Уютное кафе для утреннего кофе или легкого перекуса в Старом городе.', 'Исследование Старого города и гастрономические открытия');
INSERT INTO public.trip_pois VALUES ('072e09c6-b681-4e53-9960-797ca6e7f1b3', 'f108fc6b-d899-4049-bb37-2f0264d092ac', NULL, NULL, 'main', true, 2, '09:00', '13:00', 4, '3000 THB/чел', 'Посетите заповедник слонов, где вы сможете покормить и пообщаться со слонами в этичной среде. Бронируйте заранее.', 'Природа, слоны и закаты');
INSERT INTO public.trip_pois VALUES ('072e09c6-b681-4e53-9960-797ca6e7f1b3', '84ed9e4f-d5b2-4364-a8a1-58f117f77bbc', NULL, NULL, 'main', true, 2, '14:30', '16:00', 1.5, '0', 'Поднимитесь на холм, чтобы насладиться панорамными видами и встретить диких обезьян. Будьте осторожны с личными вещами.', 'Природа, слоны и закаты');
INSERT INTO public.trip_pois VALUES ('072e09c6-b681-4e53-9960-797ca6e7f1b3', 'b59166c3-db3e-40e0-abf6-12c4bb10432d', NULL, NULL, 'main', true, 2, '17:30', '19:30', 2, '0', 'Обязательное место для наблюдения за одним из самых красивых закатов на Пхукете. Приезжайте пораньше, чтобы занять хорошее место.', 'Природа, слоны и закаты');
INSERT INTO public.trip_pois VALUES ('072e09c6-b681-4e53-9960-797ca6e7f1b3', '7eff965b-493d-47ca-912b-3734738fabf3', NULL, NULL, 'main', true, 2, '20:00', '22:00', 2, '700 THB/чел', 'Популярное место для ужина с вкусными ребрышками и живой атмосферой.', 'Природа, слоны и закаты');
INSERT INTO public.trip_pois VALUES ('072e09c6-b681-4e53-9960-797ca6e7f1b3', '20231288-9e95-4ef0-8529-6cdc51978038', NULL, NULL, 'additional', false, 2, '09:00', '13:00', 4, '3000 THB/чел', 'Альтернативный заповедник слонов, если первый вариант недоступен или вы ищете другое место.', 'Природа, слоны и закаты');
INSERT INTO public.trip_pois VALUES ('072e09c6-b681-4e53-9960-797ca6e7f1b3', 'ef31aa05-792a-466c-b6a9-5d4b2de1399d', NULL, NULL, 'additional', false, 2, '15:00', '16:00', 1, '0', 'Если хочется немного физической активности, можно прогуляться по этому парку после Monkey Hill.', 'Природа, слоны и закаты');
INSERT INTO public.trip_pois VALUES ('072e09c6-b681-4e53-9960-797ca6e7f1b3', '68c60df6-d930-46c9-ad77-e2d55b0554bf', NULL, NULL, 'additional', false, 2, '16:00', '17:00', 1, '0', 'Еще одна живописная смотровая площадка с видами на три пляжа (Карон, Ката, Ката Ной).', 'Природа, слоны и закаты');
INSERT INTO public.trip_pois VALUES ('072e09c6-b681-4e53-9960-797ca6e7f1b3', '4182486e-1df3-4e15-8fd3-46601b738e4f', NULL, NULL, 'additional', false, 2, '20:00', '22:00', 2, '1000 THB/чел', 'Если ищете более романтическую атмосферу для ужина после заката.', 'Природа, слоны и закаты');
INSERT INTO public.trip_pois VALUES ('072e09c6-b681-4e53-9960-797ca6e7f1b3', '31ccb6e5-e9d7-420c-8893-f63bc0cba3ac', NULL, NULL, 'main', true, 3, '10:00', '14:00', 4, '0', 'Проведите утро, наслаждаясь солнцем и морем на одном из самых красивых пляжей Пхукета. Можно взять в аренду лежаки и зонтики.', 'Пляжный отдых и вечерние развлечения');
INSERT INTO public.trip_pois VALUES ('072e09c6-b681-4e53-9960-797ca6e7f1b3', 'c485b265-fc3c-4be8-8e50-4a21c5de36b0', NULL, NULL, 'main', true, 3, '14:30', '17:30', 3, '200 THB/чел (за лодку)', 'Добраться можно на лодке с пляжа Патонг или Карон. Это более уединенный и живописный пляж.', 'Пляжный отдых и вечерние развлечения');
INSERT INTO public.trip_pois VALUES ('072e09c6-b681-4e53-9960-797ca6e7f1b3', '21b737be-091e-49d0-9b36-d43b337e13cf', NULL, NULL, 'additional', false, 3, '11:00', '12:00', 1, '0', 'Небольшой парк рядом с пляжем Ката, где можно отдохнуть в тени.', 'Пляжный отдых и вечерние развлечения');
INSERT INTO public.trip_pois VALUES ('072e09c6-b681-4e53-9960-797ca6e7f1b3', 'baad8011-b534-430b-a44d-940b62d338e1', NULL, NULL, 'additional', false, 3, '15:00', '17:00', 2, '200 THB/чел (за вход и дорогу)', 'Еще один уединенный пляж, до которого добираться сложнее, но он компенсирует это своей красотой.', 'Пляжный отдых и вечерние развлечения');
INSERT INTO public.trip_pois VALUES ('072e09c6-b681-4e53-9960-797ca6e7f1b3', 'd71ace14-2ca2-49c8-be35-87a89cc43871', NULL, NULL, 'additional', false, 3, '22:00', '00:00', 2, '800 THB/чел', 'Альтернативный бар для ночного отдыха с хорошей музыкой и атмосферой.', 'Пляжный отдых и вечерние развлечения');
INSERT INTO public.trip_pois VALUES ('072e09c6-b681-4e53-9960-797ca6e7f1b3', '455bed37-ac42-4008-be8e-9535099352b2', NULL, NULL, 'additional', false, 3, '22:30', '01:00', 2.5, '1000 THB/чел', 'Еще один вариант ночного клуба для любителей танцев и вечеринок.', 'Пляжный отдых и вечерние развлечения');
INSERT INTO public.trip_pois VALUES ('072e09c6-b681-4e53-9960-797ca6e7f1b3', '310f52f2-b43d-4278-9b4f-197510539f44', NULL, NULL, 'main', true, 4, '09:30', '11:30', 2, '0 (пожертвования приветствуются)', 'Посетите самый важный и красивый храм на Пхукете. Уважайте местные обычаи и одевайтесь скромно.', 'Культурное наследие и кулинарные изыски');
INSERT INTO public.trip_pois VALUES ('072e09c6-b681-4e53-9960-797ca6e7f1b3', '652a1288-91f2-4131-9511-93307a1ebc30', NULL, NULL, 'main', true, 4, '12:00', '13:30', 1.5, '0', 'Еще один интересный храм с большой статуей лежащего Будды. Отличное место для фото.', 'Культурное наследие и кулинарные изыски');
INSERT INTO public.trip_pois VALUES ('072e09c6-b681-4e53-9960-797ca6e7f1b3', '5e17f7c3-35d3-490d-b324-6a9aa76bed79', NULL, NULL, 'main', true, 4, '15:00', '18:00', 3, '2500 THB/чел', 'Пройдите кулинарный мастер-класс и научитесь готовить традиционные тайские блюда, а затем насладитесь ими на ужин. Бронируйте заранее.', 'Культурное наследие и кулинарные изыски');
INSERT INTO public.trip_pois VALUES ('072e09c6-b681-4e53-9960-797ca6e7f1b3', '672c970e-7fd4-4138-abdb-1d4aa9574e30', NULL, NULL, 'main', true, 4, '20:00', '22:00', 2, '600 THB/чел', 'Завершите день дегустацией местного крафтового пива. Отличная атмосфера и уникальные вкусы.', 'Культурное наследие и кулинарные изыски');
INSERT INTO public.trip_pois VALUES ('072e09c6-b681-4e53-9960-797ca6e7f1b3', '2b6a74a0-9498-4bd4-9f86-16f793c33bae', NULL, NULL, 'additional', false, 3, '22:00', '01:00', 3, '1500 THB/чел', 'Для тех, кто ищет активную ночную жизнь, этот клуб предлагает танцы и развлечения до утра.', 'Пляжный отдых и вечерние развлечения');
INSERT INTO public.trip_pois VALUES ('072e09c6-b681-4e53-9960-797ca6e7f1b3', '22b3a542-0176-4b47-bdf2-a152fa66ad9e', NULL, NULL, 'additional', false, 4, '10:30', '11:30', 1, '0', 'Еще один китайский храм, известный своими красочными фестивалями. Стоит посетить, если есть время.', 'Культурное наследие и кулинарные изыски');
INSERT INTO public.trip_pois VALUES ('072e09c6-b681-4e53-9960-797ca6e7f1b3', 'fa1f5ca8-3efd-4ff7-a2ba-cebcde5b807e', NULL, NULL, 'additional', false, 4, '13:00', '14:00', 1, '0', 'Храм с наполовину закопанной статуей Будды. Интересная легенда и спокойная атмосфера.', 'Культурное наследие и кулинарные изыски');
INSERT INTO public.trip_pois VALUES ('072e09c6-b681-4e53-9960-797ca6e7f1b3', '0545f52e-467a-4235-a3ac-7b29f69e2d11', NULL, NULL, 'additional', false, 4, '18:00', '20:00', 2, '500 THB/чел', 'Если захочется более современного ужина или шопинга, Central Phuket предлагает множество ресторанов и магазинов.', 'Культурное наследие и кулинарные изыски');
INSERT INTO public.trip_pois VALUES ('072e09c6-b681-4e53-9960-797ca6e7f1b3', '03e1a5ea-e1b4-4a9c-81bc-ae56fe96171d', NULL, NULL, 'additional', false, 4, '20:30', '22:30', 2, '700 THB/чел', 'Паб с хорошим выбором напитков и закусок, если хочется более расслабленной обстановки.', 'Культурное наследие и кулинарные изыски');
INSERT INTO public.trip_pois VALUES ('072e09c6-b681-4e53-9960-797ca6e7f1b3', '8f33fe2e-b709-48a1-a9b3-265651539b1f', NULL, NULL, 'main', true, 5, '09:00', '12:00', 3, '1500 THB/чел', 'Отправьтесь в приключение на квадроциклах по бездорожью, наслаждаясь видами по пути к Большому Будде.', 'Активный отдых и панорамные виды');
INSERT INTO public.trip_pois VALUES ('072e09c6-b681-4e53-9960-797ca6e7f1b3', 'e5a75350-3895-4477-9930-ce19b751ce99', NULL, NULL, 'main', true, 5, '13:00', '14:30', 1.5, '0', 'Смотровая площадка с потрясающими видами на город Пхукет и близлежащие острова. Есть рестораны с панорамным видом.', 'Активный отдых и панорамные виды');
INSERT INTO public.trip_pois VALUES ('072e09c6-b681-4e53-9960-797ca6e7f1b3', '2c233431-10c2-448f-b0ca-d3b36e023cd2', NULL, NULL, 'main', true, 5, '15:00', '17:00', 2, '0', 'Еще одна живописная смотровая площадка, менее известная, но предлагающая захватывающие виды.', 'Активный отдых и панорамные виды');
INSERT INTO public.trip_pois VALUES ('072e09c6-b681-4e53-9960-797ca6e7f1b3', 'b4f45af1-c69d-4de0-bf5b-e8ba16e3d2be', NULL, NULL, 'main', true, 5, '19:00', '22:00', 3, '600 THB/чел', 'Погрузитесь в атмосферу ночного рынка с уличной едой, сувенирами и развлечениями. Ужин.', 'Активный отдых и панорамные виды');
INSERT INTO public.trip_pois VALUES ('072e09c6-b681-4e53-9960-797ca6e7f1b3', '702a7e40-2958-4610-aa97-a9af4fa00e58', NULL, NULL, 'additional', false, 5, '13:30', '14:30', 1, '0', 'То же место, что и Khao Rang, но с акцентом на парк для прогулок.', 'Активный отдых и панорамные виды');
INSERT INTO public.trip_pois VALUES ('072e09c6-b681-4e53-9960-797ca6e7f1b3', '84159053-a926-4c90-b281-54356ee6af42', NULL, NULL, 'additional', false, 5, '14:00', '15:00', 1, '0', 'Еще одна смотровая башня для панорамных видов, если вы любите высоту.', 'Активный отдых и панорамные виды');
INSERT INTO public.trip_pois VALUES ('072e09c6-b681-4e53-9960-797ca6e7f1b3', '05c31595-5dd3-4728-8501-374605675d44', NULL, NULL, 'additional', false, 5, '15:30', '16:30', 1, '0', 'Еще одна из многочисленных смотровых площадок, предлагающая уникальные ракурсы.', 'Активный отдых и панорамные виды');
INSERT INTO public.trip_pois VALUES ('072e09c6-b681-4e53-9960-797ca6e7f1b3', '0a33fb84-a91c-4bed-a953-b00f8b9db6fe', NULL, NULL, 'additional', false, 5, '19:30', '22:00', 2.5, '500 THB/чел', 'Альтернативный ночной рынок, если вы хотите исследовать другие районы и вкусы.', 'Активный отдых и панорамные виды');
INSERT INTO public.trip_pois VALUES ('072e09c6-b681-4e53-9960-797ca6e7f1b3', '54939325-175f-416b-a9a9-95dabfc70298', NULL, NULL, 'main', true, 6, '10:00', '13:00', 3, '1200 THB/чел', 'Посетите крупнейший аквариум Таиланда, чтобы увидеть разнообразный морской мир. Отличное место для всех возрастов.', 'Развлечения и шоу');
INSERT INTO public.trip_pois VALUES ('072e09c6-b681-4e53-9960-797ca6e7f1b3', '95d45a44-b02b-456b-8c39-76ecd7e4a05d', NULL, NULL, 'main', true, 6, '14:00', '16:00', 2, '1000 THB/чел', 'Уникальная возможность близко познакомиться с тиграми. Выбирайте пакет, который соответствует вашим предпочтениям.', 'Развлечения и шоу');
INSERT INTO public.trip_pois VALUES ('072e09c6-b681-4e53-9960-797ca6e7f1b3', '1571c260-feae-486e-894b-cd9a18a8dc13', NULL, NULL, 'main', true, 6, '18:00', '22:00', 4, '2000 THB/чел (с ужином)', 'Культурное шоу с элементами магии, акробатики и традиционных танцев. Включает ужин ''шведский стол''. Бронируйте заранее.', 'Развлечения и шоу');
INSERT INTO public.trip_pois VALUES ('072e09c6-b681-4e53-9960-797ca6e7f1b3', '0f8197a5-1b67-442a-b044-78e7dc545e9f', NULL, NULL, 'main', true, 6, '22:30', '00:30', 2, '800 THB/чел', 'Завершите вечер в одном из ночных баров, наслаждаясь напитками и музыкой.', 'Развлечения и шоу');
INSERT INTO public.trip_pois VALUES ('072e09c6-b681-4e53-9960-797ca6e7f1b3', '9a318f5c-3f86-4d9e-999a-4ad663cceaa6', NULL, NULL, 'additional', false, 6, '10:30', '12:30', 2, '500 THB/чел', 'Если вы любите птиц, этот парк предлагает интересные шоу и возможность увидеть множество видов.', 'Развлечения и шоу');
INSERT INTO public.trip_pois VALUES ('072e09c6-b681-4e53-9960-797ca6e7f1b3', '5f9e83f6-9b53-41ac-8a3b-52ad6c720a5e', NULL, NULL, 'additional', false, 6, '14:30', '16:00', 1.5, '300 THB/чел', 'Небольшой зоопарк с домашними животными, идеально подходит для расслабленного времяпровождения.', 'Развлечения и шоу');
INSERT INTO public.trip_pois VALUES ('072e09c6-b681-4e53-9960-797ca6e7f1b3', '2c053102-6c19-498d-a9b5-f842a1c64a95', NULL, NULL, 'additional', false, 6, '18:30', '22:00', 3.5, '1800 THB/чел (с ужином)', 'Альтернативное культурное шоу, предлагающее масштабное представление истории и культуры Таиланда.', 'Развлечения и шоу');
INSERT INTO public.trip_pois VALUES ('072e09c6-b681-4e53-9960-797ca6e7f1b3', '917ee817-fb66-43ed-8a72-20127c94413f', NULL, NULL, 'additional', false, 6, '22:00', '00:00', 2, '1000 THB/чел', 'Для любителей караоке, это место предлагает приватные комнаты и большой выбор песен.', 'Развлечения и шоу');
INSERT INTO public.trip_pois VALUES ('072e09c6-b681-4e53-9960-797ca6e7f1b3', '62b065d8-3474-4318-ad7f-39cff36e6a56', NULL, NULL, 'main', true, 7, '10:00', '13:00', 3, '300 THB/чел', 'Посетите один из крупнейших рынков Пхукета, чтобы купить сувениры, одежду и попробовать уличную еду. Работает по выходным, уточняйте расписание.', 'Отдых, шопинг и прощальный ужин');
INSERT INTO public.trip_pois VALUES ('072e09c6-b681-4e53-9960-797ca6e7f1b3', 'cdec4643-87df-43fd-9d64-5a14fdf8c799', NULL, NULL, 'main', true, 7, '13:30', '15:00', 1.5, '200 THB/чел', 'Еще один рынок, где можно найти свежие продукты и местные деликатесы. Отлично подходит для легкого обеда.', 'Отдых, шопинг и прощальный ужин');
