INSERT INTO public.trip_pois VALUES ('f50f8aa9-3d59-438f-ab92-78b348b1d8f5', '7935a00d-f63a-43d0-9224-f2f64aeddfd1', NULL, NULL, 'additional', false, 6, '22:00', '00:00', 2, '35 USD/чел', 'Если ищете более изысканный бар с коктейлями, Chess 154 будет отличным выбором.', 'Активный Отдых и Панорамные Виды');
INSERT INTO public.trip_pois VALUES ('f50f8aa9-3d59-438f-ab92-78b348b1d8f5', '2b4a0ca1-8754-4a33-b0fb-d43694bf8de3', NULL, NULL, 'additional', false, 6, '20:00', '22:00', 2, '30 USD/чел', 'Пивоварня с хорошим выбором пива и закусок, если предпочитаете более спокойный вечер.', 'Активный Отдых и Панорамные Виды');
INSERT INTO public.trip_pois VALUES ('f50f8aa9-3d59-438f-ab92-78b348b1d8f5', '78460896-17b1-4f37-8264-3ec3b929c7c1', NULL, NULL, 'main', true, 7, '10:00', '11:30', 1.5, '8 USD/чел', 'Насладитесь последними панорамными видами на город с высоты.', 'Прощание с Пусаном: Городские Виды и Отдых');
INSERT INTO public.trip_pois VALUES ('f50f8aa9-3d59-438f-ab92-78b348b1d8f5', '599ad551-e155-4c46-a765-13789850928a', NULL, NULL, 'main', true, 7, '12:00', '13:30', 1.5, '0', 'Поднимитесь по исторической лестнице и исследуйте окрестности, можно воспользоваться монорельсом.', 'Прощание с Пусаном: Городские Виды и Отдых');
INSERT INTO public.trip_pois VALUES ('f50f8aa9-3d59-438f-ab92-78b348b1d8f5', '0a2933d4-5b0e-4879-94fc-8f313c296db6', NULL, NULL, 'main', true, 7, '14:00', '15:30', 1.5, '10 USD/чел', 'Отдохните и выпейте кофе в уютном кафе, наслаждаясь последними моментами в Пусане.', 'Прощание с Пусаном: Городские Виды и Отдых');
INSERT INTO public.trip_pois VALUES ('f50f8aa9-3d59-438f-ab92-78b348b1d8f5', '307e5e84-7a0a-4fba-ac04-259c97262cd5', NULL, NULL, 'main', true, 7, '19:00', '21:30', 2.5, '35 USD/чел', 'Проведите прощальный ужин и вечер в одном из местных пабов, наслаждаясь атмосферой.', 'Прощание с Пусаном: Городские Виды и Отдых');
INSERT INTO public.trip_pois VALUES ('f50f8aa9-3d59-438f-ab92-78b348b1d8f5', '00081c49-8e86-4cef-b3d5-401a6127df79', NULL, NULL, 'additional', false, 7, '11:00', '12:00', 1, '0', 'Если есть время, можно совершить короткую прогулку по этому прибрежному парку.', 'Прощание с Пусаном: Городские Виды и Отдых');
INSERT INTO public.trip_pois VALUES ('f50f8aa9-3d59-438f-ab92-78b348b1d8f5', '6b51557e-6667-45b9-a702-0c9620ddb5d5', NULL, NULL, 'additional', false, 7, '15:00', '16:00', 1, '8 USD/чел', 'Еще одно стильное кафе для перерыва, если TIDE Coffee Roasters не подойдет.', 'Прощание с Пусаном: Городские Виды и Отдых');
INSERT INTO public.trip_pois VALUES ('f50f8aa9-3d59-438f-ab92-78b348b1d8f5', '3ab4590a-e977-4740-890e-a0f87c275465', NULL, NULL, 'additional', false, 7, '20:00', '22:00', 2, '30 USD/чел', 'Альтернативный бар для прощального вечера, с хорошим выбором пива и закусок.', 'Прощание с Пусаном: Городские Виды и Отдых');
INSERT INTO public.trip_pois VALUES ('1a9b315c-f5b8-411b-befa-d1c6ca8abf5d', '2d2b3d60-d2e8-4bc5-afaf-9e92d195f8f7', NULL, NULL, 'main', true, 1, '09:30', '12:30', 3, '20 юаней/чел', 'Обязательно уделите время деталям архитектуры и резьбы по дереву, это один из лучших образцов традиционной кантонской архитектуры.', 'Культурное погружение и история');
INSERT INTO public.trip_pois VALUES ('1a9b315c-f5b8-411b-befa-d1c6ca8abf5d', '1744bb52-1dff-45ce-8490-db3a1cd0707d', NULL, NULL, 'main', true, 1, '13:30', '16:00', 2.5, '12 юаней/чел', 'Музей находится под землей, что создает особую атмосферу. Познакомьтесь с артефактами времен династии Западная Хань.', 'Культурное погружение и история');
INSERT INTO public.trip_pois VALUES ('1a9b315c-f5b8-411b-befa-d1c6ca8abf5d', 'a0929563-2938-4eac-bf2c-7d9eb9b6afb8', NULL, NULL, 'main', true, 1, '16:30', '18:00', 1.5, '0', 'Одно из немногих католических соборов в готическом стиле в Китае. Вход бесплатный, но соблюдайте тишину и уважение.', 'Культурное погружение и история');
INSERT INTO public.trip_pois VALUES ('1a9b315c-f5b8-411b-befa-d1c6ca8abf5d', '81b458ba-cb94-4fe9-8dd4-7ae516d4c38b', NULL, NULL, 'main', true, 1, '19:00', '21:00', 2, '100-150 юаней/чел', 'Попробуйте традиционные кантонские димсамы. Ресторан очень популярен, поэтому может быть очередь.', 'Культурное погружение и история');
INSERT INTO public.trip_pois VALUES ('1a9b315c-f5b8-411b-befa-d1c6ca8abf5d', '6660ca4c-ed5e-4bb6-a5a5-0e2f2adec0b0', NULL, NULL, 'additional', false, 1, '11:00', '13:00', 2, '0', 'Если вы хотите углубиться в современную историю Гуанчжоу, этот музей предложит интересные экспозиции.', 'Культурное погружение и история');
INSERT INTO public.trip_pois VALUES ('1a9b315c-f5b8-411b-befa-d1c6ca8abf5d', '7f744a41-8d4d-41a0-956c-7c5719bf4fac', NULL, NULL, 'additional', false, 1, '15:00', '16:30', 1.5, '5 юаней/чел', 'Красивый буддийский храм с пагодой, отличный вариант для спокойного отдыха и фото.', 'Культурное погружение и история');
INSERT INTO public.trip_pois VALUES ('1a9b315c-f5b8-411b-befa-d1c6ca8abf5d', '1c8b96f2-2bf0-411d-870a-9a54bf52b3d5', NULL, NULL, 'additional', false, 1, '21:00', '23:00', 2, '150-250 юаней/чел', 'Запасной вариант для вечернего отдыха с напитками и живой музыкой, если захочется продолжения.', 'Культурное погружение и история');
INSERT INTO public.trip_pois VALUES ('1a9b315c-f5b8-411b-befa-d1c6ca8abf5d', 'e65bb8fc-1396-49eb-882b-23ace89f169e', NULL, NULL, 'main', true, 2, '09:00', '13:00', 4, '5 юаней/чел (вход), 20-30 юаней (канатная дорога)', 'Поднимитесь на гору Байюнь для панорамных видов на город. Можно подняться пешком или на канатной дороге. Возьмите с собой воду.', 'Природа и городские виды');
INSERT INTO public.trip_pois VALUES ('1a9b315c-f5b8-411b-befa-d1c6ca8abf5d', '27397574-f8f2-4e83-ab3d-adc9ee8b5c98', NULL, NULL, 'main', true, 2, '14:00', '16:00', 2, '10 юаней/чел', 'Расположен у подножия горы Байюнь, идеальное место для прогулки после спуска. Красивые цветочные композиции и водопады.', 'Природа и городские виды');
INSERT INTO public.trip_pois VALUES ('1a9b315c-f5b8-411b-befa-d1c6ca8abf5d', '6607d460-8c17-47ab-b395-344082e51f7e', NULL, NULL, 'main', true, 2, '18:00', '19:00', 1, '0', 'Отличная точка для вечерних фотографий Кантонской башни. Можно просто прогуляться по набережной.', 'Природа и городские виды');
INSERT INTO public.trip_pois VALUES ('1a9b315c-f5b8-411b-befa-d1c6ca8abf5d', 'be1f657c-4dc3-4182-9a6f-44bc92cfbd00', NULL, NULL, 'main', true, 2, '19:30', '21:00', 1.5, '80-150 юаней/чел', 'Незабываемый способ увидеть ночной Гуанчжоу и его освещенные небоскребы. Бронируйте билеты заранее, особенно в выходные.', 'Природа и городские виды');
INSERT INTO public.trip_pois VALUES ('1a9b315c-f5b8-411b-befa-d1c6ca8abf5d', '11050da5-7d1f-49f3-b44c-9c87139138f4', NULL, NULL, 'additional', false, 2, '10:00', '11:30', 1.5, '0', 'Если вы любите искусство на открытом воздухе, этот парк предлагает интересные скульптуры и спокойную атмосферу.', 'Природа и городские виды');
INSERT INTO public.trip_pois VALUES ('1a9b315c-f5b8-411b-befa-d1c6ca8abf5d', '6eda0799-9085-4c86-b030-221b6eb2814c', NULL, NULL, 'additional', false, 2, '15:00', '16:00', 1, '5 юаней/чел', 'Прекрасное место для любителей орхидей, расположенное недалеко от горы Байюнь.', 'Природа и городские виды');
INSERT INTO public.trip_pois VALUES ('1a9b315c-f5b8-411b-befa-d1c6ca8abf5d', '3403ff6f-e5f9-44f2-8637-1f5edbadaad1', NULL, NULL, 'additional', false, 2, '21:00', '23:00', 2, '150-300 юаней/чел', 'Район с множеством баров и ресторанов на берегу Жемчужной реки, отличное место для продолжения вечера после круиза.', 'Природа и городские виды');
INSERT INTO public.trip_pois VALUES ('1a9b315c-f5b8-411b-befa-d1c6ca8abf5d', '1f6d1190-7a12-42f7-b6c6-f2ed603efe81', NULL, NULL, 'main', true, 3, '09:30', '17:30', 8, '300-500 юаней/чел (зависит от парка)', 'Посвятите целый день одному из парков курорта Chimelong. В зависимости от ваших предпочтений, это может быть аквапарк или сафари-парк.', 'Развлечения и адреналин');
INSERT INTO public.trip_pois VALUES ('1a9b315c-f5b8-411b-befa-d1c6ca8abf5d', 'b2df04f7-fd62-4e8e-ae47-efe1fd278f1e', NULL, NULL, 'main', true, 3, '10:00', '16:00', 6, '200-300 юаней/чел', 'Один из крупнейших аквапарков мира, идеально подходит для жаркого летнего дня. Обязательно наденьте купальник и солнцезащитный крем.', 'Развлечения и адреналин');
INSERT INTO public.trip_pois VALUES ('1a9b315c-f5b8-411b-befa-d1c6ca8abf5d', '9280a3b8-b459-4fd1-b5ff-56b42ae882dc', NULL, NULL, 'main', true, 3, '10:00', '16:00', 6, '250-350 юаней/чел', 'Если вы любите животных, этот сафари-парк предложит уникальный опыт. Можно передвигаться на поезде или на канатной дороге для лучшего обзора.', 'Развлечения и адреналин');
INSERT INTO public.trip_pois VALUES ('1a9b315c-f5b8-411b-befa-d1c6ca8abf5d', 'a39c9bd7-6f7e-43e5-b34e-bbbf9e78413d', NULL, NULL, 'main', true, 3, '19:00', '21:00', 2, '100-200 юаней/чел', 'Большой выбор местной уличной еды и ресторанов. Отличное место, чтобы попробовать что-то новое после активного дня.', 'Развлечения и адреналин');
INSERT INTO public.trip_pois VALUES ('1a9b315c-f5b8-411b-befa-d1c6ca8abf5d', '34601fd0-4333-4353-9ba2-c7037dc0d727', NULL, NULL, 'additional', false, 3, '11:00', '14:00', 3, '150-250 юаней/чел', 'Если вы ищете еще больше адреналина, этот парк аттракционов предложит водные горки и другие развлечения.', 'Развлечения и адреналин');
INSERT INTO public.trip_pois VALUES ('1a9b315c-f5b8-411b-befa-d1c6ca8abf5d', '0a3f37ad-1b5e-41ca-ba48-dabd0459a36f', NULL, NULL, 'additional', false, 3, '11:00', '15:00', 4, '100-200 юаней/чел', 'Еще один вариант парка развлечений, если Chimelong слишком большой или вы хотите разнообразия.', 'Развлечения и адреналин');
INSERT INTO public.trip_pois VALUES ('1a9b315c-f5b8-411b-befa-d1c6ca8abf5d', '0885d055-62aa-414d-aaad-8f3d61d4ce68', NULL, NULL, 'additional', false, 3, '20:00', '21:30', 1.5, '80-120 юаней/чел', 'Если вы предпочитаете более спокойный ужин, Dagefan предлагает вкусную местную кухню.', 'Развлечения и адреналин');
INSERT INTO public.trip_pois VALUES ('1a9b315c-f5b8-411b-befa-d1c6ca8abf5d', 'e43156d6-544a-4480-8a89-900c9590db65', NULL, NULL, 'main', true, 4, '10:00', '13:00', 3, '0', 'Современный музей с обширной коллекцией, охватывающей историю, искусство и природу провинции Гуандун. Забронируйте билеты онлайн заранее.', 'Искусство и релакс');
INSERT INTO public.trip_pois VALUES ('1a9b315c-f5b8-411b-befa-d1c6ca8abf5d', 'c50110a7-92a6-4e0b-a12a-1b891b9ca2c4', NULL, NULL, 'main', true, 4, '14:00', '16:00', 2, '0', 'Познакомьтесь с работами местных художников и студентов художественной академии. Отличный способ увидеть современное китайское искусство.', 'Искусство и релакс');
INSERT INTO public.trip_pois VALUES ('1a9b315c-f5b8-411b-befa-d1c6ca8abf5d', 'e9e23dd2-1e1f-4acb-8abf-80a4e5ddc75a', NULL, NULL, 'main', true, 4, '17:00', '19:00', 2, '200-400 юаней/чел', 'После нескольких активных дней расслабьтесь на тайском массаже. Забронируйте сеанс заранее.', 'Искусство и релакс');
INSERT INTO public.trip_pois VALUES ('1a9b315c-f5b8-411b-befa-d1c6ca8abf5d', '677883d5-aab2-497e-b9ec-a75b35552d30', NULL, NULL, 'main', true, 4, '19:30', '21:30', 2, '150-250 юаней/чел', 'Ресторан с приятной атмосферой и европейской кухней. Отличное место для романтического ужина.', 'Искусство и релакс');
INSERT INTO public.trip_pois VALUES ('1a9b315c-f5b8-411b-befa-d1c6ca8abf5d', '28e0b668-deec-4f64-a63a-cc72ce4e6a44', NULL, NULL, 'additional', false, 4, '10:00', '11:30', 1.5, '0-50 юаней/чел', 'Если вы интересуетесь современным искусством, эта галерея предлагает разнообразные выставки.', 'Искусство и релакс');
INSERT INTO public.trip_pois VALUES ('1a9b315c-f5b8-411b-befa-d1c6ca8abf5d', 'ff259bfc-f7a5-4eee-8043-ff1a4977b4a8', NULL, NULL, 'additional', false, 4, '14:00', '15:30', 1.5, '0-80 юаней/чел', 'Еще одна галерея современного искусства, которая может предложить интересные экспозиции.', 'Искусство и релакс');
INSERT INTO public.trip_pois VALUES ('1a9b315c-f5b8-411b-befa-d1c6ca8abf5d', 'c16afdad-82a4-4fc7-a7f1-4907cd9bf96f', NULL, NULL, 'additional', false, 4, '17:00', '19:00', 2, '200-500 юаней/чел', 'Альтернативный вариант для спа-процедур и релаксации.', 'Искусство и релакс');
INSERT INTO public.trip_pois VALUES ('1a9b315c-f5b8-411b-befa-d1c6ca8abf5d', 'c30dffae-2d9a-4f3b-8922-91927fd86f2a', NULL, NULL, 'main', true, 5, '10:00', '13:00', 3, '200-1000 юаней/чел (зависит от покупок)', 'Один из самых престижных торговых центров Гуанчжоу с большим выбором брендовых магазинов и ресторанов.', 'Шоппинг и современные районы');
INSERT INTO public.trip_pois VALUES ('1a9b315c-f5b8-411b-befa-d1c6ca8abf5d', 'f7d00079-1040-452b-a660-c297038ca388', NULL, NULL, 'main', true, 5, '14:00', '16:30', 2.5, '100-500 юаней/чел', 'Оптовый рынок модной одежды. Не забудьте торговаться! Цены для туристов могут быть завышены в 2-3 раза.', 'Шоппинг и современные районы');
INSERT INTO public.trip_pois VALUES ('1a9b315c-f5b8-411b-befa-d1c6ca8abf5d', '82a3ee30-ecaf-4b1e-a65f-b488b6768a18', NULL, NULL, 'main', true, 5, '16:30', '18:30', 2, '100-500 юаней/чел', 'Еще один крупный рынок одежды. Здесь можно найти как оптовые, так и розничные предложения. Торгуйтесь активно!', 'Шоппинг и современные районы');
INSERT INTO public.trip_pois VALUES ('1a9b315c-f5b8-411b-befa-d1c6ca8abf5d', '80a37810-187c-47f6-bc81-3d310f081746', NULL, NULL, 'main', true, 5, '20:00', '22:00', 2, '150-300 юаней/чел', 'Стильный коктейль-бар, где можно расслабиться после шопинга. Попробуйте их фирменные напитки.', 'Шоппинг и современные районы');
INSERT INTO public.trip_pois VALUES ('1a9b315c-f5b8-411b-befa-d1c6ca8abf5d', 'd5eb0807-98ca-46f5-9c21-3891426da96b', NULL, NULL, 'additional', false, 5, '10:00', '13:00', 3, '200-800 юаней/чел', 'Если вы ищете скидки на брендовую одежду, Wanguo Outlets может быть хорошим вариантом.', 'Шоппинг и современные районы');
INSERT INTO public.trip_pois VALUES ('1a9b315c-f5b8-411b-befa-d1c6ca8abf5d', '31135abd-7c77-49b4-b37e-b1c0694b8029', NULL, NULL, 'additional', false, 5, '14:00', '16:00', 2, '100-400 юаней/чел', 'Еще один торговый центр с широким ассортиментом одежды и аксессуаров.', 'Шоппинг и современные районы');
INSERT INTO public.trip_pois VALUES ('1a9b315c-f5b8-411b-befa-d1c6ca8abf5d', 'aae59232-a0a1-4b12-880f-d4cfae770dfc', NULL, NULL, 'additional', false, 5, '21:00', '23:00', 2, '100-200 юаней/чел', 'Если вы ищете более оживленный бар с музыкой, Goddess Pub может быть хорошим выбором.', 'Шоппинг и современные районы');
INSERT INTO public.trip_pois VALUES ('1a9b315c-f5b8-411b-befa-d1c6ca8abf5d', '06ad83e7-bfac-458f-9e14-3d257e3f4c1e', NULL, NULL, 'main', true, 6, '09:30', '12:30', 3, '0', 'Прогуляйтесь по этому историческому острову с европейской архитектурой. Идеальное место для неспешной прогулки и фотографий.', 'Парки и культурное наследие');
INSERT INTO public.trip_pois VALUES ('1a9b315c-f5b8-411b-befa-d1c6ca8abf5d', '8159f2a2-beac-49c2-9a09-1707f157f585', NULL, NULL, 'main', true, 6, '13:30', '15:30', 2, '0', 'Красивый парк с озером, мостиками и пагодами. Отличное место для отдыха и наблюдения за местной жизнью.', 'Парки и культурное наследие');
INSERT INTO public.trip_pois VALUES ('1a9b315c-f5b8-411b-befa-d1c6ca8abf5d', '62d5c4f2-c2a3-46ae-86d2-956ca2edf5f8', NULL, NULL, 'main', true, 6, '16:00', '17:30', 1.5, '0', 'Музей кантонской оперы, где можно узнать об этом традиционном искусстве. Иногда проводятся представления.', 'Парки и культурное наследие');
INSERT INTO public.trip_pois VALUES ('1a9b315c-f5b8-411b-befa-d1c6ca8abf5d', '63be6c44-3ed7-4440-b5f2-4f61e341c5ec', NULL, NULL, 'main', true, 6, '19:00', '21:00', 2, '100-200 юаней/чел', 'Ресторан, специализирующийся на морепродуктах. Отличное место, чтобы попробовать свежие местные деликатесы.', 'Парки и культурное наследие');
INSERT INTO public.trip_pois VALUES ('1a9b315c-f5b8-411b-befa-d1c6ca8abf5d', '4a570c99-ba06-4c3f-8037-08a61dfb30bf', NULL, NULL, 'additional', false, 6, '10:00', '12:00', 2, '0', 'Еще один живописный парк с озером, если вы хотите больше времени провести на природе.', 'Парки и культурное наследие');
INSERT INTO public.trip_pois VALUES ('1a9b315c-f5b8-411b-befa-d1c6ca8abf5d', 'fd98d3e2-604c-4a9a-989a-0e241bdb0d9e', NULL, NULL, 'additional', false, 6, '10:00', '12:00', 2, '0', 'Восточный вход в парк Liuhuahu, удобно для начала прогулки.', 'Парки и культурное наследие');
INSERT INTO public.trip_pois VALUES ('1a9b315c-f5b8-411b-befa-d1c6ca8abf5d', 'abc21cde-121b-4ec4-80b2-2d57f1ebdb51', NULL, NULL, 'additional', false, 6, '21:00', '23:00', 2, '100-200 юаней/чел', 'Уютный паб для вечернего отдыха с напитками и легкими закусками.', 'Парки и культурное наследие');
INSERT INTO public.trip_pois VALUES ('1a9b315c-f5b8-411b-befa-d1c6ca8abf5d', '9bb33798-8b5a-4ff7-9d56-032b88b470ff', NULL, NULL, 'additional', false, 7, '10:00', '12:30', 2.5, '0', 'Если вы предпочитаете более уединенное место для прогулки на природе, этот лесной парк предложит тишину и свежий воздух.', 'Отдых и последние впечатления');
INSERT INTO public.trip_pois VALUES ('1a9b315c-f5b8-411b-befa-d1c6ca8abf5d', '20bfc709-5e19-4ecf-a277-0c3c01025c0e', NULL, NULL, 'additional', false, 7, '14:00', '15:30', 1.5, '0', 'Небольшой, но ухоженный парк для короткой прогулки или отдыха на скамейке.', 'Отдых и последние впечатления');
INSERT INTO public.trip_pois VALUES ('1a9b315c-f5b8-411b-befa-d1c6ca8abf5d', 'f0971cfc-1d12-466c-82a9-cc4157f4b763', NULL, NULL, 'additional', false, 7, '19:00', '20:30', 1.5, '150-250 юаней/чел', 'Если вы соскучились по европейской кухне, этот итальянский ресторан предложит вкусные блюда.', 'Отдых и последние впечатления');
INSERT INTO public.trip_pois VALUES ('1a9b315c-f5b8-411b-befa-d1c6ca8abf5d', '75bbfc7d-71ed-4f8e-91b9-98cd01a7f362', 1, NULL, 'main', true, 7, '18:00', '20:00', 2, '150-250 юаней/чел', 'Один из самых известных ресторанов кантонской кухни. Отличное место для прощального ужина. Попробуйте их жареную свинину на гриле.', 'Отдых и последние впечатления');
INSERT INTO public.trip_pois VALUES ('1a9b315c-f5b8-411b-befa-d1c6ca8abf5d', '891bd4cb-dcd8-4018-b7d3-973a7fab4879', 4, NULL, 'main', true, 7, '09:30', '12:30', 3, '0', 'Огромный городской водно-болотный парк, идеальное место для утренней прогулки, наблюдения за птицами и наслаждения природой.', 'Отдых и последние впечатления');
INSERT INTO public.trip_pois VALUES ('1a9b315c-f5b8-411b-befa-d1c6ca8abf5d', '93d2b5be-45a0-41fb-81f7-bea8eff61a4d', 2, NULL, 'main', true, 7, '21:00', '23:00', 2, '100-200 юаней/чел', 'Завершите путешествие в уютном баре с хорошим выбором напитков. Отличное место, чтобы поделиться впечатлениями о поездке.', 'Отдых и последние впечатления');
INSERT INTO public.trip_pois VALUES ('1a9b315c-f5b8-411b-befa-d1c6ca8abf5d', 'dda087c6-6e95-469f-ab21-1f9d32509ec1', 3, NULL, 'main', true, 7, '13:00', '14:30', 1.5, '0', 'Небольшой, но уютный парк рядом с водно-болотным парком, хорошее место для пикника или короткого отдыха.', 'Отдых и последние впечатления');
INSERT INTO public.trip_pois VALUES ('ceb1a46f-f44c-4b15-be86-899d83febc59', '34afa3a2-c7cc-4e5d-b022-cb2d82bdd21b', NULL, NULL, 'main', true, 1, '09:30', '10:00', 0.5, '0', 'Начните день с культовых ворот Каминаримон, символа Асакусы. Идеальное место для первых фотографий.', 'Историческое наследие Асакусы и Уэно');
INSERT INTO public.trip_pois VALUES ('ceb1a46f-f44c-4b15-be86-899d83febc59', '79b50e57-87c7-471c-90ec-cce1c3214bb1', NULL, NULL, 'main', true, 1, '10:00', '11:30', 1.5, '20-50 USD/чел', 'Прогуляйтесь по торговой улице Накамисэ, ведущей к храму Сэнсо-дзи. Здесь можно купить традиционные сувениры и попробовать местные закуски.', 'Историческое наследие Асакусы и Уэно');
INSERT INTO public.trip_pois VALUES ('ceb1a46f-f44c-4b15-be86-899d83febc59', '1c16d8e2-f31c-4be3-b712-3a0b8af47885', NULL, NULL, 'main', true, 1, '13:00', '16:00', 3, '10-15 USD/чел', 'Погрузитесь в историю и искусство Японии, посетив один из крупнейших музеев страны, расположенный в парке Уэно.', 'Историческое наследие Асакусы и Уэно');
INSERT INTO public.trip_pois VALUES ('ceb1a46f-f44c-4b15-be86-899d83febc59', 'c19db208-16e5-4d9e-ae6d-273bb3e98a94', NULL, NULL, 'main', true, 1, '16:00', '17:30', 1.5, '0', 'Отдохните в живописном парке Уэно, наслаждаясь природой и атмосферой после насыщенной культурной программы.', 'Историческое наследие Асакусы и Уэно');
INSERT INTO public.trip_pois VALUES ('ceb1a46f-f44c-4b15-be86-899d83febc59', 'a7b354d4-dc40-4049-87dc-69b2237ed7fd', NULL, NULL, 'additional', false, 1, '11:30', '12:30', 1, '5-10 USD/чел', 'Если интересуетесь современным искусством, эта галерея предлагает интересные выставки недалеко от Асакусы.', 'Историческое наследие Асакусы и Уэно');
INSERT INTO public.trip_pois VALUES ('ceb1a46f-f44c-4b15-be86-899d83febc59', 'e9532b32-de5a-4dba-9b5d-4477ff612a4f', NULL, NULL, 'additional', false, 1, '17:30', '18:30', 1, '10-30 USD/чел', 'Оживленный рынок Амейоко — отличное место для вечерней прогулки и покупки сувениров или перекуса.', 'Историческое наследие Асакусы и Уэно');
INSERT INTO public.trip_pois VALUES ('ceb1a46f-f44c-4b15-be86-899d83febc59', 'db4ac11b-aaf2-4964-a3f1-71309b18be4a', NULL, NULL, 'additional', false, 1, '16:30', '17:30', 1, '0', 'Если хотите спокойствия, прогуляйтесь вокруг пруда Синобадзу в парке Уэно, особенно красив во время цветения лотосов.', 'Историческое наследие Асакусы и Уэно');
INSERT INTO public.trip_pois VALUES ('ceb1a46f-f44c-4b15-be86-899d83febc59', 'cb99df95-74af-4765-b9e5-54e5699672ff', NULL, NULL, 'main', true, 2, '09:30', '11:30', 2, '0', 'Насладитесь спокойствием и красотой японских садов, а также видом на Императорский дворец.', 'Императорские сады и современные небоскребы');
INSERT INTO public.trip_pois VALUES ('ceb1a46f-f44c-4b15-be86-899d83febc59', '367f547b-17e2-4417-9ba6-084e4cc43d41', NULL, NULL, 'main', true, 2, '11:30', '12:30', 1, '0', 'Приятное место для прогулки и отдыха с фонтанами, расположенное недалеко от Императорского дворца.', 'Императорские сады и современные небоскребы');
INSERT INTO public.trip_pois VALUES ('ceb1a46f-f44c-4b15-be86-899d83febc59', '036c4611-df09-4872-b71d-bbc6f0c6635c', NULL, NULL, 'main', true, 2, '13:30', '16:00', 2.5, '10-15 USD/чел', 'Посетите этот музей с красивой архитектурой, чтобы увидеть коллекции западного искусства и насладиться временными выставками.', 'Императорские сады и современные небоскребы');
INSERT INTO public.trip_pois VALUES ('ceb1a46f-f44c-4b15-be86-899d83febc59', '30658009-a299-422a-abd7-f36827c2738c', NULL, NULL, 'main', true, 2, '16:30', '17:30', 1, '0', 'Поднимитесь на верхние этажи здания Dentsu для панорамных видов на город, особенно красивых на закате.', 'Императорские сады и современные небоскребы');
INSERT INTO public.trip_pois VALUES ('ceb1a46f-f44c-4b15-be86-899d83febc59', 'b993310b-bceb-4c1e-ada4-04f6d5603838', NULL, NULL, 'additional', false, 2, '18:00', '20:00', 2, '20-50 USD/чел', 'Если есть возможность, посмотрите часть представления традиционного театра Кабуки. Можно купить билеты на один акт.', 'Императорские сады и современные небоскребы');
INSERT INTO public.trip_pois VALUES ('ceb1a46f-f44c-4b15-be86-899d83febc59', 'a4ace9b9-97f1-46fb-bff0-f5ed0d5f1fac', NULL, NULL, 'additional', false, 2, '19:30', '21:00', 1.5, '100-200 USD/чел', 'Для изысканного ужина попробуйте суши в одном из самых известных ресторанов Гиндзы. Бронирование обязательно.', 'Императорские сады и современные небоскребы');
INSERT INTO public.trip_pois VALUES ('ceb1a46f-f44c-4b15-be86-899d83febc59', 'fd82a8da-3506-4c9a-bb7a-4a6a249ca84e', NULL, NULL, 'main', true, 3, '10:00', '10:30', 0.5, '0', 'Ощутите пульс Токио, пересекая самый оживленный перекресток в мире. Лучше всего наблюдать с верхних этажей зданий вокруг.', 'Шибуя, Харадзюку и современное искусство');
INSERT INTO public.trip_pois VALUES ('ceb1a46f-f44c-4b15-be86-899d83febc59', 'd7ff60c8-1699-4735-aa85-56447f0b7af1', NULL, NULL, 'main', true, 3, '10:30', '10:42', 0.2, '0', 'Почтите память верного Хатико, символа преданности, расположенного рядом с перекрестком Шибуя.', 'Шибуя, Харадзюку и современное искусство');
INSERT INTO public.trip_pois VALUES ('ceb1a46f-f44c-4b15-be86-899d83febc59', '0cf7dfb1-b1bc-4ac8-a9ea-dfb3c035732c', NULL, NULL, 'main', true, 3, '12:00', '13:00', 1, '15-25 USD/чел', 'Попробуйте знаменитый гюкацу (жареная говядина) в Харадзюку, это популярное место, поэтому возможны очереди.', 'Шибуя, Харадзюку и современное искусство');
INSERT INTO public.trip_pois VALUES ('ceb1a46f-f44c-4b15-be86-899d83febc59', 'ba07d40a-7b62-4d90-806f-79786e4bed7f', NULL, NULL, 'main', true, 3, '14:00', '16:00', 2, '0-5 USD/чел', 'Исследуйте необычные и креативные работы местных художников в галерее Design Festa, расположенной в Харадзюку.', 'Шибуя, Харадзюку и современное искусство');
INSERT INTO public.trip_pois VALUES ('ceb1a46f-f44c-4b15-be86-899d83febc59', '336b9e7d-5c6b-4d61-8576-9236057b90fc', NULL, NULL, 'main', true, 3, '16:00', '18:00', 2, '25-35 USD/чел', 'Погрузитесь в интерактивный мир цифрового искусства. Рекомендуется бронировать билеты заранее.', 'Шибуя, Харадзюку и современное искусство');
INSERT INTO public.trip_pois VALUES ('ceb1a46f-f44c-4b15-be86-899d83febc59', '1d677282-41e0-4329-97c0-0c543bbac4f1', NULL, NULL, 'additional', false, 3, '11:00', '11:30', 0.5, '5-10 USD/чел', 'Отличное место для кофе-брейка с видом на оживленный район Шибуя.', 'Шибуя, Харадзюку и современное искусство');
INSERT INTO public.trip_pois VALUES ('ceb1a46f-f44c-4b15-be86-899d83febc59', 'e4b3d98e-486e-4be5-989c-9c502699db20', NULL, NULL, 'additional', false, 3, '15:00', '16:00', 1, '10-20 USD/чел', 'Посетите уникальную обжарочную Starbucks с несколькими этажами и эксклюзивными напитками. Красивый дизайн и отличный кофе.', 'Шибуя, Харадзюку и современное искусство');
INSERT INTO public.trip_pois VALUES ('ceb1a46f-f44c-4b15-be86-899d83febc59', 'b99a8085-b3bc-4b0c-a3c2-b2aba702c3ea', NULL, NULL, 'additional', false, 3, '20:00', '22:00', 2, '30-50 USD/чел', 'Завершите день в музыкальном баре в Шибуе, наслаждаясь напитками и атмосферой.', 'Шибуя, Харадзюку и современное искусство');
INSERT INTO public.trip_pois VALUES ('ceb1a46f-f44c-4b15-be86-899d83febc59', '1f23f9d3-4fb3-4463-bcae-cb6e115425a7', NULL, NULL, 'main', true, 4, '09:30', '11:30', 2, '3-5 USD/чел', 'Один из самых красивых ландшафтных садов Токио, идеально подходит для утренней прогулки и медитации.', 'Традиционные сады и современная архитектура');
INSERT INTO public.trip_pois VALUES ('ceb1a46f-f44c-4b15-be86-899d83febc59', '49c07e64-06b4-4f7b-954a-cdb9e983d73d', NULL, NULL, 'main', true, 4, '12:00', '15:00', 3, '5-10 USD/чел', 'Уникальная возможность увидеть и потрогать старинные японские здания, перенесенные из разных частей Токио.', 'Традиционные сады и современная архитектура');
INSERT INTO public.trip_pois VALUES ('ceb1a46f-f44c-4b15-be86-899d83febc59', 'e299cd04-b866-4f3d-8fc5-b5f01701a3b7', NULL, NULL, 'main', true, 4, '15:30', '18:00', 2.5, '3-5 USD/чел', 'Огромный парк с разнообразными садами, цветами и зонами отдыха. Отличное место для прогулок и пикников.', 'Традиционные сады и современная архитектура');
INSERT INTO public.trip_pois VALUES ('ceb1a46f-f44c-4b15-be86-899d83febc59', 'f74decc4-8294-4dc4-9a0f-a47fa21464a1', NULL, NULL, 'main', true, 4, '18:30', '20:00', 1.5, '10-15 USD/чел', 'Поднимитесь на Токийскую башню для потрясающих видов на город, особенно красивых на закате и ночью.', 'Традиционные сады и современная архитектура');
INSERT INTO public.trip_pois VALUES ('ceb1a46f-f44c-4b15-be86-899d83febc59', '6f620c64-8438-4a6d-bc09-0b2281510bac', NULL, NULL, 'additional', false, 4, '17:00', '18:00', 1, '0', 'Если вы находитесь в районе Синдзюку, этот парк предлагает зеленый оазис среди небоскребов.', 'Традиционные сады и современная архитектура');
INSERT INTO public.trip_pois VALUES ('ceb1a46f-f44c-4b15-be86-899d83febc59', 'e37eaa22-f425-424a-9cc4-a2c315fad8e1', NULL, NULL, 'additional', false, 4, '19:00', '20:00', 1, '0', 'Посетите смотровую площадку Tokyo Opera City Tower для еще одного впечатляющего вида на ночной Токио.', 'Традиционные сады и современная архитектура');
INSERT INTO public.trip_pois VALUES ('ceb1a46f-f44c-4b15-be86-899d83febc59', 'e4fd0633-9504-4bfb-88bf-bccb92f189b0', NULL, NULL, 'main', true, 5, '08:00', '10:00', 2, '20-50 USD/чел', 'Посетите новый рыбный рынок Тоёсу, преемник Цукидзи. Здесь можно наблюдать за торговлей и попробовать свежайшие морепродукты на завтрак.', 'Рынок, современное искусство и развлечения');
INSERT INTO public.trip_pois VALUES ('ceb1a46f-f44c-4b15-be86-899d83febc59', '3bfbd328-ea70-42d8-90c4-04e9f93ec9bb', NULL, NULL, 'main', true, 5, '11:00', '13:30', 2.5, '10-15 USD/чел', 'Погрузитесь в мир современного искусства в MOT, где представлены как японские, так и международные художники.', 'Рынок, современное искусство и развлечения');
INSERT INTO public.trip_pois VALUES ('ceb1a46f-f44c-4b15-be86-899d83febc59', '14a066ad-962c-41a4-af5c-47de0bf97f19', NULL, NULL, 'main', true, 5, '14:00', '16:00', 2, '20-25 USD/чел', 'Насладитесь морской жизнью в аквариуме Сумида, расположенном у подножия Tokyo Skytree.', 'Рынок, современное искусство и развлечения');
INSERT INTO public.trip_pois VALUES ('ceb1a46f-f44c-4b15-be86-899d83febc59', '19f1388e-b38e-46da-be06-6a118a00a89f', NULL, NULL, 'main', true, 5, '16:30', '18:30', 2, '20-30 USD/чел', 'Поднимитесь на Tokyo Skytree для захватывающих панорамных видов на Токио и его окрестности.', 'Рынок, современное искусство и развлечения');
INSERT INTO public.trip_pois VALUES ('ceb1a46f-f44c-4b15-be86-899d83febc59', 'bc8ef288-7e07-4338-b2b8-e5f48a6be388', NULL, NULL, 'additional', false, 5, '18:30', '19:00', 0.5, '0', 'Прогуляйтесь по Радужному мосту или полюбуйтесь им издалека, особенно красиво вечером, когда он подсвечивается.', 'Рынок, современное искусство и развлечения');
INSERT INTO public.trip_pois VALUES ('ceb1a46f-f44c-4b15-be86-899d83febc59', '5143b2bd-1c1f-4388-a15c-17d2a4cbef41', NULL, NULL, 'additional', false, 5, '19:00', '20:30', 1.5, '15-20 USD/чел', 'Завершите день, наслаждаясь панорамным видом на город с Roppongi Hills, здесь также есть Художественный музей Мори.', 'Рынок, современное искусство и развлечения');
INSERT INTO public.trip_pois VALUES ('ceb1a46f-f44c-4b15-be86-899d83febc59', '33c97d92-04ef-4a6b-a008-c76a95e66169', NULL, NULL, 'main', true, 6, '10:00', '11:30', 1.5, '0-2 USD/чел', 'Посетите этот очаровательный храм, известный своими тысячами фигурок манеки-нэко (машущих кошек).', 'Храмы, парки и спокойствие');
INSERT INTO public.trip_pois VALUES ('ceb1a46f-f44c-4b15-be86-899d83febc59', '80cc0e41-62b7-44c8-9189-deed00dc0c0a', NULL, NULL, 'main', true, 6, '12:00', '13:00', 1, '0-5 USD/чел', 'Посетите храм Сэнгакудзи, известный как место захоронения 47 ронинов, и узнайте их историю.', 'Храмы, парки и спокойствие');
INSERT INTO public.trip_pois VALUES ('ceb1a46f-f44c-4b15-be86-899d83febc59', '849438b1-2ef5-4ed5-8ae4-563b8f98d82d', NULL, NULL, 'main', true, 6, '14:00', '16:00', 2, '0', 'Прогуляйтесь по красивому парку Инокасира, возьмите напрокат лодку или посетите зоопарк внутри парка.', 'Храмы, парки и спокойствие');
INSERT INTO public.trip_pois VALUES ('ceb1a46f-f44c-4b15-be86-899d83febc59', 'db88a9c4-55c9-42b8-a3d0-fb122450c3b8', NULL, NULL, 'main', true, 6, '16:30', '18:30', 2, '3-5 USD/чел', 'Погрузитесь в атмосферу Токио периода Эдо, прогулявшись по воссозданной улице с домами и магазинами.', 'Храмы, парки и спокойствие');
INSERT INTO public.trip_pois VALUES ('ceb1a46f-f44c-4b15-be86-899d83febc59', '2d043cc3-6941-4984-a2dd-fe9350f07ad3', NULL, NULL, 'additional', false, 6, '11:00', '11:30', 0.5, '0', 'Если интересуетесь архитектурой, эта церковь предлагает интересный контраст с традиционными японскими храмами.', 'Храмы, парки и спокойствие');
INSERT INTO public.trip_pois VALUES ('ceb1a46f-f44c-4b15-be86-899d83febc59', '5c4db94e-b3dd-4b81-9189-6e45f5ac4121', NULL, NULL, 'additional', false, 6, '13:00', '13:30', 0.5, '0', 'Небольшой, но красивый храм, предлагающий умиротворение и красивые виды, особенно во время цветения сакуры.', 'Храмы, парки и спокойствие');
INSERT INTO public.trip_pois VALUES ('ceb1a46f-f44c-4b15-be86-899d83febc59', 'fd36e12f-7bc3-4afb-8352-64c479a634b4', NULL, NULL, 'main', true, 7, '10:00', '13:00', 3, '10-20 USD/чел (чаевые)', 'Присоединитесь к бесплатному пешему туру, чтобы узнать больше о городе от местных жителей и открыть для себя новые уголки Токио.', 'Свободное время и прощание с Токио');
INSERT INTO public.trip_pois VALUES ('ceb1a46f-f44c-4b15-be86-899d83febc59', '0ac4b474-f179-4acf-9769-db4284c5ca47', NULL, NULL, 'main', true, 7, '14:00', '20:00', 6, '60-80 USD/чел', 'Если вы любите парки развлечений, проведите вторую половину дня в Дисней Си, уникальном парке с морской тематикой.', 'Свободное время и прощание с Токио');
INSERT INTO public.trip_pois VALUES ('ceb1a46f-f44c-4b15-be86-899d83febc59', '01b4fdd1-cad5-4a48-87c8-8cc1e77fe385', NULL, NULL, 'main', true, 7, '18:00', '19:00', 1, '0', 'Перед вылетом посетите смотровую площадку Терминала 3, чтобы полюбоваться взлетающими и приземляющимися самолетами.', 'Свободное время и прощание с Токио');
INSERT INTO public.trip_pois VALUES ('ceb1a46f-f44c-4b15-be86-899d83febc59', 'ca6920d3-f8d9-49b9-b89c-683ed9aeae6a', NULL, NULL, 'additional', false, 7, '10:00', '12:00', 2, '25-35 USD/чел', 'Если вы не успели посетить TeamLab Planets раньше, это отличный шанс погрузиться в мир цифрового искусства.', 'Свободное время и прощание с Токио');
INSERT INTO public.trip_pois VALUES ('ceb1a46f-f44c-4b15-be86-899d83febc59', 'e7022e7e-0b83-4500-bb3d-44c37a832fd5', NULL, NULL, 'additional', false, 7, '13:00', '13:30', 0.5, '0', 'Сделайте забавные фотографии со статуей Годзиллы, если вы находитесь в районе Синдзюку.', 'Свободное время и прощание с Токио');
INSERT INTO public.trip_pois VALUES ('ceb1a46f-f44c-4b15-be86-899d83febc59', 'ea9bf382-6822-4a0b-91aa-bcc6059b3535', NULL, NULL, 'additional', false, 7, '16:00', '19:00', 3, '40-60 USD/чел', 'Расслабьтесь в СПА-комплексе LaQua с горячими источниками и различными процедурами.', 'Свободное время и прощание с Токио');
INSERT INTO public.trip_pois VALUES ('2343e2c5-4e06-4276-8f34-b14c07ddb76c', 'b267480b-e6ad-45fe-b6d1-aeb0b4590b1f', NULL, NULL, 'main', true, 1, '09:30', '12:30', 3, '30 USD/чел', 'Приходите пораньше, чтобы избежать больших очередей и насладиться дворцом и гаремом без спешки.', 'Сердце Стамбула: Султанахмет и древние тайны');
INSERT INTO public.trip_pois VALUES ('2343e2c5-4e06-4276-8f34-b14c07ddb76c', '3e2e87b6-f5b8-460a-b450-c7dc3462dfe0', NULL, NULL, 'main', true, 1, '13:00', '15:30', 2.5, '15 USD/чел', 'Обязательно посетите саркофаг Александра и другие древние артефакты, расположенные в трех основных зданиях музея.', 'Сердце Стамбула: Султанахмет и древние тайны');
INSERT INTO public.trip_pois VALUES ('2343e2c5-4e06-4276-8f34-b14c07ddb76c', 'e924b429-5694-4790-bb7c-42fb82ee7302', NULL, NULL, 'main', true, 1, '16:00', '17:30', 1.5, '10 USD/чел', 'Полюбуйтесь необычной атмосферой подземного водохранилища, особенно головами Медузы и колонной слез.', 'Сердце Стамбула: Султанахмет и древние тайны');
INSERT INTO public.trip_pois VALUES ('2343e2c5-4e06-4276-8f34-b14c07ddb76c', 'e70c480c-8612-4913-8480-c7cde44d40ea', NULL, NULL, 'main', true, 1, '19:00', '21:00', 2, '30 USD/чел', 'Насладитесь традиционной турецкой кухней в уютной атмосфере с видом на исторические достопримечательности.', 'Сердце Стамбула: Султанахмет и древние тайны');
INSERT INTO public.trip_pois VALUES ('2343e2c5-4e06-4276-8f34-b14c07ddb76c', '034a83f1-8c63-49c8-8134-a2f323da71ff', NULL, NULL, 'additional', false, 1, '17:30', '18:30', 1, '0', 'Идеальное место для вечерней прогулки и любования Голубой мечетью и собором Святой Софии снаружи.', 'Сердце Стамбула: Султанахмет и древние тайны');
INSERT INTO public.trip_pois VALUES ('2343e2c5-4e06-4276-8f34-b14c07ddb76c', 'e3c222c1-ba9d-4c99-b974-4c691a590992', NULL, NULL, 'additional', false, 1, '18:30', '19:00', 0.5, '0', 'Отдохните на скамейках, наслаждаясь атмосферой и видами на исторические памятники.', 'Сердце Стамбула: Султанахмет и древние тайны');
INSERT INTO public.trip_pois VALUES ('2343e2c5-4e06-4276-8f34-b14c07ddb76c', 'a3576ef2-37d3-4d02-9343-c9c5fbe1da0c', NULL, NULL, 'additional', false, 1, '19:00', '21:00', 2, '25 USD/чел', 'Рассмотрите этот ресторан как альтернативу для ужина с видом на достопримечательности Султанахмета.', 'Сердце Стамбула: Султанахмет и древние тайны');
INSERT INTO public.trip_pois VALUES ('2343e2c5-4e06-4276-8f34-b14c07ddb76c', '11de0ef3-cb67-4c28-a146-99004f4b51ff', NULL, NULL, 'additional', false, 1, '17:00', '18:00', 1, '0', 'Небольшой, но очаровательный рынок рядом с Голубой мечетью, где можно найти сувениры и изделия ручной работы.', 'Сердце Стамбула: Султанахмет и древние тайны');
INSERT INTO public.trip_pois VALUES ('2343e2c5-4e06-4276-8f34-b14c07ddb76c', '69dfdce9-defa-4655-9dbb-4ce1d8088032', NULL, NULL, 'main', true, 2, '09:30', '12:30', 3, '35 USD/чел', 'Обязательно посетите Селамлык и Гарем, чтобы полностью погрузиться в роскошь и историю последнего дворца османских султанов.', 'Величие Османской империи и торговые пути');
INSERT INTO public.trip_pois VALUES ('2343e2c5-4e06-4276-8f34-b14c07ddb76c', 'af2add16-2ed9-4e11-b55e-3fe472fd2682', NULL, NULL, 'main', true, 2, '13:00', '15:00', 2, '10 USD/чел', 'Расположенный рядом с Долмабахче, этот музей предлагает уникальную коллекцию турецкой живописи 19-20 веков.', 'Величие Османской империи и торговые пути');
INSERT INTO public.trip_pois VALUES ('2343e2c5-4e06-4276-8f34-b14c07ddb76c', '3d2f4147-b5c9-4f06-960a-564904ffcce5', NULL, NULL, 'main', true, 2, '15:30', '18:00', 2.5, '0', 'Погрузитесь в атмосферу одного из старейших и крупнейших крытых рынков мира. Не забудьте торговаться!', 'Величие Османской империи и торговые пути');
INSERT INTO public.trip_pois VALUES ('2343e2c5-4e06-4276-8f34-b14c07ddb76c', '963303df-7276-49d9-8910-9f5dd217308f', NULL, NULL, 'main', true, 2, '19:00', '21:00', 2, '35 USD/чел', 'Насладитесь изысканной османской кухней на террасе с прекрасным видом на город.', 'Величие Османской империи и торговые пути');
INSERT INTO public.trip_pois VALUES ('2343e2c5-4e06-4276-8f34-b14c07ddb76c', '9a71e579-0386-4ea2-b5b4-1947abf0bdb1', NULL, NULL, 'additional', false, 2, '12:00', '13:00', 1, '0', 'Небольшая художественная галерея рядом с дворцом Долмабахче, предлагающая работы современных турецких художников.', 'Величие Османской империи и торговые пути');
INSERT INTO public.trip_pois VALUES ('2343e2c5-4e06-4276-8f34-b14c07ddb76c', 'c188cfbd-0dcb-4749-9d3f-3be9b6ff45c0', NULL, NULL, 'additional', false, 2, '18:00', '19:30', 1.5, '0', 'Если у вас еще есть силы для шопинга, Египетский базар предложит специи, сладости и сухофрукты.', 'Величие Османской империи и торговые пути');
INSERT INTO public.trip_pois VALUES ('2343e2c5-4e06-4276-8f34-b14c07ddb76c', '18f2b9f5-38b4-45c2-acff-00ddae15ed77', NULL, NULL, 'additional', false, 2, '19:00', '21:00', 2, '30 USD/чел', 'Альтернативный вариант для ужина с красивым видом на Босфор, предлагающий традиционные турецкие блюда.', 'Величие Османской империи и торговые пути');
INSERT INTO public.trip_pois VALUES ('2343e2c5-4e06-4276-8f34-b14c07ddb76c', '6a048168-9f22-4bd4-a25e-ebe8d189566e', NULL, NULL, 'additional', false, 2, '17:00', '17:30', 0.5, '0', 'Посетите этот исторический караван-сарай, чтобы увидеть его внутренний двор и, возможно, найти скрытые мастерские.', 'Величие Османской империи и торговые пути');
INSERT INTO public.trip_pois VALUES ('2343e2c5-4e06-4276-8f34-b14c07ddb76c', '1dbd1386-81ee-41f5-b214-c6eb799ae984', NULL, NULL, 'main', true, 3, '10:00', '12:00', 2, '0', 'Посетите эту величественную мечеть, шедевр архитектора Синана, и насладитесь панорамным видом на Золотой Рог и Босфор.', 'Религиозное наследие и панорамные виды');
INSERT INTO public.trip_pois VALUES ('2343e2c5-4e06-4276-8f34-b14c07ddb76c', 'e8fa7d9c-45b7-4389-ad91-5e16dc6c860b', NULL, NULL, 'main', true, 3, '12:30', '14:30', 2, '12 USD/чел', 'Музей расположен в бывшем дворце Ибрагима-паши и содержит впечатляющую коллекцию исламского искусства, включая ковры и каллиграфию.', 'Религиозное наследие и панорамные виды');
INSERT INTO public.trip_pois VALUES ('2343e2c5-4e06-4276-8f34-b14c07ddb76c', '8bfbfb32-328c-4683-bb05-1b879c7983d2', NULL, NULL, 'main', true, 3, '16:00', '17:30', 1.5, '15 USD/чел', 'Поднимитесь на одну из самых высоких смотровых площадок Стамбула, чтобы увидеть город с высоты птичьего полета. Особенно красиво на закате.', 'Религиозное наследие и панорамные виды');
INSERT INTO public.trip_pois VALUES ('2343e2c5-4e06-4276-8f34-b14c07ddb76c', 'ea2b3c9b-677e-4368-acae-bdf011f814cf', NULL, NULL, 'main', true, 3, '19:00', '21:00', 2, '30 USD/чел', 'Ужин с прекрасным видом на исторический центр города и вкуснейшей турецкой кухней.', 'Религиозное наследие и панорамные виды');
INSERT INTO public.trip_pois VALUES ('2343e2c5-4e06-4276-8f34-b14c07ddb76c', '21b97517-579a-40d7-9461-ba6c7e0f909d', NULL, NULL, 'additional', false, 3, '14:30', '16:00', 1.5, '8 USD/чел', 'Интересный музей, демонстрирующий достижения исламской науки и техники, расположенный недалеко от Сулеймание.', 'Религиозное наследие и панорамные виды');
INSERT INTO public.trip_pois VALUES ('2343e2c5-4e06-4276-8f34-b14c07ddb76c', 'b18a2e13-2c84-4843-984d-69f101f9473c', NULL, NULL, 'additional', false, 3, '17:30', '18:00', 0.5, '0', 'Отличное место для фотосессии и наслаждения видами на Босфор после посещения Sapphire.', 'Религиозное наследие и панорамные виды');
INSERT INTO public.trip_pois VALUES ('2343e2c5-4e06-4276-8f34-b14c07ddb76c', '3dd64599-6195-4a84-96f4-887f17980f5a', NULL, NULL, 'additional', false, 3, '19:00', '21:00', 2, '25 USD/чел', 'Уютный ресторан с садом, предлагающий разнообразные блюда турецкой и средиземноморской кухни.', 'Религиозное наследие и панорамные виды');
INSERT INTO public.trip_pois VALUES ('2343e2c5-4e06-4276-8f34-b14c07ddb76c', 'ae1bc6bf-be7b-49cd-9f55-dfc0e63f9090', NULL, NULL, 'additional', false, 3, '19:00', '21:00', 2, '25 USD/чел', 'Попробуйте аутентичные блюда стамбульской кухни в этом ресторане, расположенном в историческом районе.', 'Религиозное наследие и панорамные виды');
INSERT INTO public.trip_pois VALUES ('2343e2c5-4e06-4276-8f34-b14c07ddb76c', '85d73476-23bc-4ade-8669-250a20256a91', NULL, NULL, 'main', true, 4, '10:30', '13:00', 2.5, '10 USD/чел', 'Насладитесь коллекцией современного турецкого и международного искусства в новом здании музея с видом на Босфор.', 'Искусство, современность и релакс');
INSERT INTO public.trip_pois VALUES ('2343e2c5-4e06-4276-8f34-b14c07ddb76c', 'c1202ae6-3cac-4d0c-a858-1fde2f21d3b1', NULL, NULL, 'main', true, 4, '13:30', '16:30', 3, '15 USD/чел', 'Уникальный музей промышленности, транспорта и связи, расположенный на берегу Золотого Рога. Интересно для всех возрастов.', 'Искусство, современность и релакс');
INSERT INTO public.trip_pois VALUES ('2343e2c5-4e06-4276-8f34-b14c07ddb76c', 'd4cb7bbe-4942-419f-9521-c9646d8a4bf9', NULL, NULL, 'main', true, 4, '17:00', '19:00', 2, '80-150 USD/чел', 'Побалуйте себя традиционным турецким хаммамом в роскошной исторической обстановке. Бронируйте заранее.', 'Искусство, современность и релакс');
INSERT INTO public.trip_pois VALUES ('2343e2c5-4e06-4276-8f34-b14c07ddb76c', '27efd268-5695-4757-aef0-6025c54e2e54', NULL, NULL, 'main', true, 4, '19:30', '21:30', 2, '30 USD/чел', 'Расслабьтесь после хаммама, наслаждаясь вкусным барбекю и панорамным видом с крыши.', 'Искусство, современность и релакс');
INSERT INTO public.trip_pois VALUES ('2343e2c5-4e06-4276-8f34-b14c07ddb76c', '689618c7-6671-4824-8d9e-ef847b6f10fd', NULL, NULL, 'additional', false, 4, '11:00', '12:30', 1.5, '8 USD/чел', 'Небольшая, но интересная галерея, предлагающая выставки современного искусства и культурные мероприятия.', 'Искусство, современность и релакс');
INSERT INTO public.trip_pois VALUES ('2343e2c5-4e06-4276-8f34-b14c07ddb76c', 'b6f7134b-1c3b-4ff3-987b-0526beaa1bf9', NULL, NULL, 'additional', false, 4, '11:00', '13:00', 2, '8 USD/чел', 'Еще одна ведущая галерея современного искусства в Стамбуле, расположенная в районе Бейоглу.', 'Искусство, современность и релакс');
INSERT INTO public.trip_pois VALUES ('2343e2c5-4e06-4276-8f34-b14c07ddb76c', '1c34036a-247c-4742-8d07-2e1f9a1d4f6b', NULL, NULL, 'additional', false, 4, '17:00', '19:00', 2, '60-120 USD/чел', 'Альтернативный вариант для турецкой бани, предлагающий более приватный и современный подход.', 'Искусство, современность и релакс');
INSERT INTO public.trip_pois VALUES ('2343e2c5-4e06-4276-8f34-b14c07ddb76c', '9834e869-c033-44d9-8f09-25cf44cfd3fd', NULL, NULL, 'additional', false, 4, '19:00', '20:30', 1.5, '20 USD/чел', 'Уютное кафе-бар в районе Галата, идеальное для вечернего напитка и легкого ужина.', 'Искусство, современность и релакс');
INSERT INTO public.trip_pois VALUES ('2343e2c5-4e06-4276-8f34-b14c07ddb76c', '0f8dda67-4fb3-4a8e-953f-2a7be33518a2', NULL, NULL, 'main', true, 5, '10:00', '13:00', 3, '0', 'Насладитесь прогулкой по живописному лесу, подышите свежим воздухом и отдохните от городской суеты.', 'Природа, парки и спокойствие');
INSERT INTO public.trip_pois VALUES ('2343e2c5-4e06-4276-8f34-b14c07ddb76c', '6ed1eed3-51b9-41e2-a628-a42abf2d8381', NULL, NULL, 'main', true, 5, '13:30', '16:00', 2.5, '25 USD/чел', 'Один из крупнейших тематических аквариумов в мире, расположенный недалеко от леса Флорья. Отличное место для всех возрастов.', 'Природа, парки и спокойствие');
INSERT INTO public.trip_pois VALUES ('2343e2c5-4e06-4276-8f34-b14c07ddb76c', '96be240b-2d7b-402a-8d7c-65ac8727eb5c', NULL, NULL, 'main', true, 5, '16:30', '18:30', 2, '0', 'Исторический парк с красивыми павильонами, прудами и живописными видами. Отличное место для вечерней прогулки.', 'Природа, парки и спокойствие');
INSERT INTO public.trip_pois VALUES ('2343e2c5-4e06-4276-8f34-b14c07ddb76c', '1211bea0-debc-4fcf-8478-7ab22d03f2c6', NULL, NULL, 'main', true, 5, '19:00', '21:00', 2, '30 USD/чел', 'Ресторан с приятной атмосферой и разнообразным меню, расположенный недалеко от парка Йылдыз.', 'Природа, парки и спокойствие');
INSERT INTO public.trip_pois VALUES ('2343e2c5-4e06-4276-8f34-b14c07ddb76c', 'f8964dc5-2bf1-4ca3-b9e2-1e27d539e47e', NULL, NULL, 'additional', false, 5, '10:00', '13:00', 3, '0', 'Если вы хотите еще больше природы, этот парк предлагает пешие прогулки и пикники в живописной сельской местности.', 'Природа, парки и спокойствие');
INSERT INTO public.trip_pois VALUES ('2343e2c5-4e06-4276-8f34-b14c07ddb76c', '1f0e53a3-b5d9-43b9-bce5-109902f5300c', NULL, NULL, 'additional', false, 5, '17:00', '18:30', 1.5, '0', 'Уютный городской парк, где можно отдохнуть и понаблюдать за местной жизнью.', 'Природа, парки и спокойствие');
INSERT INTO public.trip_pois VALUES ('2343e2c5-4e06-4276-8f34-b14c07ddb76c', '5ae113d1-96ff-4055-9863-6e2c9386b6d9', NULL, NULL, 'additional', false, 5, '17:00', '18:30', 1.5, '0', 'Современный парк на азиатской стороне Стамбула, с красивыми ландшафтами и местами для отдыха.', 'Природа, парки и спокойствие');
INSERT INTO public.trip_pois VALUES ('2343e2c5-4e06-4276-8f34-b14c07ddb76c', 'ce4e8c12-f45a-4bf8-a524-facc024ba416', NULL, NULL, 'additional', false, 5, '18:00', '19:00', 1, '0', 'Прогуляйтесь вдоль побережья, наслаждаясь морским бризом и видом на Мраморное море.', 'Природа, парки и спокойствие');
INSERT INTO public.trip_pois VALUES ('2343e2c5-4e06-4276-8f34-b14c07ddb76c', '49ff7b38-24be-44a5-88c9-a8dc3272345e', NULL, NULL, 'main', true, 6, '10:00', '11:30', 1.5, '8 USD/чел', 'Одна из старейших византийских церквей Стамбула, расположенная во дворе Топкапы. Известна своей простотой и акустикой.', 'Византийские церкви и аутентичные районы');
INSERT INTO public.trip_pois VALUES ('2343e2c5-4e06-4276-8f34-b14c07ddb76c', 'dbc11775-7903-474e-8184-00f0831327dd', NULL, NULL, 'main', true, 6, '12:00', '13:00', 1, '0', 'Неоготическая католическая церковь, одна из главных в Стамбуле. Красивая архитектура и спокойная атмосфера.', 'Византийские церкви и аутентичные районы');
INSERT INTO public.trip_pois VALUES ('2343e2c5-4e06-4276-8f34-b14c07ddb76c', '337211cf-7ed2-43ca-aa55-502f8325f44c', NULL, NULL, 'main', true, 6, '14:00', '15:00', 1, '0', 'Крупнейшая католическая церковь в Стамбуле, расположенная на улице Истикляль. Потрясающая архитектура и витражи.', 'Византийские церкви и аутентичные районы');
INSERT INTO public.trip_pois VALUES ('2343e2c5-4e06-4276-8f34-b14c07ddb76c', '7480da4d-ba5c-4b46-ad75-756fba8ebd6e', NULL, NULL, 'main', true, 6, '15:30', '17:30', 2, '0', 'Один из менее туристических рынков, где можно найти одежду, текстиль и другие товары по более низким ценам.', 'Византийские церкви и аутентичные районы');
INSERT INTO public.trip_pois VALUES ('2343e2c5-4e06-4276-8f34-b14c07ddb76c', '8fa714c2-5985-489e-9052-59285f51e0fa', NULL, NULL, 'main', true, 6, '19:00', '21:00', 2, '30 USD/чел', 'Ужин с видом на море и свежими морепродуктами, идеально после насыщенного дня.', 'Византийские церкви и аутентичные районы');
INSERT INTO public.trip_pois VALUES ('2343e2c5-4e06-4276-8f34-b14c07ddb76c', '1a8f912b-9fd7-4501-a7ac-07ad55fc60aa', NULL, NULL, 'additional', false, 6, '11:00', '12:00', 1, '0', 'Древняя византийская церковь, известная своей святыней и источником. Расположена немного в стороне от основных туристических маршрутов.', 'Византийские церкви и аутентичные районы');
INSERT INTO public.trip_pois VALUES ('2343e2c5-4e06-4276-8f34-b14c07ddb76c', '821980c1-3d66-4706-8dce-70cb0947f9cb', NULL, NULL, 'additional', false, 6, '13:00', '13:30', 0.5, '0', 'Красивая армянская церковь, расположенная в районе Кадыкёй. Интересна своей архитектурой и историей.', 'Византийские церкви и аутентичные районы');
INSERT INTO public.trip_pois VALUES ('2343e2c5-4e06-4276-8f34-b14c07ddb76c', '56f4498e-0cd7-48c6-8f15-f87ac046d1e2', NULL, NULL, 'additional', false, 6, '14:00', '14:30', 0.5, '0', 'Историческая греческая православная церковь, известная своей иконой Девы Марии. Посещается в первый день каждого месяца.', 'Византийские церкви и аутентичные районы');
INSERT INTO public.trip_pois VALUES ('2343e2c5-4e06-4276-8f34-b14c07ddb76c', '6b0bc16c-7845-4ade-a921-e14ed89bc999', NULL, NULL, 'additional', false, 6, '19:00', '21:00', 2, '30 USD/чел', 'Ресторан, предлагающий изысканные блюда османской кухни в элегантной обстановке.', 'Византийские церкви и аутентичные районы');
INSERT INTO public.trip_pois VALUES ('2343e2c5-4e06-4276-8f34-b14c07ddb76c', 'bacbe5a2-5971-40d5-8420-112976cf699b', NULL, NULL, 'main', true, 7, '10:00', '11:30', 1.5, '10 USD/чел', 'Погрузитесь в историческую реконструкцию завоевания Константинополя с помощью 3D-панорамы. Впечатляющее зрелище.', 'Культурное погружение и прощание с городом');
INSERT INTO public.trip_pois VALUES ('2343e2c5-4e06-4276-8f34-b14c07ddb76c', '0ee3fa53-c959-465e-8bd6-2a95639eeec4', NULL, NULL, 'main', true, 7, '12:00', '14:00', 2, '8 USD/чел', 'Интересный музей для любителей авиации, где представлены различные самолеты и артефакты турецкой авиации.', 'Культурное погружение и прощание с городом');
INSERT INTO public.trip_pois VALUES ('2343e2c5-4e06-4276-8f34-b14c07ddb76c', '11e63885-f2e7-4ec9-9280-8cffde74377a', NULL, NULL, 'main', true, 7, '15:00', '17:00', 2, '20-30 USD/чел', 'Завершите поездку круизом по Босфору, чтобы увидеть Стамбул с воды и насладиться панорамными видами.', 'Культурное погружение и прощание с городом');
INSERT INTO public.trip_pois VALUES ('2343e2c5-4e06-4276-8f34-b14c07ddb76c', 'f15bbd5a-82c9-43b6-8cd2-cd17033eb646', NULL, NULL, 'main', true, 7, '18:00', '19:30', 1.5, '15 USD/чел', 'Уютное кафе для прощального ужина или легкого перекуса перед отъездом, с хорошим кофе и выпечкой.', 'Культурное погружение и прощание с городом');
INSERT INTO public.trip_pois VALUES ('2343e2c5-4e06-4276-8f34-b14c07ddb76c', '882e3a01-4752-460a-ba66-e16dec7951b1', NULL, NULL, 'additional', false, 7, '11:00', '12:00', 1, '0', 'Культурный центр, где иногда проводятся выставки или мероприятия, если вы ищете что-то местное и нетуристическое.', 'Культурное погружение и прощание с городом');
INSERT INTO public.trip_pois VALUES ('2343e2c5-4e06-4276-8f34-b14c07ddb76c', '65903921-1f5a-4517-a0e3-8f4dbbe8d5c7', NULL, NULL, 'additional', false, 7, '11:00', '12:00', 1, '0', 'Еще один культурный центр, который может предложить интересные местные выставки или мероприятия.', 'Культурное погружение и прощание с городом');
INSERT INTO public.trip_pois VALUES ('2343e2c5-4e06-4276-8f34-b14c07ddb76c', '0a0511b0-09e5-4a24-9c10-441fb44adf33', NULL, NULL, 'additional', false, 7, '14:00', '15:00', 1, '0', 'Если вы хотите приобрести последние сувениры или получить информацию о городе перед отъездом.', 'Культурное погружение и прощание с городом');
INSERT INTO public.trip_pois VALUES ('2343e2c5-4e06-4276-8f34-b14c07ddb76c', 'd6a70672-cfeb-4e0f-aa83-e973c49b1d9d', NULL, NULL, 'additional', false, 7, '17:00', '18:00', 1, '10 USD/чел', 'Хорошее место для последнего турецкого кофе или чая перед отъездом, чтобы запечатлеть воспоминания о Стамбуле.', 'Культурное погружение и прощание с городом');
INSERT INTO public.trip_pois VALUES ('7b1e28a1-41c4-4f84-9902-71ee3587e166', '3f4d97ba-eded-4cb4-a5f4-af0dfa386e11', NULL, NULL, 'main', true, 1, '10:00', '12:00', 2, '160-250 AED/чел', 'Забронируйте билеты заранее онлайн, чтобы избежать очередей и выбрать оптимальное время посещения (утром или на закате).', 'Современный Дубай и захватывающие виды');
INSERT INTO public.trip_pois VALUES ('7b1e28a1-41c4-4f84-9902-71ee3587e166', 'd2355af6-e15a-44c9-8938-efd6c116222c', NULL, NULL, 'main', true, 1, '12:30', '14:00', 1.5, '50-150 AED/чел (сувениры/обед)', 'Прогуляйтесь по этому традиционному рынку с видом на Бурдж-Халифа и фонтаны, найдите уникальные сувениры и насладитесь обедом в одном из ресторанов.', 'Современный Дубай и захватывающие виды');
INSERT INTO public.trip_pois VALUES ('7b1e28a1-41c4-4f84-9902-71ee3587e166', '8dda4329-1557-4403-be32-2a51314b6add', NULL, NULL, 'main', true, 1, '14:30', '16:30', 2, '199-300 AED/чел', 'Помимо основного аквариума, рассмотрите возможность посещения Underwater Zoo, чтобы увидеть редких животных и интерактивные экспозиции.', 'Современный Дубай и захватывающие виды');
INSERT INTO public.trip_pois VALUES ('7b1e28a1-41c4-4f84-9902-71ee3587e166', '1f1391c6-df0f-4466-a621-8ffaa207158a', NULL, NULL, 'main', true, 1, '19:00', '21:00', 2, '150-250 AED/чел', 'Насладитесь аутентичной грузинской кухней в уютной атмосфере после насыщенного дня.', 'Современный Дубай и захватывающие виды');
INSERT INTO public.trip_pois VALUES ('7b1e28a1-41c4-4f84-9902-71ee3587e166', '6376144e-a5a7-4082-8eef-4d1ac4a5b079', NULL, NULL, 'additional', false, 1, '17:00', '19:00', 2, '50-100 AED/чел', 'Если вы устали от прогулок, можно отдохнуть и посмотреть фильм в современном кинотеатре.', 'Современный Дубай и захватывающие виды');
INSERT INTO public.trip_pois VALUES ('7b1e28a1-41c4-4f84-9902-71ee3587e166', 'a0d5ea2a-c896-4c20-ae00-9c394bd11bca', NULL, NULL, 'additional', false, 1, '16:00', '17:30', 1.5, '100-150 AED/чел', 'Уникальное иммерсивное арт-пространство, которое позволит погрузиться в мир искусства с помощью света и звука.', 'Современный Дубай и захватывающие виды');
INSERT INTO public.trip_pois VALUES ('7b1e28a1-41c4-4f84-9902-71ee3587e166', 'e874fb84-bde1-4626-b4de-63ec7f43e4c7', NULL, NULL, 'additional', false, 1, '09:00', '11:30', 2.5, '149 AED/чел', 'Если вы предпочитаете начать день с футуристического опыта, это музей предлагает заглянуть в будущее. Билеты бронировать сильно заранее.', 'Современный Дубай и захватывающие виды');
INSERT INTO public.trip_pois VALUES ('7b1e28a1-41c4-4f84-9902-71ee3587e166', '05270ee6-67a8-461e-9dc0-f048385ed72e', NULL, NULL, 'main', true, 2, '10:00', '11:00', 1, '0', 'Посетите эту прекрасную мечеть, соблюдая дресс-код (скромная одежда, для женщин платок). Отличная возможность познакомиться с исламской архитектурой.', 'Культурное наследие и восточный колорит');
INSERT INTO public.trip_pois VALUES ('7b1e28a1-41c4-4f84-9902-71ee3587e166', 'a9cc99ed-e670-4073-ba2c-ae509070d1d4', NULL, NULL, 'main', true, 2, '11:30', '13:00', 1.5, '50-100 AED/чел (специи/сувениры)', 'Погрузитесь в мир ароматов и красок. Здесь можно купить специи, травы, сухофрукты и сувениры. Не стесняйтесь торговаться!', 'Культурное наследие и восточный колорит');
INSERT INTO public.trip_pois VALUES ('7b1e28a1-41c4-4f84-9902-71ee3587e166', '571b9df1-5e5d-4152-8427-b90cfbc1f97b', NULL, NULL, 'main', true, 2, '13:30', '15:00', 1.5, '50-150 AED/чел (сувениры/покупки)', 'Исследуйте этот оживленный рынок, известный своими сувенирами, текстилем и изделиями ручной работы. Отличное место для поиска подарков.', 'Культурное наследие и восточный колорит');
INSERT INTO public.trip_pois VALUES ('7b1e28a1-41c4-4f84-9902-71ee3587e166', '6cc872fa-51f7-4a18-8a30-b1e07f563133', NULL, NULL, 'main', true, 2, '15:30', '16:30', 1, '20-50 AED/чел', 'Отдохните в уютном Музее кофе, узнайте об истории и культуре кофе в регионе, попробуйте местные сорта.', 'Культурное наследие и восточный колорит');
INSERT INTO public.trip_pois VALUES ('7b1e28a1-41c4-4f84-9902-71ee3587e166', '8bb2dc28-be56-4cd4-8461-47d094c9db50', NULL, NULL, 'main', true, 2, '19:00', '21:00', 2, '150-250 AED/чел', 'Завершите день ужином в ресторане с восточной кухней, наслаждаясь атмосферой и традиционными блюдами.', 'Культурное наследие и восточный колорит');
INSERT INTO public.trip_pois VALUES ('7b1e28a1-41c4-4f84-9902-71ee3587e166', 'bd0b5169-1331-444a-ac3f-bbd27b1119a3', NULL, NULL, 'additional', false, 2, '16:30', '17:30', 1, '50-100 AED/чел (покупки)', 'Посмотрите на традиционное искусство и ремесла, возможно, найдете что-то уникальное для себя.', 'Культурное наследие и восточный колорит');
INSERT INTO public.trip_pois VALUES ('7b1e28a1-41c4-4f84-9902-71ee3587e166', 'e0838d69-6af1-4ed8-a0f5-36ddca8efa21', NULL, NULL, 'additional', false, 2, '17:30', '18:30', 1, '0', 'Небольшая, но интересная галерея современного искусства в историческом районе Аль-Фахиди. Отличный способ отвлечься от суеты рынков.', 'Культурное наследие и восточный колорит');
INSERT INTO public.trip_pois VALUES ('7b1e28a1-41c4-4f84-9902-71ee3587e166', 'a5fec517-77a2-440a-aeee-98fba160a431', NULL, NULL, 'main', true, 3, '10:00', '12:30', 2.5, '75 AED/чел', 'Потрясающий цветочный сад, который выглядит как сказка. Идеально подходит для красивых фотографий и неспешных прогулок.', 'Отдых на природе и развлечения');
INSERT INTO public.trip_pois VALUES ('7b1e28a1-41c4-4f84-9902-71ee3587e166', '1d35f5ce-1859-4832-9abd-ae74dd6156d2', NULL, NULL, 'main', true, 3, '13:00', '14:30', 1.5, '0', 'Один из крупнейших парков Дубая с красивыми ландшафтами, детскими площадками и возможностью для пикника. Отличное место для отдыха на свежем воздухе.', 'Отдых на природе и развлечения');
INSERT INTO public.trip_pois VALUES ('7b1e28a1-41c4-4f84-9902-71ee3587e166', 'fa891599-6bef-4dcf-a3f2-e7fd0f4692f8', NULL, NULL, 'main', true, 3, '15:00', '16:30', 1.5, '50 AED/чел', 'Поднимитесь на Дубайскую Рамку, чтобы увидеть панорамные виды на старый и новый Дубай. Стеклянный пол добавит острых ощущений.', 'Отдых на природе и развлечения');
INSERT INTO public.trip_pois VALUES ('7b1e28a1-41c4-4f84-9902-71ee3587e166', 'e5940277-6667-4a94-8d83-50297d3135a7', NULL, NULL, 'main', true, 3, '18:00', '20:00', 2, '70 AED/чел', 'Вечерний визит в этот парк с удивительными световыми инсталляциями и светящимися динозаврами подарит незабываемые впечатления.', 'Отдых на природе и развлечения');
INSERT INTO public.trip_pois VALUES ('7b1e28a1-41c4-4f84-9902-71ee3587e166', '66c9e5de-a771-4f12-baf0-10ee7f2b26fc', NULL, NULL, 'main', true, 3, '20:30', '22:30', 2, '100-200 AED/чел', 'Завершите день вкусным ужином в одном из местных ресторанов, предлагающих разнообразную кухню.', 'Отдых на природе и развлечения');
INSERT INTO public.trip_pois VALUES ('7b1e28a1-41c4-4f84-9902-71ee3587e166', '09b58751-cadd-4039-9952-42a157b354ba', NULL, NULL, 'additional', false, 3, '12:00', '13:30', 1.5, '75 AED/чел', 'Если вы любите экзотических животных, этот парк предлагает уникальную возможность увидеть крокодилов в естественной среде обитания.', 'Отдых на природе и развлечения');
INSERT INTO public.trip_pois VALUES ('7b1e28a1-41c4-4f84-9902-71ee3587e166', '6059ea49-5eea-421e-9cec-9818df43317f', NULL, NULL, 'additional', false, 3, '14:00', '15:00', 1, '0', 'Современный урбанистический парк, где можно погулять, покататься на скейтборде или просто отдохнуть на скамейке.', 'Отдых на природе и развлечения');
INSERT INTO public.trip_pois VALUES ('7b1e28a1-41c4-4f84-9902-71ee3587e166', 'cb426f00-2ee2-416f-a8cf-f41f97a0d402', NULL, NULL, 'additional', false, 3, '11:00', '12:30', 1.5, '3 AED/чел', 'Один из старейших и самых популярных парков Дубая, идеально подходит для пикника и отдыха.', 'Отдых на природе и развлечения');
INSERT INTO public.trip_pois VALUES ('7b1e28a1-41c4-4f84-9902-71ee3587e166', '51aaae48-3d85-4217-aec1-175891c1c2c9', NULL, NULL, 'main', true, 4, '14:00', '16:30', 2.5, '0', 'Один из самых оживленных пляжей Дубая с множеством кафе и магазинов поблизости. Прогуляйтесь по набережной и насладитесь атмосферой.', 'Пляжный отдых и релаксация');
INSERT INTO public.trip_pois VALUES ('7b1e28a1-41c4-4f84-9902-71ee3587e166', '45bec929-ce52-4b69-9167-5437dab58df9', NULL, NULL, 'main', true, 4, '17:00', '19:00', 2, '300-600 AED/чел', 'Завершите поездку расслабляющим массажем в роскошном спа-салоне, чтобы снять усталость после насыщенных дней.', 'Пляжный отдых и релаксация');
INSERT INTO public.trip_pois VALUES ('7b1e28a1-41c4-4f84-9902-71ee3587e166', '0d724174-10c6-4c4b-98a9-c42faeea4f9a', NULL, NULL, 'main', true, 4, '20:00', '22:00', 2, '200-400 AED/чел', 'Изысканный ужин с видом на Дубай Марину станет отличным завершением вашего путешествия.', 'Пляжный отдых и релаксация');
INSERT INTO public.trip_pois VALUES ('7b1e28a1-41c4-4f84-9902-71ee3587e166', '64124e2c-56b6-484a-978f-7f9b852a173c', NULL, NULL, 'additional', false, 4, '09:00', '12:00', 3, '0', 'Модный пляжный район с уникальным дизайном, множеством кафе и магазинов. Отличная альтернатива для утреннего пляжного отдыха.', 'Пляжный отдых и релаксация');
INSERT INTO public.trip_pois VALUES ('7b1e28a1-41c4-4f84-9902-71ee3587e166', 'e562f62c-bbbb-4e7a-860f-0124ba3b6f08', NULL, NULL, 'additional', false, 4, '11:00', '13:00', 2, '0', 'Простой и доступный пляж для тех, кто предпочитает спокойный отдых без лишней суеты.', 'Пляжный отдых и релаксация');
INSERT INTO public.trip_pois VALUES ('7b1e28a1-41c4-4f84-9902-71ee3587e166', '78bb450c-15e5-48b5-baa6-8e51c31fde30', NULL, NULL, 'additional', false, 4, '16:00', '17:30', 1.5, '250-500 AED/чел', 'Еще один вариант для расслабляющего спа-отдыха, если вы предпочитаете более традиционные процедуры.', 'Пляжный отдых и релаксация');
